export const fetchUpdatePassword = async (
    userId: string,
    oldPassword: string,
    newPassword: string,
): Promise<boolean> => {
    try {
        await BaseService.put(`/update-pass/${userId}`, {
            contrasena_actual: oldPassword,
            nueva_contrasena: newPassword,
        })
        return true
    } catch (error: any) {
        console.error('Error al actualizar la contraseña:', error)
        throw error
    }
}

