import { useState } from 'react'
import Dropdown from '@/components/ui/Dropdown'
import Avatar from '@/components/ui/Avatar'
import { HiOutlineOfficeBuilding, HiPlus, HiOutlineEye, HiOutlinePencil, HiOutlineTrash } from 'react-icons/hi'
import { useSelector, useDispatch } from 'react-redux'
import { RootState } from '@/store/rootReducer'
import { 
    setCurrentBusinessUnit, 
    getBusinessUnits,
    BusinessUnit 
} from '@/store/slices/businessUnit'
import useThemeClass from '@/utils/hooks/useThemeClass'
import classNames from 'classnames'
import CreateBusinessUnitDialog from './CreateBusinessUnitDialog'
import ViewBusinessUnitDrawer from './ViewBusinessUnitDialog'
import EditBusinessUnitDrawer from './EditBusinessUnitDialog'
import { IconButton, Tooltip } from '@mui/material'
import { apiDeleteBusinessUnit } from '@/services/BusinessUnitService'
import Swal from 'sweetalert2'

const BusinessUnitDropdown = () => {
    const { textTheme } = useThemeClass()
    const dispatch = useDispatch()
    
    const { currentBusinessUnit, allBusinessUnits } = useSelector(
        (state: RootState) => state.businessUnit.data
    )

    const [dialogIsOpen, setDialogIsOpen] = useState(false)
    const [viewDialogOpen, setViewDialogOpen] = useState(false)
    const [editDialogOpen, setEditDialogOpen] = useState(false)
    const [selectedUnit, setSelectedUnit] = useState<BusinessUnit | null>(null)

    const onBusinessUnitSelect = (bu: BusinessUnit) => {
        dispatch(setCurrentBusinessUnit(bu))
    }

    const handleView = (e: React.MouseEvent, bu: BusinessUnit) => {
        e.stopPropagation()
        setSelectedUnit(bu)
        setViewDialogOpen(true)
    }

    const handleEdit = (e: React.MouseEvent, bu: BusinessUnit) => {
        e.stopPropagation()
        setSelectedUnit(bu)
        setEditDialogOpen(true)
    }

    const handleDelete = (e: React.MouseEvent, bu: BusinessUnit) => {
        e.stopPropagation()
        
        Swal.fire({
            title: '¿Estás seguro?',
            text: `¿Deseas eliminar la unidad "${bu.nombre}"? Esta acción no se puede deshacer.`,
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#d33',
            cancelButtonColor: '#3085d6',
            confirmButtonText: 'Sí, eliminar',
            cancelButtonText: 'Cancelar'
        }).then(async (result) => {
            if (result.isConfirmed) {
                try {
                    const resp = await apiDeleteBusinessUnit(bu._id) as any
                    if (resp.data && resp.data.ok) {
                        Swal.fire({
                            title: 'Eliminado',
                            text: 'La unidad de negocio ha sido eliminada',
                            icon: 'success',
                            confirmButtonColor: '#3b82f6'
                        })
                        
                        // If we deleted the current unit, reset it to null so the fetch picks a new one
                        if (currentBusinessUnit?._id === bu._id) {
                            dispatch(setCurrentBusinessUnit(null))
                        }
                        
                        dispatch(getBusinessUnits() as any)
                    } else {
                        throw new Error(resp.data?.msg || 'Error al eliminar')
                    }
                } catch (error: any) {
                    Swal.fire({
                        title: 'Error',
                        text: error.message || 'No se pudo eliminar la unidad',
                        icon: 'error',
                        confirmButtonColor: '#3b82f6'
                    })
                }
            }
        })
    }

    const selectedBuName = currentBusinessUnit?.nombre || 'Seleccionar Unidad'

    return (
        <>
            <Dropdown
                renderTitle={
                    <div 
                        id="business-unit-selector"
                        className="flex items-center gap-2 cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-700 p-2 rounded-lg transition-colors"
                    >
                        <Avatar 
                            size={32} 
                            shape="circle" 
                            icon={<HiOutlineOfficeBuilding />} 
                            className={classNames(
                                "bg-indigo-100 text-indigo-600 dark:bg-indigo-900 dark:text-indigo-400",
                                !currentBusinessUnit && "bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400"
                            )}
                        />
                        <div className="hidden md:block text-left">
                            <div className="text-xs text-gray-500 font-medium">Unidad de Negocio</div>
                            <div className={classNames("font-bold text-sm", textTheme)}>
                                {selectedBuName}
                            </div>
                        </div>
                    </div>
                }
                menuStyle={{ minWidth: 240 }}
                placement="bottom-start"
            >
                <Dropdown.Item variant="header">
                    <div className="py-2 px-3 text-gray-900 dark:text-gray-100 font-semibold">
                        Mis Unidades de Negocio
                    </div>
                </Dropdown.Item>
                {(Array.isArray(allBusinessUnits) ? allBusinessUnits : []).map((bu) => (
                    <Dropdown.Item 
                        key={bu._id} 
                        onClick={() => onBusinessUnitSelect(bu)}
                        className={classNames(
                            "mb-1 group", 
                            currentBusinessUnit?._id === bu._id && "bg-gray-50 dark:bg-gray-700"
                        )}
                    >
                        <div className="flex items-center justify-between w-full">
                            <div className="flex items-center gap-2">
                                <HiOutlineOfficeBuilding className="text-xl opacity-70" />
                                <span className={classNames(
                                    currentBusinessUnit?._id === bu._id && "font-semibold"
                                )}>
                                    {bu.nombre}
                                </span>
                            </div>
                            <div className="flex items-center gap-0 opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                                <Tooltip title="Ver Información">
                                    <IconButton 
                                        size="small" 
                                        onClick={(e) => handleView(e, bu)}
                                        className="text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/20"
                                    >
                                        <HiOutlineEye className="text-lg" />
                                    </IconButton>
                                </Tooltip>
                                <Tooltip title="Editar">
                                    <IconButton 
                                        size="small" 
                                        onClick={(e) => handleEdit(e, bu)}
                                        className="text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/20"
                                    >
                                        <HiOutlinePencil className="text-lg" />
                                    </IconButton>
                                </Tooltip>
                                <Tooltip title="Eliminar">
                                    <IconButton 
                                        size="small" 
                                        onClick={(e) => handleDelete(e, bu)}
                                        className="text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20"
                                    >
                                        <HiOutlineTrash className="text-lg" />
                                    </IconButton>
                                </Tooltip>
                            </div>
                        </div>
                    </Dropdown.Item>
                ))}
                <Dropdown.Item variant="divider" />
                <Dropdown.Item 
                    onClick={() => setDialogIsOpen(true)}
                >
                    <div 
                        id="add-new-business-unit"
                        className="flex items-center gap-2 text-indigo-600 dark:text-indigo-400"
                    >
                        <HiPlus className="text-xl" />
                        <span className="font-semibold">Nueva Unidad</span>
                    </div>
                </Dropdown.Item>
            </Dropdown>

            <CreateBusinessUnitDialog 
                isOpen={dialogIsOpen} 
                onClose={() => setDialogIsOpen(false)} 
            />

            {/* View Drawer */}
            {selectedUnit && (
                <ViewBusinessUnitDrawer 
                    unit={selectedUnit}
                    isOpen={viewDialogOpen}
                    onClose={() => setViewDialogOpen(false)}
                />
            )}

            {/* Edit Drawer */}
            {selectedUnit && (
                <EditBusinessUnitDrawer 
                    unit={selectedUnit}
                    isOpen={editDialogOpen}
                    onClose={() => setEditDialogOpen(false)}
                />
            )}
        </>
    )
}

