import { useEffect, useState } from 'react'
import { useSelector, useDispatch } from 'react-redux'
import { RootState } from '@/store/rootReducer'
import { getBusinessUnits } from '@/store/slices/businessUnit'
import { Button } from '@/components/ui'
import { HiOutlineOfficeBuilding, HiArrowRight, HiOutlineCursorClick } from 'react-icons/hi'
import useAuth from '@/utils/hooks/useAuth'
import { motion, AnimatePresence } from 'framer-motion'

const BusinessUnitOnboarding = () => {
    const dispatch = useDispatch()
    const { authenticated } = useAuth()
    const { allBusinessUnits, loading } = useSelector(
        (state: RootState) => state.businessUnit.data
    )
    
    const [step, setStep] = useState(1) // 1: Welcome, 2: Highlight Selector, 3: Highlight Add New, 0: Done
    const [selectorRect, setSelectorRect] = useState<DOMRect | null>(null)
    const [addNewRect, setAddNewRect] = useState<DOMRect | null>(null)

    useEffect(() => {
        if (authenticated) {
            dispatch(getBusinessUnits() as any)
        }
    }, [authenticated, dispatch])

    useEffect(() => {
        let interval: NodeJS.Timeout
        const updateAllRects = () => {
            if (step === 2) {
                const el = document.getElementById('business-unit-selector')
                if (el) setSelectorRect(el.getBoundingClientRect())
            }
            if (step === 3) {
                const el = document.getElementById('add-new-business-unit')
                if (el) setAddNewRect(el.getBoundingClientRect())
            }
        }

        if (step === 2) {
            updateAllRects()
            interval = setInterval(() => {
                const addNew = document.getElementById('add-new-business-unit')
                if (addNew) setStep(3)
            }, 300)
        }

        if (step === 3) {
            updateAllRects()
            interval = setInterval(() => {
                const addNew = document.getElementById('add-new-business-unit')
                if (!addNew) setStep(0)
            }, 300)
        }

        window.addEventListener('resize', updateAllRects)
        window.addEventListener('scroll', updateAllRects, true)
        return () => {
            clearInterval(interval)
            window.removeEventListener('resize', updateAllRects)
            window.removeEventListener('scroll', updateAllRects, true)
        }
    }, [step])

    const showOnboarding = authenticated && !loading && (Array.isArray(allBusinessUnits) ? allBusinessUnits : []).length === 0 && step !== 0

    if (!showOnboarding) {
        return null
    }

    const currentRect = step === 2 ? selectorRect : step === 3 ? addNewRect : null

    return (
        <AnimatePresence>
            {step === 1 && (
                <motion.div 
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="fixed inset-0 z-[100] flex items-center justify-center bg-gray-950/40 backdrop-blur-sm p-4"
                >
                    <motion.div 
                        initial={{ opacity: 0, scale: 0.98, y: 10 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        transition={{ duration: 0.4, ease: "easeOut" }}
                        className="bg-white dark:bg-gray-800 p-10 rounded-[2rem] shadow-2xl max-w-sm w-full border border-gray-100 dark:border-gray-700 text-center relative"
                    >
                        <div className="mb-6 flex justify-center">
                            <div className="w-16 h-16 bg-blue-50 dark:bg-blue-900/20 rounded-2xl flex items-center justify-center">
                                <HiOutlineOfficeBuilding className="text-3xl text-blue-600 dark:text-blue-400" />
                            </div>
                        </div>
                        
                        <div className="flex justify-center mb-3">
                             <span className="text-[10px] font-medium text-gray-400 uppercase tracking-[0.2em]">
                                Bienvenida
                            </span>
                        </div>

                        <h3 className="text-xl font-semibold text-gray-900 dark:text-white mb-3">
                            Configuración Inicial
                        </h3>
                        <p className="text-gray-500 dark:text-gray-400 mb-8 text-sm font-light leading-relaxed px-2">
                            Para comenzar a operar, primero configuremos su primera Unidad de Negocio en dos simples pasos.
                        </p>
                        
                        <button 
                            onClick={() => setStep(2)}
                            className="w-full py-3.5 bg-blue-600 hover:bg-blue-700 text-white rounded-xl flex items-center justify-center gap-2 transition-all font-medium text-sm shadow-lg shadow-blue-100 dark:shadow-none active:scale-[0.98]"
                        >
                            Comenzar guía
                            <HiArrowRight className="text-base" />
                        </button>
                    </motion.div>
                </motion.div>
            )}

            {(step === 2 || step === 3) && (
                <div className="fixed inset-0 z-[100] pointer-events-none overflow-hidden text-slate-900">
                    {/* Darker SVG Mask */}
                    <svg className="absolute inset-0 w-full h-full pointer-events-none">
                        <defs>
                            <mask id="spotlight-mask-final">
                                <rect width="100%" height="100%" fill="white" />
                                {currentRect && (
                                    <rect 
                                        x={currentRect.left - 8} 
                                        y={currentRect.top - 4} 
                                        width={currentRect.width + 20} 
                                        height={currentRect.height + 8} 
                                        rx="12" 
                                        fill="black" 
                                        className="transition-all duration-300 ease-out"
                                    />
                                )}
                            </mask>
                        </defs>
                        <rect 
                            width="100%" 
                            height="100%" 
                            fill="rgba(15, 23, 42, 0.5)" // Darker overlay
                            mask="url(#spotlight-mask-final)" 
                            className="transition-all duration-300"
                        />
                    </svg>

                    {/* Pro Tooltip - Refined and Slimmer */}
                    {currentRect && (
                        <motion.div 
                            key={`tooltip-${step}`}
                            initial={{ opacity: 0, y: 15 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0 }}
                            className="absolute pointer-events-auto z-[101]"
                            style={{ 
                                top: currentRect.bottom + 20, 
                                left: Math.max(20, Math.min(window.innerWidth - 300, currentRect.left + (currentRect.width / 2) - 140)),
                                width: 280
                            }}
                        >
                            <div className="bg-white dark:bg-gray-800 border border-gray-100 dark:border-gray-700 p-6 rounded-2xl shadow-xl flex flex-col gap-2">
                                <div className="flex items-center justify-between mb-1">
                                    <div className="w-6 h-6 bg-blue-50 dark:bg-blue-900/40 rounded-lg flex items-center justify-center">
                                        <HiOutlineCursorClick className="text-blue-600 dark:text-blue-400 text-xs" />
                                    </div>
                                    <span className="text-[10px] font-bold text-blue-600 bg-blue-50 dark:bg-blue-900/40 px-2.5 py-0.5 rounded-full tracking-wider">
                                        PASO {step - 1} / 2
                                    </span>
                                </div>
                                
                                <h4 className="text-sm font-semibold text-gray-900 dark:text-white">
                                    {step === 2 ? 'Active el selector' : 'Crear unidad'}
                                </h4>
                                <p className="text-xs text-gray-500 dark:text-gray-400 leading-relaxed font-light">
                                    {step === 2 
                                        ? 'Haga clic en este panel para gestionar sus diferentes Unidades de Negocio.' 
                                        : 'Bien. Ahora seleccione esta opción para definir los parámetros de su nueva unidad.'}
                                </p>
                            </div>
                        </motion.div>
                    )}
                </div>
            )}
        </AnimatePresence>
    )
}

