import React, { useEffect } from 'react'
import { calculateTotalDebt } from '@/utils/hooks/calculateClientDebt'
import ClientCardItem from './ClientCardItem'
import { Skeleton } from '@/components/ui'
import { Client } from '@/@types/clientInfo'

type ClientCardProps = {
    sortDirection: 'asc' | 'desc' | undefined
    onClientSubmit: () => void
    allClients: boolean
    clients: Client[]
    loading: boolean
    fetchClients: () => Promise<void>
    expanded: { [key: string]: boolean }
    toggleExpand: (_id: string) => void
}

const ClientCard: React.FC<ClientCardProps> = ({
    sortDirection,
    onClientSubmit,
    allClients,
    clients,
    loading,
    fetchClients,
    expanded,
    toggleExpand
}) => {

    if (loading) {
        return (
            <div>
                {Array.from(new Array(5)).map((_, index) => (
                    <Skeleton
                        key={index}
                        width="100%"
                        height={100}
                        style={{ marginBottom: '10px' }}
                    />
                ))}
            </div>
        )
    }

    const filteredClients = allClients
        ? clients
        : clients.filter((client) => client.estado !== 'Cerrado')

    const sortedClients = [...filteredClients].sort((a, b) => {
        const getName = (c: any) => {
            if (c.tipoCliente?.toLowerCase() === 'persona') {
                return `${c.apellido || ''} ${c.nombre || ''}`.trim().toLowerCase()
            }
            return (c.razonSocial || '').toLowerCase()
        }

        const nameA = getName(a)
        const nameB = getName(b)

        if (sortDirection === 'asc') {
            return nameA.localeCompare(nameB)
        }
        if (sortDirection === 'desc') {
            return nameB.localeCompare(nameA)
        }
        return 0
    })

    return (
        <div>
            {sortedClients.map((client, index) => {
                const totalDebt = calculateTotalDebt(client.Presupuestos || [])

                return (
                    <ClientCardItem
                        key={client._id}
                        client={client}
                        expanded={expanded[client._id] || false}
                        onToggleExpand={() => toggleExpand(client._id)}
                        totalDebt={totalDebt}
                        fetchClients={fetchClients}
                        isFirst={index === 0}
                    />
                )
            })}
        </div>
    )
}

export default ClientCard

import React, { useState, useEffect } from 'react'
import { Card } from '@/components/ui'
import { HiOutlineChevronDown, HiOutlineChevronUp } from 'react-icons/hi'
import { IconButton } from '@mui/material'
import formatCurrency from '@/utils/hooks/formatCurrency'
import PresupuestosCardList from '../Lists/PresupuestosCardList'
import { Client } from '@/@types/clientInfo'
import ClientDetailsDropdown from '../Dropdown/ClientDropdown'
import AddPresupuestoButton from '../Buttons/AddPresupuestoButton'
import AddPagoButton from '../Buttons/AddPagoButton'
import AddPagoModal from '../Modal/AddPagoModal'
import AddPresupuestoModal from '../Modal/AddPresupuestoModal'
import DeleteButton from '../../DeleteButton'
import { apiDeleteClient, apiGetClientById } from '@/services/ClientService'
import Swal from 'sweetalert2'
import { Tag } from '@/components/ui'

type Props = {
    client: Client
    expanded: boolean
    onToggleExpand: () => void
    totalDebt: number
    fetchClients: () => void
    isFirst?: boolean
}

const ClientCardItem: React.FC<Props> = ({
    client,
    expanded,
    onToggleExpand,
    totalDebt,
    fetchClients,
    isFirst
}) => {
    const [isPagoModalOpen, setIsPagoModalOpen] = useState(false)
    const [isPresupuestoModalOpen, setIsPresupuestoModalOpen] = useState(false)
    const [clientData, setClientData] = useState<Client>(client)

    const fetchClientDetails = async () => {
        try {
            const resp: any = await apiGetClientById(client._id)
            if (resp.data && resp.data.cliente) {
                setClientData(resp.data.cliente)
            } else if (resp.data) {
                setClientData(resp.data)
            }
        } catch (error) {
            console.error('Error fetching client details:', error)
        }
    }

    useEffect(() => {
        setClientData(client)
    }, [client])

    useEffect(() => {
        if (expanded) {
            fetchClientDetails()
        }
    }, [expanded])

    const togglePresupuestoModal = () => {
        setIsPresupuestoModalOpen(!isPresupuestoModalOpen)
    }

    const togglePagoModal = () => {
        setIsPagoModalOpen(!isPagoModalOpen)
    }

    const handleDelete = () => {
        fetchClients()
        fetchClientDetails()
    }

    const handleSubmitPay = () => {
        togglePagoModal()
        fetchClients()
        fetchClientDetails()
    }

    const handleSubmitPresupuesto = () => {
        togglePresupuestoModal()
        fetchClients()
        fetchClientDetails()
    }

    const clientDelete = async (clientId: string) => {
        if (!clientId) return

        try {
            const response: any = await apiDeleteClient(clientId)
            if (response?.data?.ok || response?.data?.success || response?.status === 200) {
                Swal.fire({
                    title: 'Eliminado',
                    text: 'El cliente ha sido eliminado correctamente.',
                    icon: 'success',
                    confirmButtonColor: '#3085d6',
                })
                handleDelete()
            } else {
                throw new Error('No se recibió confirmación del servidor')
            }
        } catch (error: any) {
            console.error('Error al eliminar el cliente:', error)
            Swal.fire({
                title: 'Error',
                text: error?.response?.data?.msg || error?.message || 'Hubo un problema al eliminar el cliente.',
                icon: 'error',
                confirmButtonColor: '#d33',
            })
        }
    }

    const handleConfirmDelete = (clientId: string) => {
        Swal.fire({
            title: '¿Estás seguro?',
            text: '¿Deseas eliminar este cliente?',
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#d33',
            cancelButtonColor: '#3085d6',
            confirmButtonText: 'Sí, eliminar',
            cancelButtonText: 'Cancelar',
        }).then((result) => {
            if (result.isConfirmed) {
                clientDelete(clientId)
            }
        })
    }

    return (
        <Card key={client._id} className="card-shadow mb-2 bg-gray">
            <div>
                <div className="flex justify-between items-center">
                    <div className="flex items-center">
                        <h5
                            className={`mr-3 ${
                                client.estado === 'Deudor'
                                    ? 'text-red-500 font-bold'
                                    : 'text-gray-900 dark:text-gray-100'
                            }`}
                        >
                            {client.tipoCliente?.toLowerCase() === 'persona'
                                ? `${client.apellido}, ${client.nombre}`
                                : client.razonSocial}
                        </h5>
                        
                        <div className="mr-3">
                            <Tag className={
                                client.estado === 'Activo' 
                                    ? 'bg-emerald-100 text-emerald-600 dark:bg-emerald-500/20 dark:text-emerald-100 border-0' 
                                    : client.estado === 'Deudor'
                                        ? 'bg-red-100 text-red-600 dark:bg-red-500/20 dark:text-red-100 border-0'
                                        : 'bg-gray-100 text-gray-600 dark:bg-gray-500/20 dark:text-gray-100 border-0'
                            }>
                                {client.estado}
                            </Tag>
                        </div>

                        <div id={isFirst ? "guide-client-dropdown" : undefined}>
                            <ClientDetailsDropdown 
                                client={client} 
                                fetchClients={fetchClients} 
                            />
                        </div>
                        <div id={isFirst ? "guide-add-presupuesto" : undefined}>
                            <AddPresupuestoButton isOpen={togglePresupuestoModal} />
                        </div>
                        <div id={isFirst ? "guide-add-pago" : undefined}>
                            <AddPagoButton isOpen={togglePagoModal} />
                        </div>
                        <div id={isFirst ? "guide-delete-client" : undefined}>
                            <DeleteButton
                                size="medium"
                                onDelete={() => handleConfirmDelete(client._id)}
                            />
                        </div>
                    </div>

                    <div className="flex items-center">
                        <h6 className="mr-2">
                            Saldo:{' '}
                            <span
                                className={`${
                                    totalDebt < 0
                                        ? 'text-green-500'
                                        : totalDebt > 0
                                          ? 'text-red-500'
                                          : 'text-gray-500'
                                }`}
                            >
                                {formatCurrency(totalDebt)}
                            </span>
                        </h6>

                        <IconButton 
                            id={isFirst ? "guide-expand-card" : undefined}
                            onClick={onToggleExpand} 
                            size="small"
                        >
                            {expanded ? (
                                <HiOutlineChevronUp />
                            ) : (
                                <HiOutlineChevronDown />
                            )}
                        </IconButton>
                    </div>
                </div>

                <div
                    className={`content-wrapper ${
                        expanded ? 'expanded' : 'collapsed'
                    }`}
                >
                    <div className="mt-3">
                        <PresupuestosCardList
                            presupuestos={clientData.Presupuestos || []}
                            clientId={clientData._id}
                            onDelete={() => {
                                handleDelete()
                                fetchClientDetails()
                            }}
                        />
                    </div>
                </div>
            </div>

            <AddPagoModal
                isOpen={isPagoModalOpen}
                toggleModal={togglePagoModal}
                selectedClientIndex={client._id}
                onSubmitPay={handleSubmitPay}
            />

            <AddPresupuestoModal
                isOpen={isPresupuestoModalOpen}
                toggleModal={togglePresupuestoModal}
                selectedClientIndex={client._id}
                onSubmitPay={handleSubmitPresupuesto}
            />
        </Card>
    )
}

export default ClientCardItem

import React from 'react'
import { Card, Tag, Tooltip } from '@/components/ui'
import classNames from 'classnames'
import {
    HiOutlineExternalLink,
    HiOutlineTruck,
    HiOutlineClipboardList,
} from 'react-icons/hi'

import { Pedido } from '@/@types/pedidos'

type CompactPedidoCardProps = {
    pedido: Partial<Pedido> & {
        _id: string
        numeroPedido: string
        categoria: string
        estado: string
        fechaPedido: string | Date
    }
    onClick: (pedido: Pedido) => void
}

const getStatusColor = (status: string) => {
    switch (status?.toUpperCase()) {
        case 'RECIBIDO':
            return 'bg-emerald-100 text-emerald-700'
        case 'PENDIENTE':
            return 'bg-amber-100 text-amber-700'
        case 'EN_TRANSITO':
            return 'bg-blue-100 text-blue-700'
        case 'CANCELADO':
            return 'bg-red-100 text-red-700'
        default:
            return 'bg-gray-100 text-gray-700'
    }
}

const getCategoryIcon = (categoria: string) => {
    switch (categoria?.toLowerCase()) {
        case 'herrajes':
            return (
                <HiOutlineClipboardList className="text-orange-500 text-sm" />
            )
        case 'perfiles':
            return <HiOutlineTruck className="text-blue-500 text-sm" />
        case 'vidrios':
            return <HiOutlineClipboardList className="text-cyan-500 text-sm" />
        case 'obra gruesa':
            return <HiOutlineTruck className="text-gray-600 text-sm" />
        case 'instalaciones':
            return <HiOutlineClipboardList className="text-green-500 text-sm" />
        case 'aberturas':
            return (
                <HiOutlineClipboardList className="text-purple-500 text-sm" />
            )
        case 'terminaciones':
            return <HiOutlineClipboardList className="text-pink-500 text-sm" />
        case 'herramientas':
            return <HiOutlineClipboardList className="text-red-500 text-sm" />
        default:
            return <HiOutlineClipboardList className="text-gray-500 text-sm" />
    }
}

const CompactPedidoCard: React.FC<CompactPedidoCardProps> = ({
