                    <HiOutlineExternalLink className="text-gray-400 text-sm opacity-0 group-hover:opacity-100 transition-opacity" />
                </div>
            </div>

            <div className="mb-2 text-xs text-gray-600">
                {pedido.proyecto && (
                    <p className="truncate mb-1">
