                            {typeof pedido.proyecto === 'object'
                                ? pedido.proyecto.nombre
                                : 'Proyecto asociado'}
                        </span>
                    </p>
                )}
                {pedido.subcategoria && (
                    <p className="truncate mb-1">
                        <span className="font-medium">
