import React from 'react'
import { Card, Tag } from '@/components/ui'
import classNames from 'classnames'
import { Project } from '@/@types/project'

type CompactProjectCardProps = {
    project: Project
    onClick: (project: Project) => void
    getProgressClasses: (percent: number) => { border: string, text: string, ring: string, bg: string }
    normalizeProgress: (val: number) => number
    getClientName: (client: any) => string
    getResponsableName: (resp: any) => string
    getStatusColor: (status?: string) => string
}

const ProgressBar = ({ percent, colorClass }: { percent: number, colorClass: string }) => {
    const normalizeInternal = (val: number) => {
        if (!val) return 0
        return (val > 0 && val <= 1) ? val * 100 : val
    }
    const p = normalizeInternal(percent)
    return (
        <div className="w-full bg-gray-200 rounded-full h-1 overflow-hidden">
            <div 
                className={`h-full rounded-full transition-all duration-500 ${colorClass}`}
                style={{ width: `${Math.min(p, 100)}%` }}
            />
        </div>
    )
}

const CompactProjectCard: React.FC<CompactProjectCardProps> = ({ 
    project, 
    onClick, 
    getProgressClasses, 
    normalizeProgress,
    getClientName,
    getResponsableName,
    getStatusColor
}) => {
    const colors = getProgressClasses(project.avance)
    const p = normalizeProgress(project.avance)

    return (
        <Card 
            clickable 
            className={`hover:shadow-md transition-shadow border-l-4 ${colors.border} p-3`}
            onClick={() => onClick(project)}
            bodyClass="p-0"
        >
            <div className="flex justify-between items-start mb-2">
                <div className="flex-1 min-w-0">
                    <h6 className="font-semibold text-sm text-gray-900 truncate mb-1">{project.nombre}</h6>
                    <span className="text-xs text-gray-500">{project.codigo}</span>
                </div>
                <Tag className={classNames(
                    getStatusColor(project.estado), 
                    "border-0 text-xs ml-2 flex-shrink-0"
                )}>
                    {project.estado?.replace('_', ' ') || 'ACTIVO'}
                </Tag>
            </div>
            
            <div className="mb-2 text-xs text-gray-600">
                <p className="truncate">Cliente: <span className="font-medium">{getClientName(project.cliente)}</span></p>
                <p className="truncate">Responsable: <span className="font-medium">{getResponsableName(project.responsable)}</span></p>
            </div>

            <div>
                <div className="flex justify-between text-xs mb-1">
                    <span className="text-gray-600">Progreso</span>
                    <span className="font-semibold text-gray-900">{Math.round(p)}%</span>
                </div>
                <ProgressBar percent={project.avance} colorClass={colors.bg} />
            </div>
        </Card>
    )
}

export default CompactProjectCard

import { useEffect, useState } from 'react'
import { useSelector } from 'react-redux'
import { RootState } from '@/store/rootReducer'
import { HiOutlineInformationCircle, HiArrowRight, HiOutlineCursorClick, HiCheck } from 'react-icons/hi'
import useAuth from '@/utils/hooks/useAuth'
import { motion, AnimatePresence } from 'framer-motion'
import { Client } from '@/@types/clientInfo'

const ClientCardOnboarding = ({ 
    clients, 
    loading 
}: { 
    clients: Client[];
    loading: boolean;
}) => {
    const { authenticated } = useAuth()
    const { currentBusinessUnit } = useSelector(
        (state: RootState) => state.businessUnit.data
    )
    
    const [step, setStep] = useState(0) 
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null)
    const [prevClientsCount, setPrevClientsCount] = useState((Array.isArray(clients) ? clients : []).length)

    const steps = [
        { id: 'guide-client-dropdown', title: 'Opciones de Cliente', desc: 'Aquí puedes ver el detalle completo del cliente o editar su información personal.' },
        { id: 'guide-add-presupuesto', title: 'Nuevo Presupuesto', desc: 'Utiliza este botón para generar un nuevo presupuesto vinculado a este cliente.' },
        { id: 'guide-add-pago', title: 'Registrar Pago', desc: 'Desde aquí podrás cargar los cobros y pagos realizados por el cliente.' },
        { id: 'guide-delete-client', title: 'Eliminar Cliente', desc: 'Si necesitas dar de baja al cliente y borrar su historial, usa esta opción.' },
        { id: 'guide-expand-card', title: 'Ver Historial', desc: 'Haz clic para expandir la tarjeta y ver el listado de todos los presupuestos y estados.' }
    ]

    useEffect(() => {
        if (loading) return

        const currentCount = (Array.isArray(clients) ? clients : []).length
        if (currentCount === 1 && prevClientsCount === 0) {
            setStep(1)
        }
        setPrevClientsCount(currentCount)
    }, [clients?.length, loading, prevClientsCount])

    useEffect(() => {
        const updateRect = () => {
            if (step >= 2 && step <= 6) {
                const targetId = steps[step - 2].id
                const el = document.getElementById(targetId)
                if (el) setTargetRect(el.getBoundingClientRect())
            }
        }

        updateRect()
        const interval = setInterval(updateRect, 500)

        window.addEventListener('resize', updateRect)
        window.addEventListener('scroll', updateRect, true)
        return () => {
            clearInterval(interval)
            window.removeEventListener('resize', updateRect)
            window.removeEventListener('scroll', updateRect, true)
        }
    }, [step])

    // Solo mostrar si hay exactamente 1 cliente (el primero creado)
    const showOnboarding = authenticated && 
                          !loading && 
                          currentBusinessUnit?._id &&
                          (Array.isArray(clients) ? clients : []).length === 1 && 
                          step !== 0

    if (!showOnboarding) {
        return null
    }

    return (
        <AnimatePresence>
            {step === 1 && (
                <motion.div 
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="fixed inset-0 z-[3000] flex items-center justify-center bg-gray-950/40 backdrop-blur-sm p-4"
                >
                    <motion.div 
                        initial={{ opacity: 0, scale: 0.98, y: 10 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        className="bg-white dark:bg-gray-800 p-10 rounded-[2.5rem] shadow-2xl max-w-sm w-full border border-gray-100 dark:border-gray-700 text-center relative"
                    >
                        <div className="mb-6 flex justify-center">
                            <div className="w-20 h-20 bg-blue-50 dark:bg-blue-900/20 rounded-3xl flex items-center justify-center">
                                <HiOutlineInformationCircle className="text-4xl text-blue-600 dark:text-blue-400" />
                            </div>
                        </div>
                        
                        <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-3">
                            ¡Primer Cliente!
                        </h3>
                        <p className="text-gray-500 dark:text-gray-400 mb-8 text-sm leading-relaxed">
                            ¡Excelente! Ya tienes tu primer cliente. Veamos rápidamente qué puedes hacer con estas tarjetas de gestión.
                        </p>
                        
                        <button 
                            onClick={() => setStep(2)}
                            className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl flex items-center justify-center gap-2 transition-all font-bold text-sm shadow-xl active:scale-[0.98]"
                        >
                            Ver funciones
                            <HiArrowRight className="text-base" />
                        </button>
                    </motion.div>
                </motion.div>
            )}

            {step >= 2 && step <= 6 && (
                <div className="fixed inset-0 z-[3000] overflow-hidden">
                    <svg className="absolute inset-0 w-full h-full pointer-events-none">
                        <defs>
                            <mask id="client-card-spotlight-mask">
                                <rect width="100%" height="100%" fill="white" />
                                {targetRect && (
                                    <rect 
                                        x={targetRect.left - 6} 
                                        y={targetRect.top - 6} 
                                        width={targetRect.width + 12} 
                                        height={targetRect.height + 12} 
                                        rx="10" 
                                        fill="black" 
                                        className="transition-all duration-300"
                                    />
                                )}
                            </mask>
                        </defs>
                        <rect 
                            width="100%" 
                            height="100%" 
                            fill="rgba(15, 23, 42, 0.75)"
                            mask="url(#client-card-spotlight-mask)" 
                            className="transition-all duration-300 pointer-events-auto"
                        />
                    </svg>

                    {/* Full screen interaction block */}
                    <div className="fixed inset-0 bg-transparent pointer-events-auto" />

                    {targetRect && (
                        <motion.div 
                            key={`step-${step}`}
                            initial={{ opacity: 0, y: 15 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="absolute pointer-events-auto z-[3001]"
                            style={{ 
                                top: targetRect.bottom + 20, 
                                left: Math.max(20, Math.min(window.innerWidth - 300, targetRect.left + (targetRect.width / 2) - 140)),
                                width: 280
                            }}
                        >
                            <div className="bg-white dark:bg-gray-800 border-t-4 border-blue-500 p-6 rounded-2xl shadow-2xl flex flex-col gap-3">
                                <div className="flex items-center justify-between mb-1">
                                    <div className="w-8 h-8 bg-blue-50 dark:bg-blue-900/40 rounded-lg flex items-center justify-center">
                                        <HiOutlineCursorClick className="text-blue-600 dark:text-blue-400 text-sm" />
                                    </div>
                                    <span className="text-[10px] font-bold text-blue-600 bg-blue-50 dark:bg-blue-900/40 px-2.5 py-0.5 rounded-full tracking-wider uppercase">
                                        Paso {step - 1} / 5
                                    </span>
                                </div>
                                <h4 className="text-base font-bold text-gray-900 dark:text-white">
                                    {steps[step - 2].title}
                                </h4>
                                <p className="text-xs text-gray-500 dark:text-gray-400 leading-relaxed">
                                    {steps[step - 2].desc}
                                </p>

                                <button 
                                    onClick={() => step === 6 ? setStep(0) : setStep(step + 1)}
                                    className="mt-2 w-full py-2.5 bg-gray-900 dark:bg-gray-100 text-white dark:text-gray-900 rounded-xl flex items-center justify-center gap-2 transition-all font-bold text-xs active:scale-[0.98]"
                                >
                                    {step === 6 ? 'Entendido, finalizar' : 'Siguiente'}
                                    {step === 6 ? <HiCheck /> : <HiArrowRight />}
                                </button>
                            </div>
                        </motion.div>
                    )}
                </div>
            )}
        </AnimatePresence>
    )
}

export default ClientCardOnboarding

import { useEffect, useState } from 'react'
import { useSelector } from 'react-redux'
import { RootState } from '@/store/rootReducer'
import { HiOutlineUserGroup, HiArrowRight, HiOutlineCursorClick } from 'react-icons/hi'
import useAuth from '@/utils/hooks/useAuth'
import { motion, AnimatePresence } from 'framer-motion'
import { Client } from '@/@types/clientInfo'

const ClientsOnboarding = ({ 
    isFormOpen, 
    clients, 
    loading 
}: { 
    isFormOpen: boolean;
    clients: Client[];
    loading: boolean;
}) => {
    const { authenticated } = useAuth()
    const { currentBusinessUnit } = useSelector(
        (state: RootState) => state.businessUnit.data
    )
    
    const [step, setStep] = useState(1) // 1: Welcome, 2: Highlight Add Client Button, 3: Form Instructions, 0: Done
    const [addClientRect, setAddClientRect] = useState<DOMRect | null>(null)
    const [submitButtonRect, setSubmitButtonRect] = useState<DOMRect | null>(null)
    const [prevClientsCount, setPrevClientsCount] = useState((Array.isArray(clients) ? clients : []).length)
    
    useEffect(() => {
        if (loading) return

        const currentCount = (Array.isArray(clients) ? clients : []).length
        if (currentCount === 0 && prevClientsCount !== 0) {
            setStep(1)
        }
        setPrevClientsCount(currentCount)
    }, [clients.length, loading, prevClientsCount])

    useEffect(() => {
        const updateRects = () => {
            if (step === 2) {
                const el = document.getElementById('add-client-button')
                if (el) setAddClientRect(el.getBoundingClientRect())
            }
            if (step === 3) {
                const el = document.getElementById('submit-client-button')
                if (el) setSubmitButtonRect(el.getBoundingClientRect())
            }
        }

        if (step === 2 && isFormOpen) {
            setStep(3)
        }

        updateRects()
        const interval = setInterval(updateRects, 500)

        window.addEventListener('resize', updateRects)
        window.addEventListener('scroll', updateRects, true)
        return () => {
            clearInterval(interval)
            window.removeEventListener('resize', updateRects)
            window.removeEventListener('scroll', updateRects, true)
        }
    }, [step, isFormOpen])

    // Solo mostrar onboarding si hay unidad de negocio pero no hay clientes
    const showOnboarding = authenticated && 
                          !loading && 
                          currentBusinessUnit?._id &&
                          (Array.isArray(clients) ? clients : []).length === 0 && 
                          step !== 0

    if (!showOnboarding) {
        return null
    }

    return (
        <AnimatePresence>
            {step === 1 && (
                <motion.div 
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="fixed inset-0 z-[100] flex items-center justify-center bg-gray-950/40 backdrop-blur-sm p-4"
                >
                    <motion.div 
                        initial={{ opacity: 0, scale: 0.98, y: 10 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        transition={{ duration: 0.4, ease: "easeOut" }}
                        className="bg-white dark:bg-gray-800 p-10 rounded-[2rem] shadow-2xl max-w-sm w-full border border-gray-100 dark:border-gray-700 text-center relative"
                    >
                        <div className="mb-6 flex justify-center">
                            <div className="w-16 h-16 bg-green-50 dark:bg-green-900/20 rounded-2xl flex items-center justify-center">
                                <HiOutlineUserGroup className="text-3xl text-green-600 dark:text-green-400" />
                            </div>
                        </div>
                        
                        <div className="flex justify-center mb-3">
                             <span className="text-[10px] font-medium text-gray-400 uppercase tracking-[0.2em]">
                                Primeros Pasos
                            </span>
                        </div>

                        <h3 className="text-xl font-semibold text-gray-900 dark:text-white mb-3">
                            Agregar su Primer Cliente
                        </h3>
                        <p className="text-gray-500 dark:text-gray-400 mb-8 text-sm font-light leading-relaxed px-2">
                            Aún no tiene clientes registrados. Comencemos agregando su primer cliente para empezar a gestionar presupuestos y pagos.
                        </p>
                        
                        <button 
                            onClick={() => setStep(2)}
                            className="w-full py-3.5 bg-green-600 hover:bg-green-700 text-white rounded-xl flex items-center justify-center gap-2 transition-all font-medium text-sm shadow-lg shadow-green-100 dark:shadow-none active:scale-[0.98]"
                        >
                            Comenzar guía
                            <HiArrowRight className="text-base" />
                        </button>
                    </motion.div>
                </motion.div>
            )}

            {step === 2 && (
                <div className="fixed inset-0 z-[100] pointer-events-none overflow-hidden">
                    {/* Visual Spotlight Mask */}
                    <svg className="absolute inset-0 w-full h-full pointer-events-none">
                        <defs>
                            <mask id="client-spotlight-mask">
                                <rect width="100%" height="100%" fill="white" />
                                {addClientRect && (
                                    <rect 
                                        x={addClientRect.left - 4} 
                                        y={addClientRect.top - 4} 
                                        width={addClientRect.width + 8} 
                                        height={addClientRect.height + 8} 
                                        rx="12" 
                                        fill="black" 
                                    />
                                )}
                            </mask>
                        </defs>
                        <rect 
                            width="100%" 
                            height="100%" 
                            fill="rgba(15, 23, 42, 0.7)"
                            mask="url(#client-spotlight-mask)" 
                        />
                    </svg>

                    {/* Interaction Blockers (4 divs to create a hole) */}
                    {addClientRect && (
                        <>
                            {/* Top blocker */}
                            <div className="fixed bg-transparent pointer-events-auto" style={{ top: 0, left: 0, right: 0, height: addClientRect.top - 4 }} />
                            {/* Bottom blocker */}
                            <div className="fixed bg-transparent pointer-events-auto" style={{ top: addClientRect.bottom + 4, left: 0, right: 0, bottom: 0 }} />
                            {/* Left blocker */}
                            <div className="fixed bg-transparent pointer-events-auto" style={{ top: addClientRect.top - 4, left: 0, width: addClientRect.left - 4, height: addClientRect.height + 8 }} />
                            {/* Right blocker */}
                            <div className="fixed bg-transparent pointer-events-auto" style={{ top: addClientRect.top - 4, left: addClientRect.right + 4, right: 0, height: addClientRect.height + 8 }} />
                        </>
                    )}

                    {addClientRect && (
                        <motion.div 
                            key="tooltip-add-client"
                            initial={{ opacity: 0, y: 15 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="absolute pointer-events-auto z-[101]"
                            style={{ 
                                top: addClientRect.bottom + 20, 
                                left: Math.max(20, Math.min(window.innerWidth - 300, addClientRect.left + (addClientRect.width / 2) - 140)),
                                width: 280
                            }}
                        >
                            <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-2xl flex flex-col gap-2">
                                <div className="flex items-center justify-between mb-1">
                                    <div className="w-6 h-6 bg-green-50 dark:bg-green-900/40 rounded-lg flex items-center justify-center">
                                        <HiOutlineCursorClick className="text-green-600 dark:text-green-400 text-xs" />
                                    </div>
                                    <span className="text-[10px] font-bold text-green-600 bg-green-50 dark:bg-green-900/40 px-2.5 py-0.5 rounded-full tracking-wider">
                                        PASO 1 / 2
                                    </span>
                                </div>
                                <h4 className="text-sm font-semibold text-gray-900 dark:text-white">
                                    Presione para Agregar
                                </h4>
                                <p className="text-xs text-gray-500 dark:text-gray-400 leading-relaxed font-light">
                                    Haga clic únicamente en el botón resaltado para abrir el formulario de cliente.
                                </p>
                            </div>
                        </motion.div>
                    )}
                </div>
            )}

            {step === 3 && (
                <div className="fixed inset-0 z-[2000] overflow-hidden pointer-events-none">
                    {/* Visual Mask showing the form button */}
                    <svg className="absolute inset-0 w-full h-full">
                        <defs>
                            <mask id="client-spotlight-mask-step3">
                                <rect width="100%" height="100%" fill="white" />
                                {submitButtonRect && (
                                    <rect 
                                        x={submitButtonRect.left - 4} 
                                        y={submitButtonRect.top - 4} 
                                        width={submitButtonRect.width + 8} 
                                        height={submitButtonRect.height + 8} 
                                        rx="12" 
                                        fill="black" 
                                    />
                                )}
                            </mask>
                        </defs>
                        <rect 
                            width="100%" 
                            height="100%" 
                            fill="rgba(15, 23, 42, 0.85)"
                            mask="url(#client-spotlight-mask-step3)" 
                            className="backdrop-blur-[2px] pointer-events-auto"
                        />
                    </svg>

                    {/* Interaction Block Over Everything */}
                    <div className="fixed inset-0 bg-transparent pointer-events-auto" />

                    <div className="fixed inset-0 flex items-end justify-end pointer-events-none p-8">
                        <motion.div 
                            initial={{ opacity: 0, scale: 0.9, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            className="bg-white dark:bg-gray-800 p-8 rounded-[2rem] shadow-[0_20px_50px_rgba(0,0,0,0.6)] border border-indigo-100 dark:border-indigo-900/50 max-w-xs w-full text-center relative pointer-events-auto mb-10 mr-4"
                        >
                            <div className="flex justify-center mb-4">
                                <div className="w-16 h-16 bg-indigo-50 dark:bg-indigo-900/40 rounded-2xl flex items-center justify-center">
                                    <HiOutlineCursorClick className="text-indigo-600 dark:text-indigo-400 text-3xl" />
                                </div>
                            </div>
                            
                            <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-2">
                                Paso Final
                            </h4>
                            <p className="text-xs text-gray-500 dark:text-gray-400 mb-6 leading-relaxed">
                                Complete el formulario lateral y cuando termine presione el botón <strong className="text-indigo-600 font-bold uppercase">Agregar Cliente</strong> resaltado.
                            </p>

                            <button 
                                onClick={() => setStep(0)}
                                className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl flex items-center justify-center gap-2 transition-all font-bold text-xs shadow-lg active:scale-[0.98]"
                            >
                                ¡Entendido!
                            </button>
                        </motion.div>
                    </div>
                </div>
            )}
        </AnimatePresence>
    )
}

export default ClientsOnboarding

