import React, { useState, useEffect, useCallback } from 'react'
import { Client } from '@/@types/clientInfo'
import { Project } from '@/@types/project'
import ClientDashboardStats from './ClientDashboardStats'
import PresupuestosCardList from '../Lists/PresupuestosCardList'
import AddPagoModal from '../Modal/AddPagoModal'
import AddPresupuestoModal from '../Modal/AddPresupuestoModal'
import { Card } from '@/components/ui'
import {
    HiOutlineDocumentText,
    HiOutlineCube,
    HiOutlineTruck,
} from 'react-icons/hi'
import { apiGetProjects } from '@/services/ProjectService'
import '../clientViewStyles.css'
import { apiGetPedidos } from '@/services/PedidoService'
import CompactProjectCard from '../Cards/CompactProjectCard'
import CompactPedidoCard from '../Cards/CompactPedidoCard'
import { Pedido } from '@/@types/pedidos'
import ProjectDashboardPanel from '../../ProjectsView/Dashboard/ProjectDashboardPanel'
import PedidoDetailPanel from '../Panels/PedidoDetailPanel'
import { useProjectActions } from '@/utils/hooks/useProjectActions'
import { useAppSelector } from '@/store'
import {
    normalizeProgress,
    getProgressClasses,
    getClientName,
    getResponsableName,
    getStatusColor,
} from '@/utils/projectUtils'

interface ClientDashboardContentProps {
    client: Client
    onUpdate: () => void
    onStatusChange?: (newStatus: Client['estado']) => void
}

const ClientDashboardContent: React.FC<ClientDashboardContentProps> = ({
    client,
    onUpdate,
    onStatusChange,
}) => {
    const [isPagoModalOpen, setIsPagoModalOpen] = useState(false)
    const [isPresupuestoModalOpen, setIsPresupuestoModalOpen] = useState(false)
    const [associatedProjects, setAssociatedProjects] = useState<Project[]>([])
    const [associatedPedidos, setAssociatedPedidos] = useState<Pedido[]>([])
    const [loadingProjects, setLoadingProjects] = useState(false)
    const [loadingPedidos, setLoadingPedidos] = useState(false)

    // Project Dashboard state
    const [projectDashboardOpen, setProjectDashboardOpen] = useState(false)
    const [selectedProject, setSelectedProject] = useState<Project | null>(null)

    // Pedido Detail Panel state
    const [pedidoDetailOpen, setPedidoDetailOpen] = useState(false)
    const [selectedPedido, setSelectedPedido] = useState<Pedido | null>(null)

    const currentBusinessUnit = useAppSelector(
        (state) => state.businessUnit.data.currentBusinessUnit,
    )

    const togglePagoModal = () => setIsPagoModalOpen(!isPagoModalOpen)
    const togglePresupuestoModal = () =>
        setIsPresupuestoModalOpen(!isPresupuestoModalOpen)

    const openProjectDashboard = (project: Project) => {
        setSelectedProject(project)
        setProjectDashboardOpen(true)
    }

    const openPedidoDetail = (pedido: Pedido) => {
        setSelectedPedido(pedido)
        setPedidoDetailOpen(true)
    }

    const fetchAssociatedData = useCallback(async () => {
        if (!client._id) return

        console.log('Fetching data for client:', client._id)
        setLoadingProjects(true)
        setLoadingPedidos(true)

        try {
            // Fetch projects
            const projectsResp: any = await apiGetProjects({
                cliente: client._id,
            })
            console.log('Projects response:', projectsResp)

            if (projectsResp.data?.ok) {
                setAssociatedProjects(projectsResp.data.proyectos)

                // Fetch pedidos for each project
                const projectIds =
                    projectsResp.data.proyectos?.map((p: any) => p._id) || []
                console.log('Project IDs:', projectIds)

                if (projectIds.length > 0) {
                    try {
                        const pedidosResp: any = await apiGetPedidos({
                            proyecto: projectIds.join(','),
                        })
                        console.log(
                            'Pedidos response (by project):',
                            pedidosResp,
                        )

                        // If we got pedidos specifically for these projects, use them
                        if (
                            pedidosResp.data?.ok &&
                            pedidosResp.data.pedidos?.length > 0
                        ) {
                            console.log(
                                'Found pedidos:',
                                pedidosResp.data.pedidos.length,
                            )
                            setAssociatedPedidos(pedidosResp.data.pedidos)
                        } else if (pedidosResp.data?.ok) {
                            // If the response was OK but empty, try the fallback just in case
                            // (e.g. if the backend doesn't support multiple IDs or there's a casting issue)
                            console.log(
                                'No pedidos found by project ID string, trying fallback...',
                            )
                            const allPedidosResp: any = await apiGetPedidos({})

                            if (
                                allPedidosResp.data?.ok &&
                                allPedidosResp.data.pedidos
                            ) {
                                const filtered =
                                    allPedidosResp.data.pedidos.filter(
                                        (p: any) => {
                                            if (!p.proyecto) return false
                                            const proyectoId =
                                                typeof p.proyecto === 'object'
                                                    ? p.proyecto._id
                                                    : p.proyecto
                                            return projectIds.includes(
                                                proyectoId,
                                            )
                                        },
                                    )
                                console.log(
                                    'Filtered pedidos (fallback):',
                                    filtered.length,
                                )
                                setAssociatedPedidos(filtered)
                            } else {
                                setAssociatedPedidos([])
                            }
                        } else {
                            setAssociatedPedidos([])
                        }
                    } catch (pedidosError) {
                        console.error('Error fetching pedidos:', pedidosError)
                        setAssociatedPedidos([])
                    }
                } else {
                    console.log('No project IDs found')
                    setAssociatedPedidos([])
                }
            } else {
                console.log('No projects found for client')
                setAssociatedProjects([])
                setAssociatedPedidos([])
            }
        } catch (error) {
            console.error('Error fetching associated client data:', error)
            setAssociatedProjects([])
            setAssociatedPedidos([])
        } finally {
            setLoadingProjects(false)
            setLoadingPedidos(false)
        }
    }, [client._id])

    const { updateStageProgress, updateSubTaskProgress, updateProjectStatus } =
        useProjectActions(
            () => fetchAssociatedData(), // Refresh function
            setAssociatedProjects,
            currentBusinessUnit?._id,
        )

    useEffect(() => {
        fetchAssociatedData()
    }, [fetchAssociatedData])

    return (
        <div className="flex flex-col space-y-2">
            <div className="flex-shrink-0">
                <ClientDashboardStats
                    client={client}
                    togglePresupuestoModal={togglePresupuestoModal}
                    togglePagoModal={togglePagoModal}
                    onStatusChange={onStatusChange}
                />
            </div>

            <Card className="shadow-sm bg-white overflow-hidden flex flex-col min-h-[200px] max-h-[400px]">
                <div className="p-3 border-b border-gray-50 flex items-center gap-2 flex-shrink-0">
                    <HiOutlineDocumentText className="text-blue-500 text-lg" />
                    <span className="font-bold text-gray-700 text-base">
                        Historial de Presupuestos
                    </span>
                </div>
                <div className="p-0 overflow-y-auto custom-scrollbar flex-1 min-h-0">
                    <PresupuestosCardList
                        presupuestos={client.Presupuestos || []}
                        clientId={client._id}
                        onDelete={onUpdate}
                    />
                </div>
            </Card>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-2">
                {/* Associated Projects Section */}
                <Card className="shadow-sm bg-white flex flex-col min-h-[200px] max-h-[400px] overflow-hidden">
                    <div className="p-2 border-b border-gray-50 flex items-center justify-between flex-shrink-0">
                        <div className="flex items-center gap-2">
                            <HiOutlineCube className="text-amber-500 text-lg" />
                            <span className="font-bold text-gray-700 text-base">
                                Proyectos Asociados
                            </span>
                        </div>
                        <span className="text-[10px] font-black text-gray-400 uppercase bg-gray-50 px-2 py-1 rounded">
                            {associatedProjects.length}
                        </span>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-2 min-h-0">
                        {loadingProjects ? (
                            <div className="text-center py-4 text-gray-400 italic">
                                Cargando proyectos...
                            </div>
                        ) : associatedProjects.length > 0 ? (
                            <div className="space-y-2">
                                {associatedProjects.map((project) => (
                                    <div
                                        key={project._id}
                                        className="flex-shrink-0"
                                    >
                                        <CompactProjectCard
                                            project={project}
                                            onClick={openProjectDashboard}
                                            getProgressClasses={
                                                getProgressClasses
                                            }
                                            normalizeProgress={
                                                normalizeProgress
                                            }
                                            getClientName={getClientName}
                                            getResponsableName={
                                                getResponsableName
                                            }
                                            getStatusColor={getStatusColor}
                                        />
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="text-center py-8 text-gray-400 italic">
                                No hay proyectos asociados.
                            </div>
                        )}
                    </div>
                </Card>

                {/* Associated Pedidos Section */}
                <Card className="shadow-sm bg-white flex flex-col min-h-[200px] max-h-[400px] overflow-hidden">
                    <div className="p-2 border-b border-gray-50 flex items-center justify-between flex-shrink-0">
                        <div className="flex items-center gap-2">
                            <HiOutlineTruck className="text-emerald-500 text-lg" />
                            <span className="font-bold text-gray-700 text-base">
                                Pedidos Asociados
                            </span>
                        </div>
                        <span className="text-[10px] font-black text-gray-400 uppercase bg-gray-50 px-2 py-1 rounded">
                            {associatedPedidos.length}
                        </span>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-2 min-h-0">
                        {loadingPedidos ? (
                            <div className="text-center py-4 text-gray-400 italic">
                                Cargando pedidos...
                            </div>
                        ) : associatedPedidos.length > 0 ? (
                            <div className="space-y-2">
                                {associatedPedidos.map((pedido) => (
                                    <div key={pedido._id} className="">
                                        <CompactPedidoCard
                                            pedido={pedido}
                                            onClick={openPedidoDetail}
                                        />
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="text-center py-8 text-gray-400 italic">
                                No hay pedidos asociados.
                            </div>
                        )}
                    </div>
                </Card>
            </div>

            {/* Project Dashboard Panel */}
            <ProjectDashboardPanel
                project={selectedProject}
                isOpen={projectDashboardOpen}
                onClose={() => setProjectDashboardOpen(false)}
                onSubTaskUpdate={(stageId, subetapaId, completed) =>
                    updateSubTaskProgress(
                        selectedProject!._id,
                        stageId,
                        subetapaId,
                        completed,
                        selectedProject,
                        setSelectedProject,
                    )
                }
                onStageUpdate={(stageId, newAvance) =>
                    updateStageProgress(
                        selectedProject!._id,
                        stageId,
                        newAvance,
                        selectedProject,
                        setSelectedProject,
                    )
                }
                onStatusUpdate={(newStatus: Project['estado']) =>
                    updateProjectStatus(
                        selectedProject!._id,
                        newStatus,
                        selectedProject,
                        setSelectedProject,
                    )
                }
                onProjectUpdate={() => fetchAssociatedData()}
            />

            {/* Pedido Detail Panel */}
            <PedidoDetailPanel
                pedido={selectedPedido}
                isOpen={pedidoDetailOpen}
                onClose={() => setPedidoDetailOpen(false)}
            />

            {/* Modals */}
            <AddPagoModal
                isOpen={isPagoModalOpen}
                toggleModal={togglePagoModal}
                selectedClientIndex={client._id}
                onSubmitPay={() => {
                    togglePagoModal()
                    onUpdate()
                }}
            />

            <AddPresupuestoModal
                isOpen={isPresupuestoModalOpen}
                toggleModal={togglePresupuestoModal}
                selectedClientIndex={client._id}
                onSubmitPay={() => {
                    togglePresupuestoModal()
                    onUpdate()
                }}
            />
        </div>
    )
}

export default ClientDashboardContent

