import React from 'react'
import { Drawer } from '@/components/ui'
import { Client } from '@/@types/clientInfo'

import ClientDashboardHeader from './ClientDashboardHeader'
import ClientDashboardContent from './ClientDashboardContent'
import { apiGetClientById, apiUpdateClient } from '@/services/ClientService'
import Swal from 'sweetalert2'

interface ClientDashboardPanelProps {
    client: Client | null
    isOpen: boolean
    onClose: () => void
    onUpdate?: () => void
}

const ClientDashboardPanel: React.FC<ClientDashboardPanelProps> = ({
    client: initialClient,
    isOpen,
    onClose,
    onUpdate
}) => {
    const [client, setClient] = React.useState<Client | null>(initialClient)
    const [loading, setLoading] = React.useState(false)

    React.useEffect(() => {
        if (isOpen && initialClient) {
            setClient(initialClient)
            fetchFullClient(initialClient._id)
        }
    }, [isOpen, initialClient])

    const fetchFullClient = async (id: string) => {
        setLoading(true)
        try {
            const resp: any = await apiGetClientById(id)
            if (resp.data && resp.data.cliente) {
                setClient(resp.data.cliente)
            } else if (resp.data) {
                setClient(resp.data)
            }
        } catch (error) {
            console.error('Error fetching full client:', error)
        } finally {
            setLoading(false)
        }
    }

    const handleStatusUpdate = async (newStatus: Client['estado']) => {
        if (!client) return
        
        // Optimistic update
        setClient({ ...client, estado: newStatus })

        try {
            await apiUpdateClient(client._id, { estado: newStatus })
            Swal.fire({
                title: 'Estado actualizado',
                text: `El cliente ahora está en estado "${newStatus}"`,
                icon: 'success',
                showConfirmButton: false,
                timer: 1500,
            })
            if (onUpdate) onUpdate()
        } catch (error) {
            console.error('Error updating status:', error)
            fetchFullClient(client._id) // Revert on error
        }
    }

    if (!initialClient) return null

    return (
        <Drawer
            title={
                client ? (
                    <ClientDashboardHeader 
                        client={client} 
                    />
                ) : null
            }
            isOpen={isOpen}
            onClose={onClose}
            placement="top" height="100%" width="100%"
            headerClass="border-b border-gray-300 px-8 py-5 bg-white backdrop-blur-md sticky top-0 z-50 rounded-t-[2.5rem] shadow-sm"
            bodyClass="p-0 bg-gray-50/10 flex flex-col h-[100vh] overflow-hidden"
            className="rounded-b-[2.5rem] overflow-hidden shadow-2xl"
        >
            <div className="flex-1 overflow-y-auto custom-scrollbar bg-gray-100 p-2">
                <div>
                    {client && (
                        <ClientDashboardContent 
                            client={client} 
                            onUpdate={() => {
                                fetchFullClient(client._id)
                                if (onUpdate) onUpdate()
                            }}
                            onStatusChange={handleStatusUpdate}
                        />
                    )}
                </div>
            </div>
        </Drawer>
    )
}

export default ClientDashboardPanel

