import React, { useEffect, useState } from 'react'
import { HiCheckCircle, HiExclamationCircle } from 'react-icons/hi'
import { Formik, Field, Form, FieldProps, FormikHelpers } from 'formik'
import * as Yup from 'yup'
import { Input, Select } from '@/components/ui'
import { FormItem, FormContainer } from '@/components/ui'
import { apiCreatePago } from '@/services/PagoService'
import { apiGetClientById } from '@/services/ClientService'
import getCurrentDate from '@/utils/hooks/getCurrentDate'
import { Client, Presupuesto, Pago } from '@/@types/clientInfo'
import useCurrencyInput from '@/utils/hooks/useCurrencyInput'

type Props = {
    selectedClientIndex: string
    onSubmitPay: () => void
    submitRef: React.MutableRefObject<() => void>
}

interface Option {
    value: string
    label: string
}

const AddPagoForm: React.FC<Props> = ({
    selectedClientIndex,
    onSubmitPay,
    submitRef,
}) => {
    const [clientByID, setClientByID] = useState<Client | null>(null)
    const [message, setMessage] = useState('')
    const [conceptOptions, setConceptOptions] = useState<Option[]>([])

    const pagoMontoInput = useCurrencyInput(0)

    useEffect(() => {
        const loadClient = async () => {
            try {
                const resp: any = await apiGetClientById(selectedClientIndex)
                if (resp.data && resp.data.cliente) {
                    setClientByID(resp.data.cliente)
                } else if (resp.data) {
                    setClientByID(resp.data)
                }
            } catch (error) {
                console.error('Error al cargar los datos del cliente:', error)
            }
        }

        loadClient()
    }, [selectedClientIndex])

    const initialValues: Pago = {
        presupuesto: '',
        monto: pagoMontoInput.value,
        condicionPago: '',
        concepto: '',
        fechaPago: getCurrentDate(),
        comprobante: '',
        observaciones: '',
        _id: '',
    }

    const validationSchema = Yup.object().shape({
        presupuesto: Yup.string().required(
            'Código de presupuesto es requerido',
        ),
        monto: Yup.number()
            .required('Monto es requerido')
            .moreThan(0, 'El monto debe ser mayor que 0'),
        condicionPago: Yup.string().required('Condición de pago es requerida'),
        concepto: Yup.string().required('Concepto de pago es requerido'),
        fechaPago: Yup.date().required('Fecha de pago es requerida'),
        comprobante: Yup.string(),
        observaciones: Yup.string(),
    })

    const handlePagoCondicionChange = (newValue: string) => {
        const conceptoOptionsMap: { [key: string]: Option[] } = {
            Pago: [
                { value: 'Anticipo Parcial', label: 'Anticipo Parcial' },
                { value: 'Anticipo Completo', label: 'Anticipo Completo' },
                { value: 'Saldo Parcial', label: 'Saldo Parcial' },
                { value: 'Saldo Completo', label: 'Saldo Completo' },
            ],
            ND: [
                { value: 'Actualización', label: 'Actualización' },
                { value: 'Extra', label: 'Extra' },
                { value: 'Devolución Parcial', label: 'Devolución Parcial' },
                { value: 'Devolución Completa', label: 'Devolución Completa' },
            ],
            NC: [
                { value: 'Descuento Extra', label: 'Descuento Extra' },
                {
                    value: 'Retención de Impuestos',
                    label: 'Retención de Impuestos',
                },
            ],
        }

        const options = conceptoOptionsMap[newValue] || []

        setConceptOptions(options)
    }

    return (
        <Formik
            initialValues={initialValues}
            validationSchema={validationSchema}
            validateOnChange={false}
            validateOnBlur={false}
            onSubmit={async (
                values,
                { setSubmitting }: FormikHelpers<Pago>,
            ) => {
                setSubmitting(true)
                if (!clientByID) {
                    setMessage('Cliente no encontrado')
                    setSubmitting(false)
                    return
                }

                try {
                    const result = await apiCreatePago({
                        presupuesto: values.presupuesto,
                        fechaPago: values.fechaPago,
                        condicionPago: values.condicionPago,
                        concepto: values.concepto,
                        comprobante: values.comprobante,
                        monto: values.monto,
                        observaciones: values.observaciones,
                    })

                    if (result?.data) {
                        setMessage('Pago agregado exitosamente')
                        onSubmitPay()
                    } else {
                        setMessage('Error al agregar el pago')
                    }
                } catch (error: any) {
                    console.error('Error al crear pago:', error)
                    setMessage(error?.response?.data?.msg || 'Error al agregar el pago')
                }

                setSubmitting(false)
            }}
        >
            {({ values, setFieldValue, setFieldError, submitForm, errors, touched, submitCount }) => {
                submitRef.current = submitForm

                useEffect(() => {
                    setFieldValue('monto', pagoMontoInput.value)
                }, [pagoMontoInput.value, setFieldValue])

                return (
                    <Form>
                        <FormContainer>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                                <FormItem
                                    label="Cliente"
                                    invalid={false}
                                >
                                    <Input
                                        type="text"
                                        value={clientByID?.tipoCliente === 'Persona' 
                                            ? `${clientByID?.nombre} ${clientByID?.apellido}`
                                            : clientByID?.razonSocial || ''
                                        }
                                        disabled
                                    />
                                </FormItem>

                                <FormItem
                                    label={clientByID?.tipoCliente === 'Persona' ? "DNI" : "CUIT"}
                                    invalid={false}
                                >
                                    <Input
                                        type="text"
                                        value={clientByID?.tipoCliente === 'Persona' ? clientByID?.dni || '' : clientByID?.cuit || ''}
                                        disabled
                                    />
                                </FormItem>

                                
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2 mt-4">
                                <FormItem
                                    label="Código de Presupuesto"
                                    invalid={
                                        !!(
                                            errors.presupuesto &&
                                            touched.presupuesto
                                        )
                                    }
                                >
                                    <Field name="presupuesto">
                                        {({ field, form }: FieldProps) => {
                                            const presupuestoOptions =
                                                (clientByID?.Presupuestos || []).map(
                                                    (
                                                        presupuesto: Presupuesto,
                                                    ) => ({
                                                        value: presupuesto._id,
                                                        label: presupuesto.presupuestoCodigo,
                                                    }),
                                                ) || []

                                            const selectedPresupuesto =
                                                presupuestoOptions.find(
                                                    (option) =>
                                                        option.value ===
                                                        field.value,
                                                )

                                            return (
                                                <Select
                                                    {...field}
                                                    value={
                                                        selectedPresupuesto ||
                                                        null
                                                    }
                                                    options={presupuestoOptions}
                                                    placeholder="Seleccionar código"
                                                    onChange={(
                                                        newValue: {
                                                            value: string
                                                        } | null,
                                                    ) => {
                                                        form.setFieldValue(
                                                            'presupuesto',
                                                            newValue
                                                                ? newValue.value
                                                                : '',
                                                        )
                                                        if (form.errors.presupuesto) {
                                                            form.setFieldError('presupuesto', undefined)
                                                        }
                                                    }}
                                                    isClearable
                                                />
                                            )
                                        }}
                                    </Field>
                                </FormItem>

                                <FormItem
                                    label="Fecha del Pago"
                                    invalid={
                                        !!(
                                            errors.fechaPago &&
                                            touched.fechaPago
                                        )
                                    }
                                >
                                    <Field name="fechaPago">
                                        {({ field, form }: FieldProps) => (
                                            <Input
                                                {...field}
                                                type="date"
                                                placeholder="Fecha del Pago"
                                                onChange={(e) => {
                                                    form.handleChange(e)
                                                    if (form.errors.fechaPago) {
                                                        form.setFieldError('fechaPago', undefined)
                                                    }
                                                }}
                                            />
                                        )}
                                    </Field>
                                </FormItem>

                                <FormItem
                                    label="Monto del Pago"
                                    invalid={
                                        !!(
                                            errors.monto &&
                                            touched.monto
                                        )
                                    }
                                >
                                    <Input
                                        type="text"
                                        value={pagoMontoInput.formattedValue}
                                        onChange={(e) => {
                                            pagoMontoInput.handleChange(e.target.value)
                                            if (errors.monto) {
                                                setFieldError('monto', undefined)
                                            }
                                        }}
                                        placeholder="Monto del Pago"
                                    />
                                </FormItem>

                                
                            </div>

<div className="grid grid-cols-1 md:grid-cols-2 gap-2 mt-4">
                            <FormItem
                                    label="Condición de Pago"
                                    invalid={
                                        !!(
                                            errors.condicionPago &&
                                            touched.condicionPago
                                        )
                                    }
                                >
                                    <Field name="condicionPago">
                                        {({ field, form }: FieldProps) => {
                                            const condicionOptions = [
                                                {
                                                    value: 'Pago',
                                                    label: 'Pago',
                                                },
                                                {
                                                    value: 'NC',
                                                    label: 'Nota de Crédito',
                                                },
                                                {
                                                    value: 'ND',
                                                    label: 'Nota de Débito',
                                                },
                                            ]

                                            const selectedCondicion =
                                                condicionOptions.find(
                                                    (option) =>
                                                        option.value ===
                                                        field.value,
                                                )

                                            return (
                                                <Select
                                                    {...field}
                                                    value={
                                                        selectedCondicion ||
                                                        null
                                                    }
                                                    options={condicionOptions}
                                                    placeholder="Seleccionar condición de pago"
                                                    onChange={(
                                                        newValue: {
                                                            value: string
                                                        } | null,
                                                    ) => {
                                                        form.setFieldValue(
                                                            'condicionPago',
                                                            newValue
                                                                ? newValue.value
                                                                : '',
                                                        )
                                                        handlePagoCondicionChange(
                                                            newValue?.value ||
                                                                '',
                                                        )
                                                        if (form.errors.condicionPago) {
                                                            form.setFieldError('condicionPago', undefined)
                                                        }
                                                    }}
                                                    isClearable
                                                />
                                            )
                                        }}
                                    </Field>
                                </FormItem>

                                <FormItem
                                    label="Concepto de Pago"
                                    invalid={
                                        !!(
                                            errors.concepto &&
                                            touched.concepto
                                        )
                                    }
                                >
                                    <Field name="concepto">
                                        {({ field, form }: FieldProps) => {
                                            const selectedConcepto =
                                                conceptOptions.find(
                                                    (option) =>
                                                        option.value ===
                                                        field.value,
                                                )

                                            return (
                                                <Select
                                                    {...field}
                                                    value={
                                                        selectedConcepto || null
                                                    }
                                                    options={conceptOptions}
                                                    placeholder="Seleccionar concepto de pago"
                                                    onChange={(
                                                        newValue: {
                                                            value: string
                                                        } | null,
                                                    ) => {
                                                        form.setFieldValue(
                                                            'concepto',
                                                            newValue
                                                                ? newValue.value
                                                                : '',
                                                        )
                                                        if (form.errors.concepto) {
                                                            form.setFieldError('concepto', undefined)
                                                        }
                                                    }}
                                                    isClearable
                                                />
                                            )
                                        }}
                                    </Field>
                                </FormItem></div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-2 mt-4">
                                <FormItem
                                    label="Número de Comprobante"
                                    invalid={
                                        !!(
                                            errors.comprobante &&
                                            touched.comprobante
                                        )
                                    }
                                >
                                    <Field
                                        type="text"
                                        name="comprobante"
                                        component={Input}
                                        placeholder="Número de Comprobante"
                                    />
                                </FormItem>

                                <FormItem
                                    className="md:col-span-1"
                                    label="Nota / Observación"
                                    invalid={
                                        !!(
                                            errors.observaciones &&
                                            touched.observaciones
                                        )
                                    }
                                >
                                    <Field
                                        type="text"
                                        name="observaciones"
                                        component={Input}
                                        placeholder="Comentarios"
                                    />
                                </FormItem>
                            </div>
                                {submitCount > 0 && (
                                <div className={`mt-6 p-4 rounded-lg border ${
                                                        !(values.presupuesto && values.fechaPago && values.monto > 0 && values.condicionPago && values.concepto)
                                        ? 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800'
                                        : 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800'
                                }`}>
                                    <h6 className={`text-sm font-bold mb-3 flex items-center gap-2 ${
                                        !(values.presupuesto && values.fechaPago && values.monto > 0 && values.condicionPago && values.concepto)
                                            ? 'text-red-600 dark:text-red-400'
                                            : 'text-green-600 dark:text-green-400'
                                    }`}>
                                        {!(values.presupuesto && values.fechaPago && values.monto > 0 && values.condicionPago && values.concepto) ? (
                                            <>
                                                <HiExclamationCircle className="text-lg" />
                                                Faltan completar campos obligatorios:
                                            </>
                                        ) : (
                                            <>
                                                <HiCheckCircle className="text-lg" />
                                                Todos los campos están completos
                                            </>
                                        )}
                                    </h6>
                                    <div className="space-y-2 pl-1">
                                        <div className={`flex items-center gap-2 text-sm font-medium ${
                                            !values.presupuesto 
                                                ? 'text-red-500 dark:text-red-400'
                                                : 'text-gray-400 line-through'
                                        }`}>
                                            <span>• Seleccionar Código de Presupuesto</span>
                                        </div>
                                        <div className={`flex items-center gap-2 text-sm font-medium ${
                                            !values.monto || values.monto <= 0
                                                ? 'text-red-500 dark:text-red-400'
                                                : 'text-gray-400 line-through'
                                        }`}>
                                            <span>• Ingresar Monto del Pago</span>
                                        </div>
                                        <div className={`flex items-center gap-2 text-sm font-medium ${
                                            !values.condicionPago 
                                                ? 'text-red-500 dark:text-red-400'
                                                : 'text-gray-400 line-through'
                                        }`}>
                                            <span>• Seleccionar Condición de Pago</span>
                                        </div>
                                        <div className={`flex items-center gap-2 text-sm font-medium ${
                                            !values.concepto 
                                                ? 'text-red-500 dark:text-red-400'
                                                : 'text-gray-400 line-through'
                                        }`}>
                                            <span>• Seleccionar Concepto de Pago</span>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </FormContainer>
                    </Form>
                )
            }}
        </Formik>
    )
}

export default AddPagoForm

