import React, { useEffect, useState } from 'react'
import { HiCheckCircle, HiExclamationCircle } from 'react-icons/hi'
import { Formik, Field, Form, FieldProps, FormikHelpers } from 'formik'
import * as Yup from 'yup'
import { Input, Select } from '@/components/ui'
import { FormItem, FormContainer } from '@/components/ui'
import { apiCreatePresupuesto } from '@/services/PresupuestoService'
import { apiGetClientById } from '@/services/ClientService'
import { Client, Presupuesto } from '@/@types/clientInfo'
import formatCurrency from '@/utils/hooks/formatCurrency'
import useCurrencyInput from '@/utils/hooks/useCurrencyInput'

type Props = {
    selectedClientIndex: string
    onSubmitPay: () => void
    submitRef: React.MutableRefObject<() => void>
}

const AddPresupuestoForm: React.FC<Props> = ({
    selectedClientIndex,
    onSubmitPay,
    submitRef,
}) => {
    const [clientByID, setClientByID] = useState<Client | null>(null)
    const [message, setMessage] = useState('')

    const precioInput = useCurrencyInput(0)

    useEffect(() => {
        const loadClient = async () => {
            try {
                const resp: any = await apiGetClientById(selectedClientIndex)
                if (resp.data && resp.data.cliente) {
                    setClientByID(resp.data.cliente)
                } else if (resp.data) {
                    setClientByID(resp.data)
                }
            } catch (error) {
                console.error('Error al cargar los datos del cliente:', error)
            }
        }

        loadClient()
    }, [selectedClientIndex])

    const initialValues: Presupuesto = {
        condicionFacturacion: '',
        iva: 0,
        precio: 0,
        presupuestoCodigo: '',
        total: 0,
        pagos: [],
        estado: 'Pendiente',
        _id: '',
    }

    const validationSchema = Yup.object().shape({
        presupuestoCodigo: Yup.string().required(
            'Código de presupuesto es requerido',
        ),
        precio: Yup.number()
            .required('El precio del presupuesto es requerido')
            .moreThan(0, 'El precio debe ser mayor a 0'),
        condicionFacturacion: Yup.string().required(
            'Condición de facturación es requerida',
        ),
    })

    const calcularIVA = (precio: number, condicion: string): number => {
        let iva = 0
        switch (condicion) {
            case '100%':
                iva = precio * 0.21
                break
            case '65%':
                iva = precio * 0.1365
                break
            case '50%':
                iva = precio * 0.105
                break
            case '0%':
                iva = 0
                break
            default:
                iva = 0
        }
        return iva
    }

    const calcularTotal = (precio: number, iva: number): number => {
        return precio + iva
    }

    return (
        <Formik
            initialValues={initialValues}
            validationSchema={validationSchema}
            validateOnChange={false}
            validateOnBlur={false}
            onSubmit={async (
                values,
                { setSubmitting }: FormikHelpers<Presupuesto>,
            ) => {
                setSubmitting(true)
                if (!clientByID) {
                    setMessage('Cliente no encontrado')
                    setSubmitting(false)
                    return
                }

                try {
                    const payload = {
                        cliente: clientByID._id,
                        presupuestoCodigo: values.presupuestoCodigo,
                        precio: values.precio,
                        condicionFacturacion: values.condicionFacturacion,
                        iva: values.iva,
                        total: values.total,
                        estado: 'Pendiente',
                        items: [], 
                        observaciones: '',
                        fecha: new Date(),
                    }

                    const response = await apiCreatePresupuesto(payload)

                    if (response) {
                        setMessage('Presupuesto agregado exitosamente')
                        onSubmitPay()
                    }
                } catch (error) {
                    console.error('Error creating presupuesto:', error)
                    setMessage('Error al crear el presupuesto')
                } finally {
                    setSubmitting(false)
                }
            }}
        >
            {({ values, setFieldValue, setFieldError, errors, touched, submitForm, submitCount }) => {
                submitRef.current = submitForm

                const precioInput = useCurrencyInput(values.precio)

                useEffect(() => {
                    setFieldValue('precio', precioInput.value)
                }, [precioInput.value, setFieldValue])

                useEffect(() => {
                    const ivaCalculado = calcularIVA(
                        precioInput.value,
                        values.condicionFacturacion,
                    )
                    const totalCalculado = calcularTotal(
                        precioInput.value,
                        ivaCalculado,
                    )

                    setFieldValue('iva', ivaCalculado)
                    setFieldValue('total', totalCalculado)
                }, [
                    precioInput.value,
                    values.condicionFacturacion,
                    setFieldValue,
                ])

                return (
                    <Form>
                        <FormContainer>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                                <FormItem
                                    label="Cliente"
                                    invalid={false}
                                >
                                    <Input
                                        type="text"
                                        value={clientByID?.tipoCliente === 'Persona' 
                                            ? `${clientByID?.nombre} ${clientByID?.apellido}`
                                            : clientByID?.razonSocial || ''
                                        }
                                        disabled
                                    />
                                </FormItem>

                                <FormItem
                                    label={clientByID?.tipoCliente === 'Persona' ? "DNI" : "CUIT"}
                                    invalid={false}
                                >
                                    <Input
                                        type="text"
                                        value={clientByID?.tipoCliente === 'Persona' ? clientByID?.dni || '' : clientByID?.cuit || ''}
                                        disabled
                                    />
                                </FormItem>

                                
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 gap-2 mt-4">
                                <FormItem
                                    label="Código de Presupuesto"
                                    invalid={
                                        !!(
                                            errors.presupuestoCodigo &&
                                            touched.presupuestoCodigo
                                        )
                                    }
                                >
                                    <Field name="presupuestoCodigo">
                                        {({ field, form }: FieldProps) => (
                                            <Input
                                                {...field}
                                                type="text"
                                                placeholder="Código de Presupuesto"
                                                onChange={(e) => {
                                                    form.setFieldValue('presupuestoCodigo', e.target.value)
                                                    if (form.errors.presupuestoCodigo) {
                                                        form.setFieldError('presupuestoCodigo', undefined)
                                                    }
                                                }}
                                            />
                                        )}
                                    </Field>
                                </FormItem>

                                <FormItem
                                    label="Precio con Descuento"
                                    invalid={
                                        !!(errors.precio && touched.precio)
                                    }
                                >
                                    <Input
                                        type="text"
                                        value={precioInput.formattedValue}
                                        onChange={(e) => {
                                            precioInput.handleChange(e.target.value)
                                            if (errors.precio) {
                                                setFieldError('precio', undefined)
                                            }
                                        }}
                                        placeholder="Precio c/Descuento"
                                    />
                                </FormItem>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2 mt-4">
                                <FormItem
                                    label="Condición de Facturación"
                                    invalid={
                                        !!(
                                            errors.condicionFacturacion &&
                                            touched.condicionFacturacion
                                        )
                                    }
                                >
                                    <Field name="condicionFacturacion">
                                        {({ field, form }: FieldProps) => {
                                            const condicionOptions = [
                                                {
                                                    value: '100%',
                                                    label: '100% - (21%)',
                                                },
                                                {
                                                    value: '65%',
                                                    label: '65% - (13,65%)',
                                                },
                                                {
                                                    value: '50%',
                                                    label: '50% - (10,5%)',
                                                },
                                                {
                                                    value: '0%',
                                                    label: '0%',
                                                },
                                            ]

                                            const selectedCondicion =
                                                condicionOptions.find(
                                                    (option) =>
                                                        option.value ===
                                                        field.value,
                                                )

                                            return (
                                                <Select
                                                    {...field}
                                                    value={
                                                        selectedCondicion ||
                                                        null
                                                    }
                                                    options={condicionOptions}
                                                    placeholder="Seleccionar condición"
                                                    onChange={(
                                                        newValue: {
                                                            value: string
                                                        } | null,
                                                    ) => {
                                                        form.setFieldValue(
                                                            'condicionFacturacion',
                                                            newValue
                                                                ? newValue.value
                                                                : '',
                                                        )
                                                        if (form.errors.condicionFacturacion) {
                                                            form.setFieldError(
                                                                'condicionFacturacion',
                                                                undefined,
                                                            )
                                                        }
                                                    }}
                                                    isClearable
                                                />
                                            )
                                        }}
                                    </Field>
                                </FormItem>

                                <FormItem
                                    label="IVA"
                                    invalid={!!(errors.iva && touched.iva)}
                                >
                                    <Input
                                        type="text"
                                        value={formatCurrency(values.iva)}
                                        disabled
                                    />
                                </FormItem>

                                <FormItem
                                    label="Total"
                                    invalid={!!(errors.total && touched.total)}
                                >
                                    <Input
                                        type="text"
                                        value={formatCurrency(values.total)}
                                        disabled
                                    />
                                </FormItem>
                            </div>

                            {submitCount > 0 && (
                                <div className={`mt-6 p-4 rounded-lg border ${
                                    !(values.presupuestoCodigo && values.precio > 0 && values.condicionFacturacion)
                                        ? 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800'
                                        : 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800'
                                }`}>
                                    <h6 className={`text-sm font-bold mb-3 flex items-center gap-2 ${
                                        !(values.presupuestoCodigo && values.precio > 0 && values.condicionFacturacion)
                                            ? 'text-red-600 dark:text-red-400'
                                            : 'text-green-600 dark:text-green-400'
                                    }`}>
                                        {!(values.presupuestoCodigo && values.precio > 0 && values.condicionFacturacion) ? (
                                            <>
                                                <HiExclamationCircle className="text-lg" />
                                                Faltan completar campos obligatorios:
                                            </>
                                        ) : (
                                            <>
                                                <HiCheckCircle className="text-lg" />
                                                Todos los campos están completos
                                            </>
                                        )}
                                    </h6>
                                    <div className="space-y-2 pl-1">
                                        <div className={`flex items-center gap-2 text-sm font-medium ${
                                            !values.presupuestoCodigo
                                                ? 'text-red-500 dark:text-red-400'
                                                : 'text-gray-400 line-through'
                                        }`}>
                                            <span>• Ingresar Código de Presupuesto</span>
                                        </div>
                                        <div className={`flex items-center gap-2 text-sm font-medium ${
                                            !values.precio || values.precio <= 0
                                                ? 'text-red-500 dark:text-red-400'
                                                : 'text-gray-400 line-through'
                                        }`}>
                                            <span>• Definir Precio del Presupuesto</span>
                                        </div>
                                        <div className={`flex items-center gap-2 text-sm font-medium ${
                                            !values.condicionFacturacion
                                                ? 'text-red-500 dark:text-red-400'
                                                : 'text-gray-400 line-through'
                                        }`}>
                                            <span>• Seleccionar Condición de Facturación</span>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </FormContainer>
                    </Form>
                )
            }}
        </Formik>
    )
}

export default AddPresupuestoForm

import React, { useState } from 'react'
import { Formik, Field, Form, FormikHelpers, FieldProps } from 'formik'
import * as Yup from 'yup'
import { Input, Select, Segment } from '@/components/ui'
import { FormItem, FormContainer } from '@/components/ui'
import { apiUpdateClient } from '@/services/ClientService'
import { Client } from '@/@types/clientInfo'
import { HiOutlineUser, HiOutlineLibrary, HiCheckCircle, HiExclamationCircle } from 'react-icons/hi'

type Props = {
    onSubmitClient: () => void
    submitRef: React.MutableRefObject<() => void>
    clientData: Client
    clientId: string
}

const EditClientForm: React.FC<Props> = ({
    onSubmitClient,
    submitRef,
    clientData,
    clientId,
}) => {
    const [message, setMessage] = useState('')

    const initialValues = {
        tipoCliente: clientData?.tipoCliente || 'Persona',
        nombre: clientData?.nombre || '',
        apellido: clientData?.apellido || '',
        dni: clientData?.dni || '',
        razonSocial: clientData?.razonSocial || '',
        cuit: clientData?.cuit || '',
        email: clientData?.email || '',
        telefono: clientData?.telefono || '',
        celular: clientData?.celular || '',
        direccion: {
            calle: clientData?.direccion?.calle || '',
            numero: clientData?.direccion?.numero || '',
            piso: clientData?.direccion?.piso || '',
            departamento: clientData?.direccion?.departamento || '',
            ciudad: clientData?.direccion?.ciudad || '',
            provincia: clientData?.direccion?.provincia || '',
            codigoPostal: clientData?.direccion?.codigoPostal || '',
        },
        observaciones: clientData?.observaciones || '',
        estado: clientData?.estado || 'Activo',
    }

    const validationSchema = Yup.object().shape({
        tipoCliente: Yup.string().required('El tipo de cliente es requerido'),
        nombre: Yup.string().when('tipoCliente', {
            is: 'Persona',
            then: (schema) => schema.required('El nombre es requerido'),
            otherwise: (schema) => schema.nullable(),
        }),
        apellido: Yup.string().when('tipoCliente', {
            is: 'Persona',
            then: (schema) => schema.required('El apellido es requerido'),
            otherwise: (schema) => schema.nullable(),
        }),
        dni: Yup.string().when('tipoCliente', {
            is: 'Persona',
            then: (schema) => schema.required('El DNI es requerido'),
            otherwise: (schema) => schema.nullable(),
        }),
        razonSocial: Yup.string().when('tipoCliente', {
            is: 'Empresa',
            then: (schema) => schema.required('La razón social es requerida'),
            otherwise: (schema) => schema.nullable(),
        }),
        cuit: Yup.string().when('tipoCliente', {
            is: 'Empresa',
            then: (schema) => schema.required('El CUIT es requerido'),
            otherwise: (schema) => schema.nullable(),
        }),
        email: Yup.string().email('Email inválido'),
    })

    const handleCUITChange = (
        e: React.ChangeEvent<HTMLInputElement>,
        setFieldValue: (field: string, value: any) => void,
    ) => {
        const inputNumber = e.target.value.replace(/\D/g, '').substring(0, 11)
        let formattedCuit = inputNumber
        if (inputNumber.length > 2) {
            formattedCuit = `${inputNumber.substring(0, 2)}-${inputNumber.substring(2, 10)}`
            if (inputNumber.length > 10) {
                formattedCuit = `${formattedCuit}-${inputNumber.charAt(10)}`
            }
        }
        setFieldValue('cuit', formattedCuit)
    }

    const updateClient = async (values: any) => {
        try {
            const response: any = await apiUpdateClient(clientId, values)
            if (response?.data?.ok || response?.data?.cliente) {
                setMessage('Cliente editado exitosamente')
                onSubmitClient()
            } else {
                setMessage(response?.data?.msg || 'Error al editar el cliente')
            }
        } catch (error: any) {
            setMessage(error.response?.data?.msg || error.message || 'Error al editar el cliente')
        }
    }

    return (
        <Formik
            initialValues={initialValues}
            validationSchema={validationSchema}
            enableReinitialize={true}
            validateOnChange={true}
            validateOnBlur={true}
            onSubmit={async (values, { setSubmitting }: FormikHelpers<any>) => {
                setSubmitting(true)
                await updateClient(values)
                setSubmitting(false)
            }}
        >
            {({ submitForm, errors, touched, setFieldValue, values, submitCount }) => {
                submitRef.current = submitForm

                return (
                    <Form>
                        <FormContainer >
                             <div className="mb-3 flex justify-center">
                                <Segment 
                                    value={[values.tipoCliente]} 
                                    onChange={(val) => setFieldValue('tipoCliente', val[0])}
                                >
                                    <Segment.Item value="Persona" type="button">
                                        <div className="flex items-center gap-2 px-2 py-1">
                                            <HiOutlineUser />
                                            <span>Persona</span>
                                        </div>
                                    </Segment.Item>
                                    <Segment.Item value="Empresa" type="button">
                                        <div className="flex items-center gap-2 px-2 py-1">
                                            <HiOutlineLibrary />
                                            <span>Empresa</span>
                                        </div>
                                    </Segment.Item>
                                </Segment>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2">
                                {values.tipoCliente === 'Persona' ? (
                                    <>
                                        <FormItem
                                            label="Nombre"
                                            invalid={!!(errors.nombre && touched.nombre)}
                                            errorMessage={errors.nombre as string}
                                        >
                                            <Field name="nombre" component={Input} placeholder="Nombre" />
                                        </FormItem>
                                        <FormItem
                                            label="Apellido"
                                            invalid={!!(errors.apellido && touched.apellido)}
                                            errorMessage={errors.apellido as string}
                                        >
                                            <Field name="apellido" component={Input} placeholder="Apellido" />
                                        </FormItem>
                                        <FormItem
                                            label="DNI"
                                            invalid={!!(errors.dni && touched.dni)}
                                            errorMessage={errors.dni as string}
                                        >
                                            <Field name="dni" component={Input} placeholder="DNI" />
                                        </FormItem>
                                    </>
                                ) : (
                                    <>
                                        <FormItem
                                            label="Razón Social"
                                            invalid={!!(errors.razonSocial && touched.razonSocial)}
                                            errorMessage={errors.razonSocial as string}
                                            className="md:col-span-2"
                                        >
                                            <Field name="razonSocial" component={Input} placeholder="Razón Social" />
                                        </FormItem>
                                        <FormItem
                                            label="CUIT"
                                            invalid={!!(errors.cuit && touched.cuit)}
                                            errorMessage={errors.cuit as string}
                                        >
                                            <Field name="cuit">
                                                {({ field, form }: FieldProps) => (
                                                    <Input
                                                        {...field}
                                                        placeholder="XX-XXXXXXXX-X"
                                                        onChange={(e) => handleCUITChange(e, form.setFieldValue)}
                                                    />
                                                )}
                                            </Field>
                                        </FormItem>
                                    </>
                                )}
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2 border-t border-gray-100 dark:border-gray-700 mt-2">
                                <FormItem label="Email" invalid={!!(errors.email && touched.email)} errorMessage={errors.email as string}>
                                    <Field name="email" component={Input} placeholder="example@mail.com" />
                                </FormItem>
                                <FormItem label="Teléfono">
                                    <Field name="telefono" component={Input} placeholder="Teléfono fijo" />
                                </FormItem>
                                <FormItem label="Celular">
                                    <Field name="celular" component={Input} placeholder="Celular" />
                                </FormItem>
                            </div>

                            <h6 className="text-xs font-bold text-gray-400 uppercase tracking-widest mt-4">Dirección</h6>
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-2">
                                <FormItem label="Calle" className="lg:col-span-2">
                                    <Field name="direccion.calle" component={Input} placeholder="Calle" />
                                </FormItem>
                                <FormItem label="Número">
                                    <Field name="direccion.numero" component={Input} placeholder="123" />
                                </FormItem>
                                <FormItem label="Piso / Depto">
                                    <div className="flex gap-2">
                                        <Field name="direccion.piso" component={Input} placeholder="Piso" className="w-1/2" />
                                        <Field name="direccion.departamento" component={Input} placeholder="A" className="w-1/2" />
                                    </div>
                                </FormItem>
                                <FormItem label="Ciudad">
                                    <Field name="direccion.ciudad" component={Input} placeholder="Ciudad" />
                                </FormItem>
                                <FormItem label="Provincia">
                                    <Field name="direccion.provincia" component={Input} placeholder="Provincia" />
                                </FormItem>
                                <FormItem label="Código Postal">
                                    <Field name="direccion.codigoPostal" component={Input} placeholder="CP" />
                                </FormItem>
                                <FormItem label="Estado">
                                    <Field name="estado">
                                        {({ field, form }: FieldProps) => (
                                            <Select
                                                {...field}
                                                options={[
                                                    { value: 'Activo', label: 'Activo' },
                                                    { value: 'Cerrado', label: 'Cerrado' },
                                                    { value: 'Deudor', label: 'Deudor' },
                                                ]}
                                                value={[{ value: 'Activo', label: 'Activo' }, { value: 'Cerrado', label: 'Cerrado' }, { value: 'Deudor', label: 'Deudor' }].find(option => option.value === values.estado)}
                                                onChange={(option: any) => form.setFieldValue(field.name, option.value)}
                                            />
                                        )}
                                    </Field>
                                </FormItem>
                            </div>

                            <FormItem label="Observaciones" className="my-2">
                                <Field name="observaciones">
                                    {({ field }: FieldProps) => (
                                        <Input {...field} textArea placeholder="Notas adicionales..." />
                                    )}
                                </Field>
                            </FormItem>
                        </FormContainer>

                        {submitCount > 0 && (
                            <div className={`mt-6 p-4 rounded-lg border ${
                                !(values.tipoCliente === 'Persona' ? (values.nombre && values.apellido && values.dni) : (values.razonSocial && values.cuit))
                                    ? 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800'
                                    : 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800'
                            }`}>
                                <h6 className={`text-sm font-bold mb-3 flex items-center gap-2 ${
                                    !(values.tipoCliente === 'Persona' ? (values.nombre && values.apellido && values.dni) : (values.razonSocial && values.cuit))
                                        ? 'text-red-600 dark:text-red-400'
                                        : 'text-green-600 dark:text-green-400'
                                }`}>
                                    {!(values.tipoCliente === 'Persona' ? (values.nombre && values.apellido && values.dni) : (values.razonSocial && values.cuit)) ? (
                                        <>
                                            <HiExclamationCircle className="text-lg" />
                                            Faltan completar campos obligatorios:
                                        </>
                                    ) : (
                                        <>
                                            <HiCheckCircle className="text-lg" />
                                            Todos los campos están completos
                                        </>
                                    )}
                                </h6>
                                <div className="space-y-2 pl-1">
                                    {values.tipoCliente === 'Persona' ? (
                                        <>
                                            <div className={`flex items-center gap-2 text-sm font-medium ${!values.nombre ? 'text-red-500 dark:text-red-400' : 'text-gray-400 line-through'}`}>
                                                <span>• Ingresar Nombre</span>
                                            </div>
                                            <div className={`flex items-center gap-2 text-sm font-medium ${!values.apellido ? 'text-red-500 dark:text-red-400' : 'text-gray-400 line-through'}`}>
                                                <span>• Ingresar Apellido</span>
                                            </div>
                                            <div className={`flex items-center gap-2 text-sm font-medium ${!values.dni ? 'text-red-500 dark:text-red-400' : 'text-gray-400 line-through'}`}>
                                                <span>• Ingresar DNI</span>
                                            </div>
                                        </>
                                    ) : (
                                        <>
                                            <div className={`flex items-center gap-2 text-sm font-medium ${!values.razonSocial ? 'text-red-500 dark:text-red-400' : 'text-gray-400 line-through'}`}>
                                                <span>• Ingresar Razón Social</span>
                                            </div>
                                            <div className={`flex items-center gap-2 text-sm font-medium ${!values.cuit ? 'text-red-500 dark:text-red-400' : 'text-gray-400 line-through'}`}>
                                                <span>• Ingresar CUIT</span>
                                            </div>
                                        </>
                                    )}
                                </div>
                            </div>
                        )}

                        {message && (
                            <div className={`mt-4 p-3 rounded-lg text-center font-medium ${
                                message.includes('exitosamente') 
                                ? 'bg-emerald-50 text-emerald-600 dark:bg-emerald-900/20 dark:text-emerald-400' 
                                : 'bg-rose-50 text-rose-600 dark:bg-rose-900/20 dark:text-rose-400'
                            }`}>
                                {message}
                            </div>
                        )}
                    </Form>
                )
            }}
        </Formik>
    )
}

export default EditClientForm

