import React from 'react'
import { Drawer, Card, Tag } from '@/components/ui'
import {
    HiOutlineTruck,
    HiOutlineClipboardList,
    HiOutlineCalendar,
    HiOutlineCube,
} from 'react-icons/hi'
import classNames from 'classnames'
import { Pedido, ItemPedido } from '@/@types/pedidos'

type PedidoDetailPanelProps = {
    pedido: Pedido | null
    isOpen: boolean
    onClose: () => void
}

const getStatusColor = (status: string) => {
    switch (status?.toUpperCase()) {
        case 'RECIBIDO':
            return 'bg-emerald-100 text-emerald-700'
        case 'PENDIENTE':
            return 'bg-amber-100 text-amber-700'
        case 'EN_TRANSITO':
            return 'bg-blue-100 text-blue-700'
        case 'CANCELADO':
            return 'bg-red-100 text-red-700'
        default:
            return 'bg-gray-100 text-gray-700'
    }
}

const getCategoryIcon = (categoria: string) => {
    switch (categoria?.toLowerCase()) {
        case 'herrajes':
            return (
                <HiOutlineClipboardList className="text-orange-500 text-xl" />
            )
        case 'perfiles':
            return <HiOutlineTruck className="text-blue-500 text-xl" />
        case 'vidrios':
            return <HiOutlineClipboardList className="text-cyan-500 text-xl" />
        case 'obra gruesa':
            return <HiOutlineTruck className="text-gray-600 text-xl" />
        case 'instalaciones':
            return <HiOutlineClipboardList className="text-green-500 text-xl" />
        case 'aberturas':
            return (
                <HiOutlineClipboardList className="text-purple-500 text-xl" />
            )
        case 'terminaciones':
            return <HiOutlineClipboardList className="text-pink-500 text-xl" />
        case 'herramientas':
            return <HiOutlineClipboardList className="text-red-500 text-xl" />
        default:
            return <HiOutlineClipboardList className="text-gray-500 text-xl" />
    }
}

const PedidoDetailPanel: React.FC<PedidoDetailPanelProps> = ({
    pedido,
    isOpen,
    onClose,
}) => {
    if (!pedido) return null

    const formatDate = (dateString: string | Date) => {
        return new Date(dateString).toLocaleDateString('es-ES', {
            day: '2-digit',
            month: '2-digit',
            year: 'numeric',
        })
    }

    return (
        <Drawer
            title={
                <div className="flex items-center gap-3">
                    {getCategoryIcon(pedido.categoria)}
                    <div>
                        <h3 className="text-lg font-bold text-gray-900">
                            Pedido {pedido.numeroPedido}
                        </h3>
                        <p className="text-sm text-gray-500 capitalize">
                            {pedido.categoria}
                        </p>
                    </div>
                </div>
            }
            isOpen={isOpen}
            onClose={onClose}
            onRequestClose={onClose}
            width={800}
        >
            <div className="space-y-6">
                {/* Header Stats */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <Card className="p-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-blue-100 rounded-lg">
                                <HiOutlineClipboardList className="text-blue-600 text-xl" />
                            </div>
                            <div>
                                <p className="text-sm text-gray-600">Estado</p>
                                <Tag
                                    className={classNames(
                                        getStatusColor(pedido.estado),
                                        'border-0 mt-1',
                                    )}
                                >
                                    {pedido.estado
                                        ?.replace('_', ' ')
                                        .toLowerCase()}
                                </Tag>
                            </div>
                        </div>
                    </Card>

                    <Card className="p-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-green-100 rounded-lg">
                                <HiOutlineCalendar className="text-green-600 text-xl" />
                            </div>
                            <div>
                                <p className="text-sm text-gray-600">
                                    Fecha Pedido
                                </p>
                                <p className="font-semibold text-gray-900">
                                    {formatDate(pedido.fechaPedido)}
                                </p>
                            </div>
                        </div>
                    </Card>

                    <Card className="p-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-purple-100 rounded-lg">
                                <HiOutlineCube className="text-purple-600 text-xl" />
                            </div>
                            <div>
                                <p className="text-sm text-gray-600">Items</p>
                                <p className="font-semibold text-gray-900">
                                    {pedido.items?.length || 0} items
                                </p>
                            </div>
                        </div>
                    </Card>
                </div>

                {/* Project Info */}
                {pedido.proyecto && (
                    <Card className="p-4">
                        <h4 className="font-semibold text-gray-900 mb-2">
                            Proyecto Asociado
                        </h4>
                        <div className="flex items-center gap-2">
                            <HiOutlineCube className="text-amber-500" />
                            <span className="font-medium text-gray-700">
                                {typeof pedido.proyecto === 'object'
                                    ? pedido.proyecto.nombre
                                    : 'Proyecto asociado'}
                            </span>
                        </div>
                        {pedido.subcategoria && (
                            <div className="mt-2">
                                <p className="text-sm text-gray-600">
                                    Subcategoría:{' '}
                                    <span className="font-medium">
                                        {pedido.subcategoria}
                                    </span>
                                </p>
                            </div>
                        )}
                    </Card>
                )}

                {/* Materials List */}
                <Card className="p-4">
                    <h4 className="font-semibold text-gray-900 mb-4">
                        Lista de Items
                    </h4>
                    <div className="space-y-3">
                        {(pedido.items || []).map(
                            (item: ItemPedido, index: number) => (
                                <div
                                    key={index}
                                    className="border border-gray-200 rounded-lg p-3"
                                >
                                    <div className="flex justify-between items-start mb-2">
                                        <div className="flex-1">
                                            <h5 className="font-medium text-gray-900">
                                                {item.descripcion ||
                                                    'Sin descripción'}
                                            </h5>
                                            {item.codigo && (
                                                <p className="text-sm text-gray-500">
                                                    Código: {item.codigo}
                                                </p>
                                            )}
                                            {item.categoria && (
                                                <p className="text-sm text-gray-500">
                                                    Categoría: {item.categoria}
                                                </p>
                                            )}
                                        </div>
                                        <div className="text-right">
                                            <p className="font-semibold text-gray-900">
                                                {item.cantidad || 0}{' '}
                                                {item.unidad || 'unidades'}
                                            </p>
                                            {item.precioUnitario && (
                                                <p className="text-sm text-gray-500">
                                                    ${item.precioUnitario} c/u
                                                </p>
                                            )}
                                            {item.subtotal && (
                                                <p className="text-sm font-medium text-gray-700">
                                                    Subtotal: ${item.subtotal}
                                                </p>
                                            )}
                                        </div>
                                    </div>

                                    {item.observaciones && (
                                        <div className="mt-2 pt-2 border-t border-gray-100">
                                            <p className="text-xs text-gray-600">
                                                <span className="font-medium">
                                                    Observaciones:
                                                </span>{' '}
                                                {item.observaciones}
                                            </p>
                                        </div>
                                    )}
                                </div>
                            ),
                        )}

                        {(!pedido.items || pedido.items.length === 0) && (
                            <div className="text-center py-4 text-gray-400 italic">
                                No hay items en este pedido
                            </div>
                        )}
                    </div>
                </Card>

                {/* Additional Info */}
                {(pedido.observaciones ||
                    pedido.proveedor ||
                    pedido.totales) && (
                    <Card className="p-4">
                        <h4 className="font-semibold text-gray-900 mb-4">
                            Información Adicional
                        </h4>

                        {pedido.totales && (
                            <div className="mb-4">
                                <h5 className="font-medium text-gray-700 mb-2">
                                    Totales
                                </h5>
                                <div className="text-sm text-gray-600 space-y-1">
                                    {pedido.totales.subtotal && (
                                        <p>
                                            Subtotal:{' '}
                                            <span className="font-medium">
                                                ${pedido.totales.subtotal}{' '}
                                                {pedido.totales.moneda || ''}
                                            </span>
                                        </p>
                                    )}
                                    {pedido.totales.impuestos && (
                                        <p>
                                            Impuestos:{' '}
                                            <span className="font-medium">
                                                ${pedido.totales.impuestos}{' '}
                                                {pedido.totales.moneda || ''}
                                            </span>
                                        </p>
                                    )}
                                    {pedido.totales.total && (
                                        <p className="font-semibold text-gray-900">
                                            Total: ${pedido.totales.total}{' '}
                                            {pedido.totales.moneda || ''}
                                        </p>
                                    )}
                                </div>
                            </div>
                        )}

                        {pedido.proveedor && (
                            <div className="mb-4">
                                <h5 className="font-medium text-gray-700 mb-2">
                                    Proveedor
                                </h5>
                                <div className="text-sm text-gray-600">
                                    {pedido.proveedor.nombre && (
                                        <p>Nombre: {pedido.proveedor.nombre}</p>
                                    )}
                                    {pedido.proveedor.contacto && (
                                        <p>
                                            Contacto:{' '}
                                            {pedido.proveedor.contacto}
                                        </p>
                                    )}
                                    {pedido.proveedor.telefono && (
                                        <p>
                                            Teléfono:{' '}
                                            {pedido.proveedor.telefono}
                                        </p>
                                    )}
                                    {pedido.proveedor.email && (
                                        <p>Email: {pedido.proveedor.email}</p>
                                    )}
                                </div>
                            </div>
                        )}

                        {pedido.observaciones && (
                            <div>
                                <h5 className="font-medium text-gray-700 mb-2">
                                    Observaciones
                                </h5>
                                <p className="text-sm text-gray-600">
                                    {pedido.observaciones}
                                </p>
                            </div>
                        )}
                    </Card>
                )}
            </div>
        </Drawer>
    )
}

export default PedidoDetailPanel

