import React, { useEffect, useState } from 'react'
import { apiGetClients } from '@/services/ClientService'
import { Client } from '@/@types/clientInfo'
import { Table } from '@/components/ui'
import THead from '@/components/ui/Table/THead'
import Th from '@/components/ui/Table/Th'
import TBody from '@/components/ui/Table/TBody'
import Td from '@/components/ui/Table/Td'
import { calculateTotalDebt } from '@/utils/hooks/calculateClientDebt'
import DividerMain from '../../DividerMain'
import formatCurrency from '@/utils/hooks/formatCurrency'
import { useAppSelector } from '@/store/hook'

const ClientsList: React.FC = () => {
    const [clientes, setClientes] = useState<Client[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState('')
    const { currentBusinessUnit } = useAppSelector(
        (state) => state.businessUnit.data,
    )
    const userAuthority = useAppSelector((state) => state.auth.user.authority)

    useEffect(() => {
        const getClientes = async () => {
            if (!currentBusinessUnit?._id) return

            try {
                const resp: any = await apiGetClients({ 
                    unidadNegocio: currentBusinessUnit._id,
                    activo: true 
                })
                
                if (resp.data && resp.data.clientes) {
                    setClientes(resp.data.clientes)
                }
            } catch (err) {
                setError('Error al obtener los clientes activos')
            } finally {
                setLoading(false)
            }
        }

        getClientes()
    }, [currentBusinessUnit?._id])

    if (!userAuthority?.includes('Admin'))
        return (
            <p>
                No tienes los permisos necesarios para acceder a esta
                información.
            </p>
        )
    if (loading) return <p>Cargando clientes...</p>
    if (error) return <p>{error}</p>
    if (clientes.length === 0) return <p>No hay clientes activos.</p>

    return (
        <div>
            <div>
                <div className="flex justify-between align-center">
                    <h5 style={{ color: '#01662b' }}>Clientes activos</h5>
                    <div className="pt-1 text-right ">
                        Total general:
                        {formatCurrency(
                            parseInt(
                                clientes
                                    .reduce(
                                        (acc, cliente) =>
                                            acc +
                                            calculateTotalDebt(
                                                cliente.Presupuestos || [],
                                            ),
                                        0,
                                    )
                                    .toFixed(2),
                            ),
                        )}
                    </div>
                </div>
                <DividerMain />
            </div>

            <Table>
                <THead>
                    <Th className="text-left pl-12" style={{ width: '50%' }}>
                        Cliente
                    </Th>
                    <Th className="text-right pr-12" style={{ width: '50%' }}>
                        Saldo
                    </Th>
                </THead>
            </Table>
            <div className="table-body-container">
                <Table>
                    <TBody>
                        {clientes.map((cliente) => {
                            const totalDebt = calculateTotalDebt(
                                cliente.Presupuestos || [],
                            )
                            return (
                                <tr key={cliente._id}>
                                    <Td
                                        className="text-left"
                                        style={{ width: '50%' }}
                                    >
                                        {cliente.tipoCliente === 'Persona'
                                            ? `${cliente.apellido || ''}, ${cliente.nombre || ''}`
                                            : cliente.razonSocial}
                                    </Td>
                                    <Td
                                        className="text-right"
                                        style={{ width: '50%' }}
                                    >
                                        {formatCurrency(
                                            parseInt(totalDebt.toFixed(2)),
                                        )}
                                    </Td>
                                </tr>
                            )
                        })}
                    </TBody>
                </Table>
            </div>
        </div>
    )
}

export default ClientsList

import Card from '@/components/ui/Card'
import Avatar from '@/components/ui/Avatar'
import { HiOutlineUser, HiOutlineLibrary, HiOutlineAcademicCap } from 'react-icons/hi'
import { Client } from '@/@types/clientInfo'
import { useMemo } from 'react'
import formatCurrency from '@/utils/hooks/formatCurrency'

const SalesSideCard = ({ clients }: { clients: Client[] }) => {
    
    const stats = useMemo(() => {
        const sortedClients = (clients || [])
            .map(c => {
                const total = (c.Presupuestos || []).reduce((sum, p) => sum + (p.total || 0), 0)
                const budgetCount = (c.Presupuestos || []).length
                return { ...c, totalRevenue: total, budgetCount }
            })
            .sort((a, b) => b.totalRevenue - a.totalRevenue)
            .slice(0, 3)

        const totalOverallRevenue = (clients || [])
            .flatMap(c => c.Presupuestos || [])
            .filter(p => p.estado === 'Aprobado')
            .reduce((sum, p) => sum + (p.total || 0), 0)

        return { topClients: sortedClients, totalOverallRevenue }
    }, [clients])

    return (
        <Card className="rounded-2xl border-none shadow-sm overflow-hidden p-0 h-full flex flex-col bg-white dark:bg-gray-800">
            <div className="bg-indigo-600 p-8 relative overflow-hidden h-[180px] flex flex-col justify-between">
                <div className="flex justify-between items-start z-10">
                    <div>
                        <h3 className="text-3xl font-bold text-white">
                            {formatCurrency(stats.totalOverallRevenue)}
                        </h3>
                        <p className="text-sm text-indigo-100 font-medium">Ventas Totales</p>
                    </div>
                </div>
                
                {/* Wave SVG */}
                <div className="absolute bottom-0 left-0 w-full leading-[0]">
                    <svg viewBox="0 0 500 150" preserveAspectRatio="none" className="h-[80px] w-full">
                        <path 
                            d="M0.00,49.98 C149.99,150.00 349.89,-49.98 500.00,49.98 L500.00,150.00 L0.00,150.00 Z" 
                            style={{ stroke: 'none', fill: 'rgba(255,255,255,0.1)' }}
                        ></path>
                    </svg>
                </div>
            </div>

            <div className="flex-1 p-6 flex flex-col gap-6">
                <h6 className="section-title text-[10px] uppercase tracking-widest font-bold">Principales Clientes</h6>
                
                {stats.topClients.map((client, index) => {
                    const colors = ['bg-blue-50 text-blue-600', 'bg-emerald-50 text-emerald-600', 'bg-amber-50 text-amber-600']
                    const name = client.tipoCliente === 'Persona' 
                        ? `${client.nombre} ${client.apellido}`
                        : client.razonSocial

                    return (
                        <div key={client._id} className="flex items-center justify-between">
                            <div className="flex items-center gap-4">
                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${colors[index % colors.length]}`}>
                                    {client.tipoCliente === 'Persona' ? <HiOutlineUser /> : <HiOutlineLibrary />}
                                </div>
                                <div>
                                    <h6 className="text-sm font-bold text-gray-900 dark:text-gray-100 truncate max-w-[120px]">
                                        {name}
                                    </h6>
                                    <p className="text-xs text-gray-400">
                                        {client.tipoCliente}
                                    </p>
                                </div>
                            </div>
                            <div className="text-right">
                                <div className="text-sm font-bold text-gray-900 dark:text-gray-100">
                                    {formatCurrency(client.totalRevenue)}
                                </div>
                                <div className="text-[10px] text-gray-400 font-medium">
                                    {client.budgetCount} Presupuestos
                                </div>
                            </div>
                        </div>
                    )
                })}

                {stats.topClients.length === 0 && (
                    <p className="text-center text-gray-400 text-sm py-4 italic">No hay datos suficientes</p>
                )}
                
                <div className="mt-auto pt-4">
                    <button className="w-full py-2 text-center text-xs font-bold text-gray-400 hover:text-gray-900 dark:hover:text-gray-100 uppercase tracking-widest transition-colors">
                        Ver Todos los Detalles
                    </button>
                </div>
            </div>
        </Card>
    )
}

