                                >
                                    <Input
                                        name="Comentario"
                                        value={values.Comentario}
                                        onChange={handleChange}
                                    />
                                </FormItem>
                            </div>

                            <div className="flex justify-end mt-4">
                                <Button type="submit" variant="solid">
                                    Registrar Movimiento
                                </Button>
                            </div>
                        </FormContainer>
                    </Form>
                )
            }}
        </Formik>
    )
}

