import React, { useState } from 'react'
import { Formik, Form } from 'formik'
import { Input, Button } from '@/components/ui'
import { FormItem, FormContainer } from '@/components/ui'
import UploadHerrajes from '../UploadHerrajes'
import { Table } from '@/components/ui'
import THead from '@/components/ui/Table/THead'
import Th from '@/components/ui/Table/Th'
import TBody from '@/components/ui/Table/TBody'
import Td from '@/components/ui/Table/Td'
import { createPedidoHerrajes } from '@/api/api'
import getCurrentDate from '@/utils/hooks/getCurrentDate'
import { showConfirmation, showSuccess, showError } from '@/utils/hooks/alerts'
import '../../pedidosViewStyles.css'
import formatNumber from '@/utils/hooks/formatNumber'

type UploadedMaterial = {
    Codigo: string
    Descripcion: string
    CantEntrega: number
    Unidad: string
    Recepciones: any[]
}

type PedidoHerrajesFormProps = {
    onClose: () => void
    onSubmit: () => void
}

const PedidoHerrajesForm: React.FC<PedidoHerrajesFormProps> = ({
    onClose,
    onSubmit,
}) => {
    const Today = getCurrentDate()
    const [uploadedData, setUploadedData] = useState<UploadedMaterial[]>([])
    const [NroPedido, setNroPedido] = useState('')
    const [Obra, setObra] = useState('')
    const [Fecha, setFecha] = useState(Today)
    const [OrdenCompra, setOrdenCompra] = useState('')
    const [Estado, setEstado] = useState('Abierto')

    const handleFileUpload = async (
        jsonData: (string | number | undefined | null)[][],
    ) => {
        const dataToUpload: UploadedMaterial[] = jsonData
            .filter((row) =>
                row.every(
                    (cell: string | number | undefined | null) =>
                        cell !== undefined && cell !== null && cell !== '',
                ),
            )
            .map(([Codigo, Descripcion, CantEntrega, Unidad]) => ({
                Codigo: String(Codigo),
                Descripcion: String(Descripcion),
                CantEntrega: Number(CantEntrega),
                Unidad: 'u.',
                Recepciones: [],
            }))

        setUploadedData(dataToUpload)
    }

    const handleConfirmSubmit = (submit: () => void) => {
        showConfirmation(
            '¿Estás seguro?',
            '¿Deseas registrar este pedido?',
        ).then((result) => {
            if (result.isConfirmed) {
                submit()
            }
        })
    }

    const handleSuccess = () => {
        showSuccess(
            'Pedido registrado',
            'El pedido se ha registrado correctamente.',
        ).then(() => {
            onClose()
        })
    }

    const handleFormSubmit = async () => {
        if (!Obra || !NroPedido || !OrdenCompra || !Fecha) {
            showError('Error', 'Todos los campos son obligatorios.')
            return
        }

        try {
            await createPedidoHerrajes(
                Obra,
                Fecha,
                NroPedido,
                OrdenCompra,
                Estado,
                uploadedData,
            )
            handleSuccess()
            setUploadedData([])
            setObra('')
            setFecha(Today)
            setNroPedido('')
            setOrdenCompra('')
            onSubmit()
        } catch (error) {
            console.error('Error al crear el pedido:', error)
            showError('Error', 'No se pudo registrar el pedido.')
        }
    }

    return (
        <Formik
            initialValues={{
                Obra: '',
                Fecha: Today,
                NroPedido: '',
                OrdenCompra: '',
                Estado: 'Abierto',
                materiales: [],
            }}
            onSubmit={() => handleConfirmSubmit(handleFormSubmit)}
        >
            {({ handleSubmit }) => (
                <Form>
                    <FormContainer>
                        <div className="flex items-center">
                            <FormItem
                                label="Nombre de la Obra"
                                className="w-3/4 mr-4"
                            >
                                <Input
                                    type="text"
                                    name="Obra"
                                    value={Obra}
                                    onChange={(e) => setObra(e.target.value)}
                                />
                            </FormItem>
                            <FormItem
                                label="Nro. de Pedido"
                                className="w-1/2 mr-4"
                            >
                                <Input
                                    type="text"
                                    name="NroPedido"
                                    value={NroPedido}
                                    onChange={(e) =>
                                        setNroPedido(e.target.value)
                                    }
                                />
                            </FormItem>
                            <FormItem
                                label="Nro. de Orden de Compra"
                                className="w-1/2"
                            >
                                <Input
                                    type="text"
                                    name="OrdenCompra"
                                    value={OrdenCompra}
                                    onChange={(e) =>
                                        setOrdenCompra(e.target.value)
                                    }
                                />
                            </FormItem>
                        </div>

                        <div className="flex items-center mb-4">
                            <FormItem label="Fecha de Pedido" className="w-1/4">
                                <Input
                                    type="date"
                                    name="Fecha"
                                    value={Fecha}
                                    onChange={(e) => setFecha(e.target.value)}
                                />
                            </FormItem>
                            <div className="w-3/4">
                                <UploadHerrajes
                                    onFileUpload={handleFileUpload}
                                    onClose={onClose}
                                />
                            </div>
                        </div>
                    </FormContainer>

                    <Table style={{ padding: 0 }}>
                        <div className="mat-list">
                            <THead>
                                <Th className="text-center w-2/12">Código</Th>
                                <Th className="text-center w-4/12">
                                    Descripción
                                </Th>
                                <Th className="text-center w-2/12">
                                    Cant. a Entregar
                                </Th>
                                <Th className="text-center w-2/12">
                                    Unidad de Medida
                                </Th>
                            </THead>
                            <TBody>
                                {uploadedData.length > 0 ? (
                                    uploadedData.map((material, index) => (
                                        <tr key={index}>
                                            <Td className="text-center w-2/12">
                                                {material.Codigo}
                                            </Td>
                                            <Td className="w-4/12">
                                                {material.Descripcion}
                                            </Td>

                                            <Td className="text-center w-2/12 p-0">
                                                {material.CantEntrega}
                                            </Td>
                                            <Td className="text-center w-2/12">
                                                {material.Unidad}
                                            </Td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr>
                                        <Td colSpan={5}>
                                            No hay materiales cargados.
                                        </Td>
                                    </tr>
                                )}
                            </TBody>
                        </div>
                    </Table>

                    <Button
                        type="button"
                        onClick={() => handleConfirmSubmit(handleSubmit)}
                        variant="solid"
                    >
                        Registrar Pedido
                    </Button>
                </Form>
            )}
        </Formik>
    )
}

export default PedidoHerrajesForm

import React, { useEffect, useState } from 'react'
import { Table } from '@/components/ui'
import THead from '@/components/ui/Table/THead'
import Th from '@/components/ui/Table/Th'
import TBody from '@/components/ui/Table/TBody'
import Td from '@/components/ui/Table/Td'
import { deletePedidoHerrajes } from '@/api/api'
import Swal from 'sweetalert2'
import '../../pedidosViewStyles.css'
import DeleteButton from '@/components/template/DeleteButton'
import { usePedidosHerrajes } from '@/utils/hooks/usePedidosHerrajes'
import { HiOutlineChevronDown, HiOutlineChevronUp } from 'react-icons/hi'
import { IconButton } from '@mui/material'
import HerrajesNestedList from './HerrajesNestedList'
import { Skeleton } from '@/components/ui'

type PedidosHerrajesListProps = {
    onSubmit: () => void
    allPedidos: boolean
}

const PedidosHerrajesList: React.FC<PedidosHerrajesListProps> = ({
    onSubmit,
    allPedidos,
}) => {
    const { pedidos, loading, fetchPedidos } = usePedidosHerrajes()
    const [expandedPedidoId, setExpandedPedidoId] = useState<string | null>(
        null,
    )

    useEffect(() => {
        fetchPedidos()
    }, [onSubmit])

    const formatDate = (dateString: string): string => {
        const [year, month, day] = dateString.split('-')
        if (year && month && day) {
            return `${day}-${month}-${year}`
        }
        return 'Fecha inválida'
    }

    const toggleExpand = (pedidoId: string) => {
        setExpandedPedidoId((prev) => (prev === pedidoId ? null : pedidoId))
    }

    const isRowExpanded = (pedidoId: string) => expandedPedidoId === pedidoId

    const handleDelete = async (pedidoId: string) => {
        if (!pedidoId) return

        try {
            const success = await deletePedidoHerrajes(pedidoId)
            if (success) {
                Swal.fire({
                    title: 'Eliminado',
                    text: 'El pedido ha sido eliminado correctamente.',
                    icon: 'success',
                    confirmButtonColor: '#3085d6',
                })
                fetchPedidos()
            }
        } catch (error) {
            console.error('Error al eliminar el pedido:', error)
            Swal.fire({
                title: 'Error',
                text: 'Hubo un problema al eliminar el pedido.',
                icon: 'error',
                confirmButtonColor: '#d33',
            })
        }
    }

    const handleConfirmDelete = (pedidoId: string) => {
        Swal.fire({
            title: '¿Estás seguro?',
            text: '¿Deseas eliminar este pedido?',
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#d33',
            cancelButtonColor: '#3085d6',
            confirmButtonText: 'Sí, eliminar',
            cancelButtonText: 'Cancelar',
        }).then((result) => {
            if (result.isConfirmed) {
                handleDelete(pedidoId)
            }
        })
    }

    const filteredPedidos = allPedidos
        ? pedidos
        : pedidos.filter((pedido) => pedido.Estado === 'Abierto')

    if (loading) {
        return (
            <div>
                {Array.from(new Array(10)).map((_, index) => (
                    <Skeleton
                        key={index}
                        width="100%"
                        height={100}
                        style={{ marginBottom: '10px' }}
                    />
                ))}
            </div>
        )
    }

    return (
        <>
            {filteredPedidos.length > 0 ? (
                <div className="table-container">
                    <Table>
                        <THead>
                            <Th className="pt-1 w-3/12">Obra</Th>
                            <Th className="pt-1 w-2/12">Fecha</Th>
                            <Th className="pt-1 w-2/12">N° de Pedido</Th>
                            <Th className="pt-1 w-2/12">N° Orden de Compra</Th>
                            <Th className="pt-1 w-2/12">Estado</Th>
                            <Th></Th>
                        </THead>
                    </Table>

                    <div className="table-body-container">
                        <Table>
                            <TBody>
                                {filteredPedidos.map((pedido, index) => (
                                    <React.Fragment key={index}>
                                        <tr>
                                            <Td className="no-wrap w-3/12 td-px">
                                                {pedido.Obra}
                                            </Td>
                                            <Td className="text-center no-wrap w-2/12 td-px">
                                                {formatDate(pedido.Fecha)}
                                            </Td>
                                            <Td className="text-center no-wrap w-2/12 td-px">
                                                {pedido.NroPedido}
                                            </Td>
                                            <Td className="text-center no-wrap w-2/12 td-status-px">
                                                {pedido.OrdenCompra}
                                            </Td>
                                            <Td
                                                className={`text-center no-wrap w-2/12 td-status-px ${
                                                    pedido.Estado === 'Cerrado'
                                                        ? 'text-red-500'
                                                        : 'text-green-500'
                                                }`}
                                            >
                                                {pedido.Estado}
                                            </Td>
                                            <Td className="m-0 text-center no-wrap td-px">
                                                <IconButton
                                                    onClick={() =>
                                                        toggleExpand(pedido._id)
                                                    }
                                                    size="small"
                                                >
                                                    {isRowExpanded(
                                                        pedido._id,
                                                    ) ? (
                                                        <HiOutlineChevronUp />
                                                    ) : (
                                                        <HiOutlineChevronDown />
                                                    )}
                                                </IconButton>

                                                <DeleteButton
                                                    size="small"
                                                    onDelete={() =>
                                                        handleConfirmDelete(
                                                            pedido._id,
                                                        )
                                                    }
                                                />
                                            </Td>
                                        </tr>
                                        {isRowExpanded(pedido._id) && (
                                            <tr>
                                                <Td
                                                    style={{ padding: 5 }}
                                                    colSpan={6}
                                                >
                                                    <div
                                                        className={`content-wrapper ${
                                                            isRowExpanded(
                                                                pedido._id,
                                                            )
                                                                ? 'expanded'
                                                                : 'collapsed'
                                                        }`}
                                                    >
                                                        <HerrajesNestedList
                                                            materiales={
                                                                pedido.Materiales
                                                            }
                                                            pedidoId={
                                                                pedido._id
                                                            }
                                                            onReceptionComplete={
                                                                fetchPedidos
                                                            }
                                                        />
                                                    </div>
                                                </Td>
                                            </tr>
                                        )}
                                    </React.Fragment>
                                ))}
                            </TBody>
                        </Table>
                    </div>
                </div>
            ) : (
                <p>No hay pedidos realizados.</p>
            )}
        </>
    )
}

