import { Modal } from '@mui/material'
import { Card } from '@/components/ui'
import React, { useRef } from 'react'
import DividerMain from '@/components/template/DividerMain'
import { IconButton } from '@mui/material'
import { HiX } from 'react-icons/hi'
import { Material, Pedido } from '@/@types/pedidos'
import RecibirMaterialForm from '../Forms/RecibirMaterialForm'

type RecibirMaterialModalProps = {
    isOpen: boolean
    toggleModal: () => void
    material: Material
    pedido: Pedido
    onReceptionComplete: () => void
}

const RecibirMaterialModal: React.FC<RecibirMaterialModalProps> = ({
    isOpen,
    toggleModal,
    material,
    pedido,
    onReceptionComplete,
}) => {
    const submitRef = useRef<() => void>(() => {})

    return (
        <Modal
            open={isOpen}
            onClose={toggleModal}
            aria-labelledby="modal-title"
            aria-describedby="modal-description"
            style={{ zIndex: 1000 }}
        >
            <Card
                style={{
                    position: 'absolute',
                    top: '50%',
                    left: '50%',
                    transform: 'translate(-50%, -50%)',
                    width: '50%',
                    height: '100%',
                }}
            >
                <div className="flex justify-between items-center mb-4">
                    <div>
                        <h4 id="modal-title" style={{ color: '#01662b' }}>
                            Información del material
                        </h4>
                        <DividerMain />
                    </div>

                                    <IconButton
                    onClick={toggleModal}
                    style={{ color: '#9ca3af', padding: 4 }}
                    size="small"
                    className="hover:bg-gray-100 transition-colors"
                >
                    <HiX className="text-xl" />
                </IconButton>
                </div>

                <RecibirMaterialForm
                    material={material}
                    pedido={pedido}
                    onSubmit={onReceptionComplete}
                    closeModal={toggleModal}
                />
            </Card>
        </Modal>
    )
}

export default RecibirMaterialModal

import React, { useState } from 'react'
import * as XLSX from 'xlsx'
import { Formik, Form } from 'formik'
import { FormItem, FormContainer, Input } from '@/components/ui'
import { Button } from '@/components/ui'
import CargarMaterialesButton from '../Buttons/CargarPedidoButton'

type UploadPerfilesProps = {
    onFileUpload: (data: any[][]) => void
    onClose?: () => void
}

const UploadPerfiles: React.FC<UploadPerfilesProps> = ({
    onFileUpload,
    onClose,
}) => {
    const [file, setFile] = useState<File | null>(null)
    const [fileName, setFileName] = useState<string>('')

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0] || null
        setFile(selectedFile)
        setFileName(selectedFile ? selectedFile.name : '')
    }

    const handleFileUpload = () => {
        if (file) {
            const reader = new FileReader()
            reader.onload = (e: ProgressEvent<FileReader>) => {
                if (!e.target?.result) return

                const data = new Uint8Array(e.target.result as ArrayBuffer)
                const workbook = XLSX.read(data, { type: 'array' })

                const sheetName = workbook.SheetNames[1]
                const sheet = workbook.Sheets[sheetName]

                if (!sheet) {
                    console.error(
                        'No se encontró la hoja especificada en el archivo.',
                    )
                    return
                }

                const jsonData = XLSX.utils.sheet_to_json(sheet, {
                    header: 1,
                    range: 10,
                }) as any[][]

                const filteredData = jsonData.map((row) => {
                    return [row[1], row[2], row[3], row[4], row[6]]
                })

                onFileUpload(filteredData)
            }
            reader.readAsArrayBuffer(file)
        } else {
            console.error('No se seleccionó ningún archivo.')
        }
    }

    return (
        <Formik
            initialValues={{}}
            onSubmit={(values) => {
                console.log('Form values:', values)
            }}
        >
            <Form>
                <FormContainer className="flex items-center justify-between">
                    <FormItem label="Archivo" className="w-10/12 mx-2">
                        <Input type="text" value={fileName} disabled />
                    </FormItem>
                    <CargarMaterialesButton
                        size="medium"
                        onChange={handleFileChange}
                    />
                    <Button
                        type="button"
                        onClick={handleFileUpload}
                        variant="twoTone"
                    >
                        Cargar archivo
                    </Button>
                </FormContainer>
            </Form>
        </Formik>
    )
}

export default UploadPerfiles

import React, { useState } from 'react'
import { Formik, Form } from 'formik'
import { Input, Button } from '@/components/ui'
import { FormItem, FormContainer } from '@/components/ui'
import UploadVidrios from '../UploadVidrios'
import { Table } from '@/components/ui'
import THead from '@/components/ui/Table/THead'
import Th from '@/components/ui/Table/Th'
import TBody from '@/components/ui/Table/TBody'
import Td from '@/components/ui/Table/Td'
import { createPedidoVidrios } from '@/api/api'
import getCurrentDate from '@/utils/hooks/getCurrentDate'
import { showConfirmation, showSuccess, showError } from '@/utils/hooks/alerts'
import '../../pedidosViewStyles.css'

type UploadedMaterial = {
    Codigo: string
    Tipologia: string
    Ancho: number
    Alto: number
    Cantidad: number
    Composicion: string
    Recepciones: any[]
}

type PedidoVidriosFormProps = {
    onClose: () => void
    onSubmit: () => void
}

const PedidoVidriosForm: React.FC<PedidoVidriosFormProps> = ({
    onClose,
    onSubmit,
}) => {
    const Today = getCurrentDate()
    const [uploadedData, setUploadedData] = useState<UploadedMaterial[]>([])
    const [NroPedido, setNroPedido] = useState('')
    const [Obra, setObra] = useState('')
    const [Fecha, setFecha] = useState(Today)
    const [Cliente, setCliente] = useState('')
    const [Estado, setEstado] = useState('Abierto')

    const handleFileUpload = async (
        jsonData: (string | number | undefined | null)[][],
    ) => {
        const dataToUpload: UploadedMaterial[] = jsonData
            .filter((row) =>
                row.every(
                    (cell: string | number | undefined | null) =>
                        cell !== undefined && cell !== null && cell !== '',
                ),
            )
            .map(([Tipologia, Ancho, Alto, Cantidad, Composicion]) => ({
                Codigo: Tipologia + '-' + Ancho + '-' + Alto,
                Tipologia: String(Tipologia),
                Ancho: Number(Ancho),
                Alto: Number(Alto),
                Cantidad: Number(Cantidad),
                Composicion: String(Composicion),
                Recepciones: [],
            }))

        setUploadedData(dataToUpload)
    }

    const handleConfirmSubmit = (submit: () => void) => {
        showConfirmation(
            '¿Estás seguro?',
            '¿Deseas registrar este pedido?',
        ).then((result) => {
            if (result.isConfirmed) {
                submit()
            }
        })
    }

    const handleSuccess = () => {
        showSuccess(
            'Pedido registrado',
            'El pedido se ha registrado correctamente.',
        ).then(() => {
            onClose()
        })
    }

    const handleFormSubmit = async () => {
        if (!Obra || !NroPedido || !Cliente || !Fecha) {
            showError('Error', 'Todos los campos son obligatorios.')
            return
        }

        try {
            await createPedidoVidrios(
                Cliente,
                Obra,
                Fecha,
                NroPedido,
                Estado,
                uploadedData,
            )
            handleSuccess()
            setUploadedData([])
            setObra('')
            setFecha(Today)
            setNroPedido('')
            setCliente('')
            onSubmit()
        } catch (error) {
            console.error('Error al crear el pedido:', error)
            showError('Error', 'No se pudo registrar el pedido.')
        }
    }

    return (
        <Formik
            initialValues={{
                Cliente: '',
                Obra: '',
                Fecha: Today,
                NroPedido: '',
                Estado: 'Abierto',
                materiales: [],
            }}
            onSubmit={() => handleConfirmSubmit(handleFormSubmit)}
        >
            {({ handleSubmit }) => (
                <Form>
                    <FormContainer>
                        <div className="flex items-center">
                            <FormItem label="Cliente" className="w-4/12 mr-2">
                                <Input
                                    type="text"
                                    name="Cliente"
                                    value={Cliente}
                                    onChange={(e) => setCliente(e.target.value)}
                                />
                            </FormItem>
                            <FormItem
                                label="Nombre de la Obra"
                                className="w-4/12 mr-2"
                            >
                                <Input
                                    type="text"
                                    name="Obra"
                                    value={Obra}
                                    onChange={(e) => setObra(e.target.value)}
                                />
                            </FormItem>
                            <FormItem label="Nro. de Pedido" className="w-4/12">
                                <Input
                                    type="text"
                                    name="NroPedido"
                                    value={NroPedido}
                                    onChange={(e) =>
                                        setNroPedido(e.target.value)
                                    }
                                />
                            </FormItem>
                        </div>

                        <div className="flex items-center mb-4">
                            <FormItem label="Fecha de Pedido" className="w-1/4">
                                <Input
                                    type="date"
                                    name="Fecha"
                                    value={Fecha}
                                    onChange={(e) => setFecha(e.target.value)}
                                />
                            </FormItem>
                            <div className="w-3/4">
                                <UploadVidrios
                                    onFileUpload={handleFileUpload}
                                    onClose={onClose}
                                />
                            </div>
                        </div>
                    </FormContainer>

                    <Table style={{ padding: 0 }}>
                        <div className="mat-list bg-gray-200">
                            <THead>
                                <Th className="text-center w-1/5 bg-gray-300">
                                    Tipología
                                </Th>
                                <Th className="text-center w-1/5">Ancho</Th>
                                <Th className="text-center w-1/5">Alto</Th>
                                <Th className="text-center w-1/5">Cantidad</Th>
                                <Th className="text-center w-1/5">
                                    Composición
                                </Th>
                            </THead>
                            <TBody>
                                {uploadedData.length > 0 ? (
                                    uploadedData.map((material, index) => (
                                        <tr key={index}>
                                            <Td className="text-center w-1/5">
                                                {material.Tipologia}
                                            </Td>
                                            <Td className="text-center w-1/5">
                                                {material.Ancho}
                                            </Td>
                                            <Td className="text-center w-1/5">
                                                {material.Alto}
                                            </Td>
                                            <Td className="text-center w-1/5">
                                                {material.Cantidad}
                                            </Td>
                                            <Td className="text-center w-1/5">
                                                {material.Composicion}
                                            </Td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr>
                                        <Td colSpan={5}>
                                            No hay materiales cargados.
                                        </Td>
                                    </tr>
                                )}
                            </TBody>
                        </div>
                    </Table>

                    <Button
                        type="button"
                        onClick={() => handleConfirmSubmit(handleSubmit)}
                        variant="solid"
                    >
                        Registrar Pedido
                    </Button>
                </Form>
            )}
        </Formik>
    )
}

export default PedidoVidriosForm

import React, { useEffect, useState } from 'react'
import { Table } from '@/components/ui'
import THead from '@/components/ui/Table/THead'
import Th from '@/components/ui/Table/Th'
import TBody from '@/components/ui/Table/TBody'
import Td from '@/components/ui/Table/Td'
import { deletePedidoVidrios } from '@/api/api'
import Swal from 'sweetalert2'
import '../../pedidosViewStyles.css'
import DeleteButton from '@/components/template/DeleteButton'
import { usePedidosVidrios } from '@/utils/hooks/usePedidosVidrios'
import { HiOutlineChevronDown, HiOutlineChevronUp } from 'react-icons/hi'
import { IconButton } from '@mui/material'
import VidriosNestedList from './VidriosNestedList'
import { Skeleton } from '@/components/ui'

type PedidosVidriosListProps = {
    onSubmit: () => void
    allPedidos: boolean
}

const PedidosVidriosList: React.FC<PedidosVidriosListProps> = ({
    onSubmit,
    allPedidos,
}) => {
    const { pedidos, loading, fetchPedidos } = usePedidosVidrios()
    const [expandedPedidoId, setExpandedPedidoId] = useState<string | null>(
        null,
    )

    useEffect(() => {
        fetchPedidos()
    }, [onSubmit])

    const formatDate = (dateString: string): string => {
        const [year, month, day] = dateString.split('-')
        if (year && month && day) {
            return `${day}-${month}-${year}`
        }
        return 'Fecha inválida'
    }

    const toggleExpand = (pedidoId: string) => {
        setExpandedPedidoId((prev) => (prev === pedidoId ? null : pedidoId))
    }

    const isRowExpanded = (pedidoId: string) => expandedPedidoId === pedidoId

    const handleDelete = async (pedidoId: string) => {
        if (!pedidoId) return

        try {
            const success = await deletePedidoVidrios(pedidoId)
            if (success) {
                Swal.fire({
                    title: 'Eliminado',
                    text: 'El pedido ha sido eliminado correctamente.',
                    icon: 'success',
                    confirmButtonColor: '#3085d6',
                })
                fetchPedidos()
            }
        } catch (error) {
            console.error('Error al eliminar el pedido:', error)
            Swal.fire({
                title: 'Error',
                text: 'Hubo un problema al eliminar el pedido.',
                icon: 'error',
                confirmButtonColor: '#d33',
            })
        }
    }

    const handleConfirmDelete = (pedidoId: string) => {
        Swal.fire({
            title: '¿Estás seguro?',
            text: '¿Deseas eliminar este pedido?',
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#d33',
            cancelButtonColor: '#3085d6',
            confirmButtonText: 'Sí, eliminar',
            cancelButtonText: 'Cancelar',
        }).then((result) => {
            if (result.isConfirmed) {
                handleDelete(pedidoId)
            }
        })
    }

    const filteredPedidos = allPedidos
        ? pedidos
        : pedidos.filter((pedido) => pedido.Estado === 'Abierto')

    if (loading) {
        return (
            <div>
                {Array.from(new Array(10)).map((_, index) => (
                    <Skeleton
                        key={index}
                        width="100%"
                        height={100}
                        style={{ marginBottom: '10px' }}
                    />
                ))}
            </div>
        )
    }

    return (
        <>
            {filteredPedidos.length > 0 ? (
                <div className="table-container">
                    <Table>
                        <THead>
                            <Th className="pt-1 w-3/12">Cliente</Th>
                            <Th className="pt-1 w-2/12">Obra</Th>
                            <Th className="pt-1 w-2/12">Fecha</Th>
                            <Th className="pt-1 w-2/12">N° de Pedido</Th>
                            <Th className="pt-1 w-2/12">Estado</Th>
                            <Th></Th>
                        </THead>
                    </Table>

                    <div className="table-body-container">
                        <Table>
                            <TBody>
                                {filteredPedidos.map((pedido, index) => (
                                    <React.Fragment key={index}>
                                        <tr>
                                            <Td className=" no-wrap w-3/12 td-px">
                                                {pedido.Cliente}
                                            </Td>
                                            <Td className="text-center no-wrap w-2/12 td-px">
                                                {pedido.Obra}
                                            </Td>
                                            <Td className="text-center no-wrap w-2/12 td-px">
                                                {formatDate(pedido.Fecha)}
                                            </Td>
                                            <Td className="text-center no-wrap w-2/12 td-px">
                                                {pedido.NroPedido}
                                            </Td>
                                            <Td
                                                className={`text-center no-wrap w-2/12 td-status-px ${
                                                    pedido.Estado === 'Cerrado'
                                                        ? 'text-red-500'
                                                        : 'text-green-500'
                                                }`}
                                            >
                                                {pedido.Estado}
                                            </Td>
                                            <Td className="m-0 text-center no-wrap td-px">
                                                <IconButton
                                                    onClick={() =>
                                                        toggleExpand(pedido._id)
                                                    }
                                                    size="small"
                                                >
                                                    {isRowExpanded(
                                                        pedido._id,
                                                    ) ? (
                                                        <HiOutlineChevronUp />
                                                    ) : (
                                                        <HiOutlineChevronDown />
                                                    )}
                                                </IconButton>

                                                <DeleteButton
                                                    size="small"
                                                    onDelete={() =>
                                                        handleConfirmDelete(
                                                            pedido._id,
                                                        )
                                                    }
                                                />
                                            </Td>
                                        </tr>
                                        {isRowExpanded(pedido._id) && (
                                            <tr>
                                                <Td
                                                    style={{ padding: 5 }}
                                                    colSpan={6}
                                                >
                                                    <div
                                                        className={`content-wrapper ${
                                                            isRowExpanded(
                                                                pedido._id,
                                                            )
                                                                ? 'expanded'
                                                                : 'collapsed'
                                                        }`}
                                                    >
                                                        <VidriosNestedList
                                                            vidrios={
                                                                pedido.Vidrios
                                                            }
                                                            pedidoId={
                                                                pedido._id
                                                            }
                                                            nroPedido={
                                                                pedido.NroPedido
                                                            }
                                                            status={
                                                                pedido.Estado
                                                            }
                                                            onReceptionComplete={
                                                                fetchPedidos
                                                            }
                                                        />
                                                    </div>
                                                </Td>
                                            </tr>
                                        )}
                                    </React.Fragment>
                                ))}
                            </TBody>
                        </Table>
                    </div>
                </div>
            ) : (
                <p>No hay pedidos realizados.</p>
            )}
        </>
    )
}

export default PedidosVidriosList

import React, { useState, useEffect } from 'react'
import { Table } from '@/components/ui'
import THead from '@/components/ui/Table/THead'
import Th from '@/components/ui/Table/Th'
import TBody from '@/components/ui/Table/TBody'
import Td from '@/components/ui/Table/Td'
import { Vidrio } from '@/@types/pedidos'
import PedidoDetailsButton from '../../Buttons/PedidoDetailsButton'
import PedidoVidriosInfoModal from '../Modal/PedidoVidriosInfoModal'
import RecibirMaterialButton from '../../Buttons/RecibirMaterialButton'
import RecibirVidrioModal from '../Modal/RecibirVidrioModal'
import { updateEstadoVidrios } from '@/api/api'
import '../../pedidosViewStyles.css'

interface VidriosNestedListProps {
    vidrios: Vidrio[]
    pedidoId: string
    nroPedido: string
    status: string
    onReceptionComplete: () => void
}

const VidriosNestedList: React.FC<VidriosNestedListProps> = ({
    vidrios,
    pedidoId,
    nroPedido,
    status,
    onReceptionComplete,
}) => {
    const [isInfoModalOpen, setIsInfoModalOpen] = useState(false)
    const [selectedVidrio, setSelectedVidrio] = useState<Vidrio | null>(null)
    const [isMatModalOpen, setMatModalOpen] = useState(false)

    const toggleInfoModal = (vidrio: Vidrio | null = null) => {
        setSelectedVidrio(vidrio)
        setIsInfoModalOpen(!isInfoModalOpen)
    }

    const toggleMatModal = (vidrio: Vidrio | null = null) => {
        setSelectedVidrio(vidrio)
        setMatModalOpen(!isMatModalOpen)
    }

    useEffect(() => {
        if (status === 'Abierto') {
            const allComplete = vidrios.every((vidrio) => {
                const cantRecibida = vidrio.Recepciones
                    ? vidrio.Recepciones.reduce(
                          (recepcionTotal, recepcion) =>
                              recepcionTotal + Number(recepcion.CantRecibida),
                          0,
                      )
                    : 0
                return cantRecibida >= vidrio.Cantidad
            })

            if (allComplete) {
                updateEstadoVidrios(pedidoId, 'Cerrado')
                    .then(() => {
                        console.log(`Pedido ${pedidoId} actualizado a Cerrado`)
                        onReceptionComplete()
                    })
                    .catch((error) => {
                        console.error('Error al cerrar el pedido:', error)
                    })
            }
        }
    }, [vidrios, pedidoId, onReceptionComplete, status])

    return (
        <Table style={{ tableLayout: 'fixed', width: '100%' }}>
            <THead>
                <Th className="text-center" style={{ width: '10%' }}>
                    Tipología
                </Th>
                <Th className="text-center" style={{ width: '10%' }}>
                    Ancho
                </Th>
                <Th className="text-center" style={{ width: '10%' }}>
                    Alto
                </Th>
                <Th className="text-center" style={{ width: '12%' }}>
                    Composición
                </Th>
                <Th className="text-center" style={{ width: '10%' }}>
                    Cant. a Recibir
                </Th>
                <Th className="text-center" style={{ width: '10%' }}>
                    Cant. Recibida
                </Th>
                <Th className="text-center" style={{ width: '15%' }}>
                    Estado
                </Th>
                <Th style={{ width: '5%', padding: 0 }}></Th>
            </THead>
            <TBody>
                {vidrios.map((vidrio, index) => {
                    const cantRecibida = vidrio.Recepciones
                        ? vidrio.Recepciones.reduce(
                              (recepcionTotal, recepcion) =>
                                  recepcionTotal +
                                  Number(recepcion.CantRecibida),
                              0,
                          )
                        : 0

                    const cantEntrega = vidrio.Cantidad

                    const estado =
                        cantRecibida === 0
                            ? 'En tránsito'
                            : cantRecibida < cantEntrega
                              ? 'Incompleto'
                              : cantRecibida === cantEntrega
                                ? 'Completo'
                                : 'Excedido'

                    return (
                        <React.Fragment key={index}>
                            <tr>
                                <Td
                                    className="text-center"
                                    style={{ width: '15%' }}
                                >
                                    {vidrio.Tipologia}
                                </Td>
                                <Td
                                    className="text-center"
                                    style={{ width: '10%' }}
                                >
                                    {vidrio.Ancho} mm.
                                </Td>
                                <Td
                                    className="text-center"
                                    style={{ width: '10%' }}
                                >
                                    {vidrio.Alto} mm.
                                </Td>
                                <Td
                                    className="text-center"
                                    style={{ width: '10%' }}
                                >
                                    {vidrio.Composicion}
                                </Td>
                                <Td
                                    className="text-center"
                                    style={{ width: '10%' }}
                                >
                                    {vidrio.Cantidad} u.
                                </Td>
                                <Td
                                    className="text-center"
                                    style={{ width: '10%' }}
                                >
                                    {cantRecibida} u.
                                </Td>
                                <Td
                                    style={{ width: '15%' }}
                                    className={`text-center no-wrap w-2/12 ${
                                        {
                                            Excedido: 'text-yellow-500',
                                            Completo: 'text-green-500',
                                            Incompleto: 'text-red-500',
                                            'En tránsito': 'text-gray-500',
                                        }[estado]
                                    }`}
                                >
                                    {estado}
                                </Td>
                                <Td style={{ width: '5%', padding: 0 }}>
                                    <RecibirMaterialButton
                                        size="small"
                                        recibirMat={() =>
                                            toggleMatModal(vidrio)
                                        }
                                    />
                                    <PedidoDetailsButton
                                        size="small"
                                        pedidoInfo={() =>
                                            toggleInfoModal(vidrio)
                                        }
                                    />
                                </Td>
                            </tr>

                            {selectedVidrio && (
                                <PedidoVidriosInfoModal
                                    isOpen={isInfoModalOpen}
                                    toggleModal={() => toggleInfoModal(null)}
                                    vidrio={selectedVidrio}
                                />
                            )}

                            {selectedVidrio && (
                                <RecibirVidrioModal
                                    isOpen={isMatModalOpen}
                                    toggleModal={() => toggleMatModal(null)}
                                    vidrio={selectedVidrio}
                                    pedidoId={pedidoId}
                                    nroPedido={nroPedido}
                                    onReceptionComplete={onReceptionComplete}
                                />
                            )}
                        </React.Fragment>
                    )
                })}
            </TBody>
        </Table>
    )
}

