import React from 'react'
import { Card, Tag } from '@/components/ui'
import classNames from 'classnames'
import { Project } from '@/@types/project'

type ProjectCardProps = {
    project: Project
    onClick: (project: Project) => void
    getProgressClasses: (percent: number) => { border: string, text: string, ring: string, bg: string }
    normalizeProgress: (val: number) => number
    getClientName: (client: any) => string
    getResponsableName: (resp: any) => string
    getStatusColor: (status?: string) => string
}

const ProgressBar = ({ percent, colorClass }: { percent: number, colorClass: string }) => {
    const normalizeInternal = (val: number) => {
        if (!val) return 0
        return (val > 0 && val <= 1) ? val * 100 : val
    }
    const p = normalizeInternal(percent)
    return (
        <div className="w-full bg-gray-200 rounded-full h-1.5 overflow-hidden">
            <div 
                className={`h-full rounded-full transition-all duration-500 ${colorClass}`}
                style={{ width: `${Math.min(p, 100)}%` }}
            />
        </div>
    )
}

const ProjectCard: React.FC<ProjectCardProps> = ({ 
    project, 
    onClick, 
    getProgressClasses, 
    normalizeProgress,
    getClientName,
    getResponsableName,
    getStatusColor
}) => {
    const colors = getProgressClasses(project.avance)
    const p = normalizeProgress(project.avance)

    return (
        <Card 
            clickable 
            className={`hover:shadow-lg transition-shadow border-t-4 ${colors.border}`}
            onClick={() => onClick(project)}
        >
            <div className="flex justify-between items-start mb-4">
                <div>
                    <h6 className="section-title font-bold mb-1">{project.nombre}</h6>
                    <span className="text-xs text-gray-500">{project.codigo}</span>
                </div>
                <Tag className={classNames(
                    getStatusColor(project.estado), 
                    "border-0"
                )}>
                    {project.estado?.replace('_', ' ') || 'ACTIVO'}
                </Tag>
            </div>
            
            <div className="mb-4">
                <p className="text-sm text-gray-600 mb-1">Cliente: <span className="font-semibold">{getClientName(project.cliente)}</span></p>
                <p className="text-sm text-gray-600">Responsable: <span className="font-semibold">{getResponsableName(project.responsable)}</span></p>
            </div>

            <div className="mt-4">
                <div className="flex justify-between text-xs mb-1">
                    <span>Progreso General</span>
                    <span className="font-bold">{Math.round(p)}%</span>
                </div>
                <ProgressBar percent={project.avance} colorClass={colors.bg} />
            </div>
        </Card>
    )
}

export default ProjectCard

import React, { useState } from 'react'
import { IconButton } from '@mui/material'
import formatCurrency from '@/utils/hooks/formatCurrency'
import { Project } from '@/@types/project'
import DeleteButton from '../../DeleteButton'
import { deleteProject } from '@/api/api'
import Swal from 'sweetalert2'
import { HiOutlineArrowPath } from 'react-icons/hi2'

type Props = {
    project: Project
    expanded: boolean
    onToggleExpand: () => void
    fetchProjects: () => void
}

const ProjectCardItem: React.FC<Props> = ({
    project,
    expanded,
    onToggleExpand,
    fetchProjects,
}) => {
    const getStatusColor = (estado: string) => {
        switch (estado) {
            case 'En_curso':
                return 'text-blue-500'
            case 'Completado':
                return 'text-green-500'
            case 'Cancelado':
                return 'text-red-500'
            case 'Pausado':
                return 'text-yellow-500'
            default:
                return 'text-gray-500'
        }
    }

    const getStatusBadgeColor = (estado: string) => {
        switch (estado) {
            case 'En_curso':
                return 'bg-blue-100 text-blue-800'
            case 'Completado':
                return 'bg-green-100 text-green-800'
            case 'Cancelado':
                return 'bg-red-100 text-red-800'
            case 'Pausado':
                return 'bg-yellow-100 text-yellow-800'
            default:
                return 'bg-gray-100 text-gray-800'
        }
    }

    const formatDate = (date: Date | string | undefined) => {
        if (!date) return 'N/A'
        const dateObj = typeof date === 'string' ? new Date(date) : date
        return dateObj.toLocaleDateString('es-ES')
    }

    const getClientName = (client: any) => {
        if (!client) return 'Sin Cliente'
        if (typeof client === 'string') return client
        if (client.tipoCliente === 'Empresa') return client.razonSocial
        return `${client.nombre || ''} ${client.apellido || ''}`.trim()
    }

    const getResponsableName = (resp: any) => {
        if (!resp) return 'Sin Asignar'
        if (typeof resp === 'string') return resp
        return `${resp.nombre || ''} ${resp.apellido || ''}`.trim()
    }

    const handleDelete = () => {
        fetchProjects()
    }

    const projectDelete = async (projectId: string) => {
        if (!projectId) return

        try {
            const success = await deleteProject(projectId)
            if (success) {
                Swal.fire({
                    title: 'Eliminado',
                    text: 'El proyecto ha sido eliminado correctamente.',
                    icon: 'success',
                    confirmButtonColor: '#3085d6',
                })
                handleDelete()
            }
        } catch (error) {
            console.error('Error al eliminar el proyecto:', error)
            Swal.fire({
                title: 'Error',
                text: 'Hubo un problema al eliminar el proyecto.',
                icon: 'error',
                confirmButtonColor: '#d33',
            })
        }
    }

    const handleConfirmDelete = (projectId: string) => {
        Swal.fire({
            title: '¿Estás seguro?',
            text: '¿Deseas eliminar este proyecto?',
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#d33',
            cancelButtonColor: '#3085d6',
            confirmButtonText: 'Sí, eliminar',
            cancelButtonText: 'Cancelar',
        }).then((result) => {
            if (result.isConfirmed) {
                projectDelete(projectId)
            }
        })
    }

    const progress = Math.round(project.avance || 0)
    const isOverBudget = project.presupuesto.real > project.presupuesto.estimado

    return (
        <div className={`flip-card ${expanded ? 'flipped' : ''}`}>
            <div className="flip-card-inner">
                {/* Front side - Main project info */}
                <div className="flip-card-front">
                    <div className="flex h-full w-full">
                        {/* Contenido principal - 4/5 */}
                        <div className="flex-1" style={{ width: '90%' }}>
                            <div className="flex justify-between items-center h-full">
                                <div
                                    className="flex items-center"
                                    style={{ width: '70%' }}
                                >
                                    <div className="mr-3">
                                        <p className="text-sm text-gray-600">
                                            {project.codigo}
                                        </p>
                                        <h5 className="text-lg font-semibold">
                                            {project.nombre}
                                        </h5>
                                        <p className="text-sm text-gray-600">
                                            {getClientName(project.cliente)}
                                        </p>
                                    </div>
                                </div>

                                <div
                                    className="text-right w-full"
                                    style={{ width: '30%' }}
                                >
                                    <span
                                        className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusBadgeColor(project.estado)}`}
                                    >
                                        {project.estado.replace('_', ' ')}
                                    </span>
                                    <div className="w-full bg-gray-200 rounded-full h-2 mt-1 ml-auto">
                                        <div
                                            className={`h-2 rounded-full ${isOverBudget ? 'bg-red-500' : 'bg-blue-500'}`}
                                            style={{
                                                width: `${Math.min(progress, 100)}%`,
                                            }}
                                        ></div>
                                    </div>
                                    <span className="text-xs text-gray-500">
                                        {progress}%
                                    </span>
                                </div>
                            </div>
                        </div>

                        {/* Icono para girar - 1/5 */}
                        <div
                            className="flex items-center justify-center"
                            style={{ width: '10%' }}
                        >
                            <IconButton onClick={onToggleExpand} size="small">
                                <HiOutlineArrowPath />
                            </IconButton>
                            <DeleteButton
                                size="small"
                                onDelete={() =>
                                    handleConfirmDelete(project._id)
                                }
                            />
                        </div>
                    </div>
                </div>

                {/* Back side - Detailed project info */}
                <div className="flip-card-back">
                    <div className="flex h-full w-full">
                        {/* Contenido principal - 4/5 */}
                        <div className="flex-1" style={{ width: '90%' }}>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 h-full">
                                <div>
                                    <h6 className="font-semibold text-sm mb-2">
                                        Información del Proyecto
                                    </h6>
                                    <div className="space-y-1 text-sm">
                                        <p>
                                            <span className="font-medium">
                                                Descripción:
                                            </span>{' '}
                                            {project.descripcion || 'Sin descripción'}
                                        </p>
                                        <p>
                                            <span className="font-medium">
                                                Responsable:
                                            </span>{' '}
                                            {getResponsableName(project.responsable)}
                                        </p>
                                        <p>
                                            <span className="font-medium">
                                                Fecha Inicio:
                                            </span>{' '}
                                            {formatDate(project.fechaInicio)}
                                        </p>
                                        <p>
                                            <span className="font-medium">
                                                Fecha Fin:
                                            </span>{' '}
                                            {formatDate(project.fechaFinEstimada)}
                                        </p>
                                    </div>
                                </div>

                                <div>
                                    <h6 className="font-semibold text-sm mb-2">
                                        Equipo y Etapas
                                    </h6>
                                    <div className="space-y-1 text-sm">
                                        <p>
                                            <span className="font-medium">
                                                Equipo:
                                            </span>{' '}
                                            {project.equipo?.length || 0} miembros
                                        </p>
                                        <p>
                                            <span className="font-medium">
                                                Etapas:
                                            </span>{' '}
                                            {project.etapas?.length || 0} etapas
                                        </p>
                                        <p>
                                            <span className="font-medium">
                                                Presupuesto:
                                            </span>{' '}
                                            {formatCurrency(project.presupuesto.estimado)} {project.presupuesto.moneda}
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Icono para girar - 1/5 */}
                        <div
                            className="flex items-center justify-center"
                            style={{ width: '10%' }}
                        >
                            <IconButton onClick={onToggleExpand} size="small">
                                <HiOutlineArrowPath />
                            </IconButton>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

