import React from 'react'
import { Card } from '@/components/ui'
import { HiOutlineTrendingUp, HiOutlineTrendingDown } from 'react-icons/hi'
import classNames from 'classnames'
import { motion } from 'framer-motion'
import { Project } from '@/@types/project'
import { Select } from '@/components/ui'

interface DashboardStatsProps {
    project: Project
    projectStatus: {
        gap: number
        isAhead: boolean
        idealToday: number
        realToday: number
    } | null
    onStatusChange?: (newStatus: Project['estado']) => void
}

const statusOptions: { value: Project['estado'], label: string, color: string }[] = [
    { value: 'Planificacion', label: 'Planificación', color: 'bg-gray-100 text-gray-700' },
    { value: 'En_curso', label: 'En Curso', color: 'bg-blue-100 text-blue-700' },
    { value: 'Pausado', label: 'Pausado', color: 'bg-amber-100 text-amber-700' },
    { value: 'Completado', label: 'Completado', color: 'bg-emerald-100 text-emerald-700' },
    { value: 'Cancelado', label: 'Cancelado', color: 'bg-red-100 text-red-700' },
]

const DashboardStats: React.FC<DashboardStatsProps> = ({ project, projectStatus, onStatusChange }) => {
    const currentStatus = statusOptions.find(opt => opt.value === project.estado) || statusOptions[0]
    return (
        <Card className="border-none shadow-sm bg-white overflow-hidden flex flex-col">
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-6">
                    <div>
                        <p className="text-xs text-gray-400 font-bold uppercase mb-1">Avance del Proyecto</p>
                        <p className="text-3xl font-black text-gray-900">{projectStatus?.realToday}%</p>
                    </div>
                    <div className="h-12 w-px bg-gray-200"></div>
                    <div>
                        <p className="text-xs text-gray-400 font-bold uppercase mb-1">Estado</p>
                        <div className={classNames(
                            "flex items-center gap-2 px-3 py-1 rounded-full text-sm font-bold",
                            projectStatus?.isAhead ? "bg-emerald-50 text-emerald-600" : "bg-orange-50 text-orange-600"
                        )}>
                            {projectStatus?.isAhead ? <HiOutlineTrendingUp /> : <HiOutlineTrendingDown />}
                            <span>
                                {projectStatus?.gap === 0 ? 'Al día' : 
                                 projectStatus?.gap && projectStatus.gap < 0 ? 
                                 `${Math.abs(Math.round(projectStatus.gap))}% Atrasado` : 
                                 `${Math.abs(Math.round(projectStatus?.gap || 0))}% Adelantado`}
                            </span>
                        </div>
                    </div>
                </div>
                <div className="flex flex-col justify-center">
                    <div className="text-center hidden md:block">
                        <p className="text-[10px] font-bold text-gray-400 uppercase leading-none mb-1">Estado del Proyecto</p>
                    </div>
                    <Select
                        className="w-48 border border-gray-300 dark:border-gray-800 rounded-lg"
                        options={statusOptions}
                        value={currentStatus}
                        onChange={(option) => option && onStatusChange?.(option.value)}
                        menuPortalTarget={document.body}
                        styles={{
                            menuPortal: (base) => ({ ...base, zIndex: 9999 })
                        }}
                        components={{
                            Control: ({ children, innerProps, innerRef }: any) => (
                                <div 
                                    ref={innerRef}
                                    {...innerProps}
                                    className={`flex items-center rounded-lg cursor-pointer border-2 transition-all ${currentStatus.color.replace('bg-', 'border-').replace('text-', 'text-')}`}
                                >
                                    {children}
                                </div>
                            )
                        }}
                    />
             </div>
                <div className="flex items-center gap-16">
                    <div className="text-left">
                        <p className="text-xs text-gray-400 font-bold uppercase mb-1">Inicio</p>
                        <p className="text-sm font-bold text-gray-700">{project.fechaInicio ? new Date(project.fechaInicio).toLocaleDateString() : 'N/A'}</p>
                    </div>
                    <div className="text-left">
                        <p className="text-xs text-gray-400 font-bold uppercase mb-1">Entrega</p>
                        <p className="text-sm font-bold text-gray-700">{project.deadline ? new Date(project.deadline).toLocaleDateString() : 'N/A'}</p>
                    </div>
                </div>
            </div>
            
            <div className="relative">
                <div className="h-3 bg-gray-200 rounded-full overflow-hidden">
                    <motion.div 
                        initial={{ width: 0 }}
                        animate={{ width: `${projectStatus?.realToday}%` }}
                        transition={{ duration: 1, ease: "easeOut" }}
                        className={classNames(
                            "h-full rounded-full",
                            projectStatus?.isAhead ? "bg-gradient-to-r from-emerald-500 to-teal-500" : "bg-gradient-to-r from-orange-500 to-red-500"
                        )}
                    />
                </div>
                {projectStatus?.idealToday !== undefined && (
                    <div 
                        className="absolute top-0 bottom-0 w-0.5 bg-gray-400"
                        style={{ left: `${projectStatus.idealToday}%` }}
                    >
                        <div className="absolute top-full mt-1 left-1/2 -translate-x-1/2 text-[10px] font-bold text-gray-400 whitespace-nowrap">
                            Ideal: {projectStatus.idealToday}%
                        </div>
                    </div>
                )}
            </div>
        </Card>
    )
}

export default DashboardStats

import React from 'react'
import { HiOutlineLightningBolt } from 'react-icons/hi'
import { Drawer } from '@/components/ui'
import { Project } from '@/@types/project'
import { useProjectDashboard } from '@/utils/hooks/useProjectDashboard'

// Sub-components
import DashboardContent from './DashboardContent'

interface ProjectDashboardPanelProps {
    project: Project | null
    isOpen: boolean
    onClose: () => void
    onSubTaskUpdate?: (stageId: string, subetapaId: string, completed: boolean) => Promise<void>
    onStageUpdate?: (stageId: string, newAvance: number) => Promise<void>
    onStatusUpdate?: (newStatus: Project['estado']) => Promise<void>
    onProjectUpdate?: () => void
}

const ProjectDashboardPanel = ({ 
    project, 
    isOpen, 
    onClose, 
    onSubTaskUpdate,
    onStageUpdate,
    onStatusUpdate,
    onProjectUpdate
}: ProjectDashboardPanelProps) => {
    const { 
        chartData, 
        projectStatus, 
        nowTs, 
        pedidos, 
        loadingPedidos 
    } = useProjectDashboard(project, isOpen)

    if (!project) return null

    return (
        <Drawer
            title={
                <div className="flex items-center gap-4">
                    <div className="bg-gray-100 dark:bg-gray-800 p-2 rounded-xl border border-gray-200 dark:border-gray-700">
                        <HiOutlineLightningBolt className="theme-icon text-2xl" />
                    </div>
                    <div>
                        <h4 className="section-title font-extrabold text-gray-900">Panel de Control</h4>
                        <div className="flex items-center gap-2">
                            <span className="text-xs font-bold text-emerald-600 bg-emerald-50 rounded uppercase">{project.codigo}</span>
                            <span className="text-sm font-medium text-gray-500 whitespace-nowrap">{project.nombre}</span>
                        </div>
                    </div>
                </div>
            }
            isOpen={isOpen}
            onClose={onClose}
            placement="top" height="auto" width="100%"
            headerClass="border-b border-gray-100 bg-white backdrop-blur-md sticky top-0 z-50"
            bodyClass="p-0 bg-gray-50/30 flex flex-col max-h-[92vh] overflow-hidden"
            className="rounded-b-[2.5rem] overflow-hidden shadow-2xl"
        >
            <div className="flex-1 overflow-y-auto custom-scrollbar bg-gray-100">
                <div className="max-w mx-auto p-2">
                    <DashboardContent 
                        project={project}
                        projectStatus={projectStatus}
                        chartData={chartData}
                        nowTs={nowTs}
                        pedidos={pedidos}
                        loadingPedidos={loadingPedidos}
                        onStatusUpdate={onStatusUpdate}
                        onSubTaskToggle={async (s, st, c) => {
                            if (onSubTaskUpdate) {
                                await onSubTaskUpdate(s, st, c)
                                if (onProjectUpdate) onProjectUpdate()
                            }
                        }}
                        onStageProgressChange={async (s, a) => {
                            if (onStageUpdate) {
                                await onStageUpdate(s, a)
                                if (onProjectUpdate) onProjectUpdate()
                            }
                        }}
                    />
                </div>
            </div>
        </Drawer>
    )
}

export default ProjectDashboardPanel

import React, { useEffect } from 'react'
import { Formik, Form, Field } from 'formik'
import * as Yup from 'yup'
import { Input, Button, Select, FormItem } from '@/components/ui'
import { ProjectFormData, Etapa } from '@/@types/project'
import { useClients } from '@/utils/hooks/useClients'
import { useUsers } from '@/utils/hooks/useUsers'

type FormProps = {
    initialValues: Partial<ProjectFormData>
    onSubmit: (values: ProjectFormData, stages: Etapa[]) => void
    onCancel: () => void
}

const validationSchema = Yup.object().shape({
    nombre: Yup.string().required('El nombre es obligatorio'),
    cliente: Yup.string().required('El cliente es obligatorio'),
    codigo: Yup.string().required('El código es obligatorio'),
    responsable: Yup.mixed().required('Debes seleccionar un responsable'),
    fechaInicio: Yup.string().required('La fecha de inicio es obligatoria'),
})

const DEFAULT_STAGES: Etapa[] = [
    { 
        nombre: '1. Proyecto y planificación', 
        descripcion: 'Fase inicial que incluye el diseño arquitectónico, cálculos estructurales, presupuestación y obtención de permisos necesarios para iniciar la obra.',
        peso: 7, 
        avance: 0,
        subetapas: [
            { nombre: 'Anteproyecto y proyecto ejecutivo', avance: 0 },
            { nombre: 'Cómputo y presupuesto', avance: 0 },
            { nombre: 'Planificación de obra', avance: 0 },
            { nombre: 'Permisos y aprobaciones', avance: 0 },
        ]
    },
    { 
        nombre: '2. Preparación del terreno', 
        descripcion: 'Trabajos preliminares para acondicionar el terreno, establecer las instalaciones provisorias y preparar el sitio para el inicio de la construcción.',
        peso: 5, 
        avance: 0,
        subetapas: [
            { nombre: 'Limpieza y nivelación', avance: 0 },
            { nombre: 'Replanteo', avance: 0 },
            { nombre: 'Demoliciones (si aplica)', avance: 0 },
            { nombre: 'Instalaciones provisorias de obra', avance: 0 },
        ]
    },
    { 
        nombre: '3. Cimientos y estructura', 
        descripcion: 'Construcción de los elementos estructurales fundamentales que soportarán toda la edificación, incluyendo fundaciones, columnas, vigas y losas.',
        peso: 28, 
        avance: 0,
        subetapas: [
            { nombre: 'Excavaciones', avance: 0 },
            { nombre: 'Fundaciones', avance: 0 },
            { nombre: 'Estructura de hormigón / metálica', avance: 0 },
            { nombre: 'Losas, vigas, columnas', avance: 0 },
        ]
    },
    { 
        nombre: '4. Envolvente y cerramientos', 
        descripcion: 'Construcción de la envolvente exterior del edificio, incluyendo muros, fachadas, cubiertas y aberturas que definen el volumen y protegen el interior.',
        peso: 18, 
        avance: 0,
        subetapas: [
            { nombre: 'Muros exteriores', avance: 0 },
            { nombre: 'Fachadas', avance: 0 },
            { nombre: 'Cubiertas / techos', avance: 0 },
            { nombre: 'Aberturas exteriores', avance: 0 },
        ]
    },
    { 
        nombre: '5. Instalaciones', 
        descripcion: 'Implementación de todos los sistemas técnicos necesarios para el funcionamiento del edificio: electricidad, agua, gas, climatización y comunicaciones.',
        peso: 17, 
        avance: 0,
        subetapas: [
            { nombre: 'Eléctrica', avance: 0 },
            { nombre: 'Sanitaria', avance: 0 },
            { nombre: 'Gas', avance: 0 },
            { nombre: 'Climatización', avance: 0 },
            { nombre: 'Datos / seguridad', avance: 0 },
        ]
    },
    { 
        nombre: '6. Terminaciones interiores', 
        descripcion: 'Trabajos de acabado interior que definen la estética y funcionalidad de los espacios, incluyendo revestimientos, pisos, pintura y colocación de artefactos.',
        peso: 20, 
        avance: 0,
        subetapas: [
            { nombre: 'Revoques y cielorrasos', avance: 0 },
            { nombre: 'Pisos y revestimientos', avance: 0 },
            { nombre: 'Carpintería interior', avance: 0 },
            { nombre: 'Pintura', avance: 0 },
            { nombre: 'Artefactos', avance: 0 },
        ]
    },
    { 
        nombre: '7. Obras exteriores y cierre', 
        descripcion: 'Finalización de las obras exteriores, trabajos de paisajismo, limpieza general y puesta en marcha de todos los sistemas para la entrega final del proyecto.',
        peso: 5, 
        avance: 0,
        subetapas: [
            { nombre: 'Veredas, accesos', avance: 0 },
            { nombre: 'Paisajismo', avance: 0 },
            { nombre: 'Limpieza final', avance: 0 },
            { nombre: 'Puesta en marcha', avance: 0 },
        ]
    },
]

const ProjectForm = ({ initialValues, onSubmit, onCancel }: FormProps) => {
    const { clients, fetchClients } = useClients()
    const { users, fetchUsers, loading: loadingUsers } = useUsers()

    useEffect(() => {
        fetchClients()
        fetchUsers()
    }, [fetchClients, fetchUsers])

    const clientOptions = clients.map((client) => {
        const id = client._id 
        const label = client.tipoCliente === 'Empresa' 
            ? client.razonSocial 
            : `${client.apellido || ''} ${client.nombre || ''}`.trim()
        
        return { value: id, label: label || 'Sin Nombre' }
    })

    const userOptions = users.map((user) => {
        const id = user._id || user.id || user.uid
        const label = `${user.nombre || ''} ${user.apellido || ''}`.trim() || user.username || user.email || 'Usuario sin nombre'
        return { value: id, label }
    })

    const calculateStagesWithDeadlines = (values: any) => {
        const start = new Date(values.fechaInicio)
        let end = values.fechaFinEstimada ? new Date(values.fechaFinEstimada) : null
        
        if (!end) {
            end = new Date(start)
            end.setMonth(end.getMonth() + 6)
        }

        const totalDays = Math.max(1, Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)))
        const timeDistribution = [0.10, 0.05, 0.25, 0.20, 0.15, 0.20, 0.05]
        let cumulativeDays = 0

        return DEFAULT_STAGES.map((stage, index) => {
            const stageDays = Math.floor(totalDays * timeDistribution[index])
            const stageStartDays = cumulativeDays
            cumulativeDays += stageDays
            
            const stageDeadlineDate = new Date(start)
            stageDeadlineDate.setDate(stageDeadlineDate.getDate() + cumulativeDays)
            
            const subtasksCount = stage.subetapas?.length || 0
            const updatedSubetapas = (stage.subetapas || []).map((sub, subIndex) => {
                const subtaskDeadlineDate = new Date(start)
                const subtaskOffset = subtasksCount > 0 ? Math.floor(stageDays * ((subIndex + 1) / subtasksCount)) : 0
                subtaskDeadlineDate.setDate(subtaskDeadlineDate.getDate() + stageStartDays + subtaskOffset)
                
                return {
                    ...sub,
                    deadline: subtaskDeadlineDate.toISOString().split('T')[0]
                }
            })

            return {
                ...stage,
                deadline: stageDeadlineDate.toISOString().split('T')[0],
                subetapas: updatedSubetapas
            }
        })
    }

    return (
        <Formik
            initialValues={{
                nombre: initialValues.nombre || '',
                cliente: initialValues.cliente || '',
                codigo: initialValues.codigo || '',
                responsable: initialValues.responsable || '',
                fechaInicio: initialValues.fechaInicio || new Date().toISOString().split('T')[0],
                fechaFinEstimada: initialValues.fechaFinEstimada || '',
                deadline: initialValues.deadline || '',
                descripcion: initialValues.descripcion || '',
                presupuesto: {
                    estimado: initialValues.presupuesto?.estimado || 0,
                    moneda: initialValues.presupuesto?.moneda || 'ARS'
                },
                unidadNegocio: initialValues.unidadNegocio || ''
            }}
            validationSchema={validationSchema}
            onSubmit={(values, { setSubmitting }) => {
                const stagesWithDeadlines = calculateStagesWithDeadlines(values)
                const finalValues = {
                    ...values,
                    deadline: values.fechaFinEstimada 
                }
                onSubmit(finalValues as ProjectFormData, stagesWithDeadlines)
                setSubmitting(false)
            }}
        >
            {({ values, touched, errors, isSubmitting, handleSubmit, setFieldValue }) => {
                return (
                <Form onSubmit={handleSubmit}>
                    <div className="grid grid-cols-1 gap-4 mb-2">
                        <div className="grid grid-cols-2 gap-4">
                            <FormItem
                                label="Nombre del Proyecto"
                                invalid={Boolean(errors.nombre && touched.nombre)}
                                errorMessage={errors.nombre}
                            >
                                <Field name="nombre" as={Input} placeholder="Ej: Edificio Central" />
                            </FormItem>

                            <FormItem
                                label="Código"
                                invalid={Boolean(errors.codigo && touched.codigo)}
                                errorMessage={errors.codigo}
                            >
                                <Field name="codigo" as={Input} placeholder="PROJ-001" />
                            </FormItem>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 gap-4 mb-2">
                        <div className="grid grid-cols-2 gap-4">
                            <FormItem
                                label="Cliente"
                                invalid={Boolean(errors.cliente && touched.cliente)}
                                errorMessage={errors.cliente}
                            >
                                <Field name="cliente">
                                    {({ field }: any) => (
                                        <Select
                                            options={clientOptions}
                                            placeholder="Seleccionar Cliente"
                                            value={clientOptions.find(opt => opt.value === field.value)}
                                            onChange={(option) => setFieldValue(field.name, option?.value)}
                                        />
                                    )}
                                </Field>
                            </FormItem>
                        
                            <FormItem
                                label="Responsable"
                                invalid={Boolean(errors.responsable && touched.responsable)}
                                errorMessage={errors.responsable}
                            >
                                <Field name="responsable">
                                    {({ field }: any) => (
                                        <div>
                                            <Select
                                                options={userOptions}
                                                placeholder={loadingUsers ? "Cargando usuarios..." : "Seleccionar Responsable"}
                                                value={userOptions.find(opt => opt.value === field.value)}
                                                onChange={(option) => {
                                                    setFieldValue(field.name, option?.value)
                                                }}
                                                onBlur={() => field.onBlur({ target: { name: field.name } })}
                                            />
                                        </div>
                                    )}
                                </Field>
                            </FormItem>                            
                        </div>
                    </div>
                    <div className="grid grid-cols-1 gap-4 mb-2">
                        <div className="grid grid-cols-2 gap-4">
                            <FormItem
                                label="Fecha Inicio"
                                invalid={Boolean(errors.fechaInicio && touched.fechaInicio)}
                                errorMessage={errors.fechaInicio}
                            >
                                <Field name="fechaInicio">
                                    {({ field }: any) => (
                                         <Input 
                                            type="date" 
                                            {...field} 
                                        />
                                    )}
                                </Field>
                            </FormItem>
                             
                            <FormItem
                                 label="Fecha Fin Estimada"
                                 invalid={Boolean(errors.fechaFinEstimada && touched.fechaFinEstimada)}
                                 errorMessage={errors.fechaFinEstimada}
                            >
                                 <Field name="fechaFinEstimada">
                                     {({ field }: any) => (
                                          <Input 
                                             type="date" 
                                             {...field} 
                                         />
                                     )}
                                 </Field>
                            </FormItem>
                            </div>
                        </div>
                        
                        <div className="grid grid-cols-1 gap-2 ">
                            <FormItem
                                label="Presupuesto Estimado"
                                invalid={Boolean(errors.presupuesto?.estimado && touched.presupuesto?.estimado)}
                                errorMessage={errors.presupuesto?.estimado as string}
                            >
                                <Field name="presupuesto.estimado" as={Input} type="number" placeholder="0" prefix="$" />
                            </FormItem>

                            <FormItem
                                label="Descripción"
                                invalid={Boolean(errors.descripcion && touched.descripcion)}
                                errorMessage={errors.descripcion}
                            >
                                <Field name="descripcion" as={Input} textArea placeholder="Descripción breve" />
                            </FormItem>
                        </div>

                        <div className="flex justify-end gap-2 mt-6">
                            <Button type="button" onClick={onCancel}>
                                Cancelar
                            </Button>
                            <Button 
                                variant="solid" 
                                type="submit" 
                                loading={isSubmitting}
                                disabled={isSubmitting}
                            >
                                {isSubmitting ? 'Creando...' : 'Crear Proyecto'}
                            </Button>
                        </div>
                </Form>
                )}}
        </Formik>
    )
}

