import React from 'react'
import ProjectCard from '../Cards/ProjectCard'
import { Project } from '@/@types/project'

type ProjectCardListProps = {
    projects: Project[]
    onProjectClick: (project: Project) => void
    getProgressClasses: (percent: number) => { border: string, text: string, ring: string, bg: string }
    normalizeProgress: (val: number) => number
    getClientName: (client: any) => string
    getResponsableName: (resp: any) => string
    getStatusColor: (status?: string) => string
    loading: boolean
    allProjects: boolean
    currentBusinessUnitId?: string
}

const ProjectCardList: React.FC<ProjectCardListProps> = ({ 
    projects, 
    onProjectClick, 
    getProgressClasses, 
    normalizeProgress,
    getClientName,
    getResponsableName,
    getStatusColor,
    loading,
    allProjects,
    currentBusinessUnitId
}) => {
    if (loading) {
        return <div className="flex justify-center py-10 text-gray-400 italic">Cargando proyectos...</div>
    }

    const filteredProjects = projects.filter(p => {
        if (allProjects) return true
        
        const projectUnitId = typeof p.unidadNegocio === 'object' ? p.unidadNegocio?._id : p.unidadNegocio
        const matchesUnit = projectUnitId === currentBusinessUnitId
        const isNotClosed = p.estado !== 'Completado' && p.estado !== 'Cancelado'
        
        return matchesUnit && isNotClosed
    })

    if (filteredProjects.length === 0) {
        return <div className="flex justify-center py-10 text-gray-400 italic">No se encontraron proyectos.</div>
    }

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2">
            {filteredProjects.map(project => (
                <ProjectCard 
                    key={project._id}
                    project={project}
                    onClick={onProjectClick}
                    getProgressClasses={getProgressClasses}
                    normalizeProgress={normalizeProgress}
                    getClientName={getClientName}
                    getResponsableName={getResponsableName}
                    getStatusColor={getStatusColor}
                />
            ))}
        </div>
    )
}

export default ProjectCardList

