import axios from 'axios'
import Swal from 'sweetalert2'
import appConfig from '@/configs/app.config'
import { TOKEN_TYPE, REQUEST_HEADER_AUTH_KEY } from '@/constants/api.constant'
import { PERSIST_STORE_NAME } from '@/constants/app.constant'
import deepParseJson from '@/utils/deepParseJson'
import store, { signOutSuccess } from '../store'

const unauthorizedCode = [401]

const BaseService = axios.create({
    timeout: 60000,
    baseURL: (process.env.API_BASE_URL || '') + appConfig.apiPrefix,
})

BaseService.interceptors.request.use(
    (config) => {
        const rawPersistData = localStorage.getItem(PERSIST_STORE_NAME)
        const persistData = deepParseJson(rawPersistData)

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        let accessToken = (persistData as any).auth.session.token

        if (!accessToken) {
            const { auth } = store.getState()
            accessToken = auth.session.token
        }

        if (accessToken) {
            config.headers[
                REQUEST_HEADER_AUTH_KEY
            ] = `${TOKEN_TYPE}${accessToken}`
        }

        return config
    },
    (error) => {
        return Promise.reject(error)
    }
)

BaseService.interceptors.response.use(
    (response) => response,
    (error) => {
        const { response } = error

        if (response && unauthorizedCode.includes(response.status)) {
            store.dispatch(signOutSuccess())
        }

        // Handle generic backend errors with Swal
        const errorMsg = (response?.data as any)?.msg || error.message || 'Hubo un problema al procesar la solicitud.'
        
        // Don't show Swal for unauthorized (handled by signout) or canceled requests
        if (response?.status !== 401 && error.code !== 'ERR_CANCELED') {
            Swal.fire({
                title: 'Error',
                text: errorMsg,
                icon: 'error',
                confirmButtonColor: '#d33',
            })
        }

        return Promise.reject(error)
    }
)

export default BaseService

import { createSlice, createAsyncThunk, PayloadAction } from '@reduxjs/toolkit'
import { apiGetBusinessUnits } from '@/services/BusinessUnitService'

export type BusinessUnitType = 'ESTUDIO' | 'CONSTRUCTORA' | 'INMOBILIARIA'

export interface BusinessUnitAddress {
    calle?: string
    ciudad?: string
    provincia?: string
    codigoPostal?: string
    pais?: string
}

export interface BusinessUnitContact {
    telefono?: string
    email?: string
    sitioWeb?: string
}

export interface BusinessUnitConfig {
    moneda: string
    timezone: string
}

export type BusinessUnit = {
    _id: string
    nombre: string
    tipo: BusinessUnitType
    descripcion?: string
    direccion?: BusinessUnitAddress
    contacto?: BusinessUnitContact
    configuracion?: BusinessUnitConfig
    activo?: boolean
    fechaCreacion?: string
    fechaActualizacion?: string
}

export type BusinessUnitState = {
    currentBusinessUnit: BusinessUnit | null
    allBusinessUnits: BusinessUnit[]
    loading: boolean
}

const initialState: BusinessUnitState = {
    currentBusinessUnit: null,
    allBusinessUnits: [],
    loading: false,
}

export const getBusinessUnits = createAsyncThunk(
    'businessUnit/getBusinessUnits',
    async () => {
        const response = await apiGetBusinessUnits()
        return response.data
    }
)

const businessUnitSlice = createSlice({
    name: 'businessUnit',
    initialState,
    reducers: {
        setBusinessUnits(state, action: PayloadAction<BusinessUnit[]>) {
            state.allBusinessUnits = Array.isArray(action.payload) ? action.payload : []
        },
        setCurrentBusinessUnit(state, action: PayloadAction<BusinessUnit | null>) {
            state.currentBusinessUnit = action.payload
        },
        addBusinessUnit(state, action: PayloadAction<BusinessUnit>) {
            if (!Array.isArray(state.allBusinessUnits)) {
                state.allBusinessUnits = []
            }
            state.allBusinessUnits.push(action.payload)
        }
    },
    extraReducers: (builder) => {
        builder
            .addCase(getBusinessUnits.pending, (state) => {
                state.loading = true
            })
            .addCase(getBusinessUnits.fulfilled, (state, action) => {
                state.loading = false
                // Handle both direct array or wrapped { unidades: [...] } response
                const data = Array.isArray(action.payload)
                    ? action.payload
                    : (action.payload as any)?.unidades || (action.payload as any)?.data || []
                
                state.allBusinessUnits = data
                
                if (data.length > 0 && !state.currentBusinessUnit) {
                    state.currentBusinessUnit = data[0]
                }
            })
            .addCase(getBusinessUnits.rejected, (state) => {
                state.loading = false
            })
    },
})

export const { setBusinessUnits, setCurrentBusinessUnit, addBusinessUnit } = businessUnitSlice.actions
export default businessUnitSlice.reducer

import { useState, useEffect } from 'react'
import useFetchUserIncomes from './useFetchUserIncomes'
import useFetchAllIncomes from './usetFetchAllIncomes'

interface Income {
    monto: number
}

const calculateWeightedIncome = () => {
    const incomes: Income[] = useFetchUserIncomes()
    const allIncomes: Income[] = useFetchAllIncomes()

    const calculateTotalIncome = (incomesArray: Income[]): number => {
        return incomesArray.reduce((total, income) => total + income.monto, 0)
    }

    const [totalUserIncome, setTotalUserIncome] = useState<number>(0)
    const [totalIncome, setTotalIncome] = useState<number>(0)
    const [percentage, setPercentage] = useState<number>(0)

    useEffect(() => {
        const userIncome = calculateTotalIncome(incomes)
        const allIncome = calculateTotalIncome(allIncomes)

        setTotalUserIncome(userIncome)
        setTotalIncome(allIncome)

        if (allIncome !== 0) {
            setPercentage((userIncome / allIncome) * 100)
        }
    }, [incomes, allIncomes])

    return {
        totalUserIncome,
        totalIncome,
        percentage,
    }
}

export default calculateWeightedIncome

