    signInSuccess,
    signOutSuccess,
    useAppSelector,
    useAppDispatch,
} from '@/store'
import appConfig from '@/configs/app.config'
import { REDIRECT_URL_KEY } from '@/constants/app.constant'
import { useNavigate } from 'react-router-dom'
import useQuery from './useQuery'
import type { SignInCredential, SignUpCredential } from '@/@types/auth'
import {
    LOCAL_STORAGE_USER_KEY,
    LOCAL_STORAGE_TOKEN_KEY,
} from '../../services/LocalStorageService'

type Status = 'success' | 'failed'

function useAuth() {
    const dispatch = useAppDispatch()

    const navigate = useNavigate()

    const query = useQuery()

    const { token, signedIn } = useAppSelector((state) => state.auth.session)

    const signIn = async (
        values: SignInCredential,
    ): Promise<
        | {
              status: Status
              message: string
          }
        | undefined
    > => {
        try {
            const resp = await apiSignIn(values)

            if (resp.data && resp.data.token) {
                const { token, user: userData } = resp.data
                dispatch(signInSuccess(token))

                const user = userData || {
                    avatar: '',
                    userName: 'Anonymous',
                    authority: ['USER'],
                    email: '',
                    invites: [],
                }

                dispatch(setUser(user))

                localStorage.setItem(
                    LOCAL_STORAGE_USER_KEY,
                    JSON.stringify(user),
                )
                localStorage.setItem(LOCAL_STORAGE_TOKEN_KEY, token)

                const redirectUrl =
                    query.get(REDIRECT_URL_KEY) ||
                    appConfig.authenticatedEntryPath
                navigate(redirectUrl)

                return {
                    status: 'success',
                    message: '',
                }
            }
        } catch (errors: any) {
            return {
                status: 'failed',
                message: errors?.response?.data?.msg || errors?.response?.data?.message || errors.toString(),
            }
        }
    }

    const signUp = async (values: SignUpCredential) => {
        try {
            const resp = await apiSignUp(values)
            if (resp.data) {
                const { token } = resp.data
                dispatch(signInSuccess(token))
                if (resp.data.user) {
                    dispatch(
                        setUser(
                            resp.data.user || {
                                avatar: '',
                                userName: 'Anonymous',
                                authority: ['USER'],
                                email: '',
                                invites: [],
                            },
                        ),
                    )
                }
                const redirectUrl = query.get(REDIRECT_URL_KEY)
                navigate(
                    redirectUrl
                        ? redirectUrl
                        : appConfig.authenticatedEntryPath,
                )
                return {
                    status: 'success',
                    message: '',
                }
            }
            // eslint-disable-next-line  @typescript-eslint/no-explicit-any
        } catch (errors: any) {
            return {
                status: 'failed',
                message: errors?.response?.data?.message || errors.toString(),
            }
        }
    }

    const handleSignOut = () => {
        dispatch(signOutSuccess())
        dispatch(
            setUser({
                avatar: '',
                userName: '',
                email: '',
                authority: [],
                invites: [],
            }),
        )
        navigate(appConfig.unAuthenticatedEntryPath)
    }

    const signOut = async () => {
        // await apiSignOut()
        handleSignOut()
    }

    return {
        authenticated: token && signedIn,
        //login,
        signIn,
        signUp,
        signOut,
    }
}

export default useAuth

import { useState, useEffect, useCallback } from 'react'
import { fetchBusinessUnits } from '@/api/api'

export const useBusinessUnits = (activo?: boolean, tipo?: string) => {
    const [businessUnits, setBusinessUnits] = useState<any[]>([])
    const [loading, setLoading] = useState<boolean>(true)

    const fetchData = useCallback(async () => {
        try {
            setLoading(true)
            const response = await fetchBusinessUnits(activo, tipo)
            if (response) {
                setBusinessUnits(Array.isArray(response) ? response : (response.unidadesNegocio || []))
            }
        } catch (error) {
            console.error('Error fetching business units:', error)
        } finally {
            setLoading(false)
        }
    }, [activo, tipo])

    useEffect(() => {
        fetchData()
    }, [fetchData])

    return {
        businessUnits,
        loading,
        fetchBusinessUnits: fetchData,
    }
}

