        if (costoFijo?.Costo) {
            sumaCostosFijos += costoFijo.Costo

            if (index > 0) formulaCostosFijos += ' + '
            formulaCostosFijos += `${formatCurrency(costoFijo.Costo)}`
        }
    })

    const ponderador = sumaCostosFijos / (horasMensuales * operariosTotales)
    const costoTotal = costoBase + ponderador

    //Colocacion en obra
    const horasColocacionSemanales = operariosColocacion * horasSemanales
    const costoColocacion =
        (costoTotal * horasColocacionSemanales) / puertasColocadasSemanales
    const costoColocacionMarco = costoColocacion * ponderadoMarco
    const costoColocacionHoja = costoColocacion * ponderadoHoja

    //Costo de fabricacion
    const horasFabricacionSemanales = operariosFabricacion * horasSemanales
    const costoFabricacion =
        (costoTotal * horasFabricacionSemanales) / puertasFabricadasSemanales
    const costoFabricacionMarco = costoFabricacion * ponderadoMarco
    const costoFabricacionHoja = costoFabricacion * ponderadoHoja

    const costoFabricacionBoca = costoTotal * jornada * 0.8

    //Costo de lustrado
    const horasLustradoSemanales = operariosLustre * horasSemanales
    const costoLustrado =
        (costoTotal * horasLustradoSemanales) / puertasLustradasSemanales
    const costoLustradoMarco = costoLustrado * ponderadoMarco
    const costoLustradoHoja = costoLustrado * ponderadoHoja

    //Costo de pintado
    const horasPintadoSemanales = operariosPintura * horasSemanales
    const costoPintado =
        (costoTotal * horasPintadoSemanales) / puertasPintadasSemanales
    const costoPintadoMarco = costoPintado * ponderadoMarco
    const costoPintadoHoja = costoPintado * ponderadoHoja

    return {
        costoTotal,
        costoColocacionMarco,
        costoColocacionHoja,
        costoFabricacionHoja,
        costoFabricacionBoca,
        costoFabricacionMarco,
        costoLustradoHoja,
        costoLustradoMarco,
        costoPintadoHoja,
        costoPintadoMarco,
    }
}

export const useCalculatedCosts = (puerta?: Puerta) => {
    const {
        variablesPredefinidas,
        margenes,
        parametros,
        costosFijos,
        manoObra,
        costoVidrios,
        loading,
        error,
    } = useCostos()

    const { calculatedCosts, groupedCosts } = useMemo(() => {
        const costs: CalculatedCost[] = []

        // Calcular costos para cada producto
        PRODUCTS.forEach((product) => {
            let mats: {
                id: string
                calc: (variables: any) => { value: number; formula: string }
            }[] = []
            if (product.id === 'puerta-lustrar') {
                mats = [
                    {
                        id: 'placaParaiso',
                        calc: (v) =>
                            calculateMaterialCosts.placaParaiso(v, margenes),
                    },
                    {
                        id: 'relleno',
                        calc: (v) =>
                            calculateMaterialCosts.relleno(v, margenes),
                    },
                    {
                        id: 'cantoParaiso',
                        calc: (v) =>
                            calculateMaterialCosts.cantoParaiso(v, margenes),
                    },
                    {
                        id: 'cemento',
                        calc: (v) =>
                            calculateMaterialCosts.cemento(v, margenes),
                    },
                    {
                        id: 'cola',
                        calc: (v) => calculateMaterialCosts.cola(v, margenes),
                    },
                ]
            } else if (product.id === 'puerta-pintar') {
                mats = [
                    {
                        id: 'placaCrudo',
                        calc: (v) =>
                            calculateMaterialCosts.placaCrudo(
                                v,
                                margenes,
                                puerta,
                            ),
                    },
                    {
                        id: 'cemento',
                        calc: (v) =>
                            calculateMaterialCosts.cemento(v, margenes),
                    },
                    {
                        id: 'cola',
                        calc: (v) => calculateMaterialCosts.cola(v, margenes),
                    },
                ]
            } else if (product.id === 'terminacion-lustre') {
                mats = [
                    {
                        id: 'thiner',
                        calc: (v) => calculateMaterialCosts.thiner(v, margenes),
                    },
                    {
                        id: 'lustre',
                        calc: (v) => calculateMaterialCosts.lustre(v, margenes),
                    },
                    {
                        id: 'lijas',
                        calc: (v) => calculateMaterialCosts.lijas(v, margenes),
                    },
                    {
                        id: 'estopa',
                        calc: (v) => calculateMaterialCosts.estopa(v, margenes),
                    },
                ]
            } else if (product.id === 'terminacion-hidrolaqueado') {
                mats = [
                    {
                        id: 'baseGris',
                        calc: (v) =>
                            calculateMaterialCosts.baseGris(v, margenes),
                    },
                    {
                        id: 'pinturaBlanca',
                        calc: (v) =>
                            calculateMaterialCosts.pinturaBlanca(v, margenes),
                    },
                    {
                        id: 'thiner',
                        calc: (v) => calculateMaterialCosts.thiner(v, margenes),
                    },
                    {
                        id: 'lijas',
                        calc: (v) => calculateMaterialCosts.lijas(v, margenes),
                    },
                ]
            } else if (product.id === 'marco') {
                mats = [
                    {
                        id: 'paraisoMarco',
                        calc: (v) =>
                            calculateMaterialCosts.paraisoMarco(v, margenes),
                    },
                    {
                        id: 'burlete',
                        calc: (v) =>
                            calculateMaterialCosts.burlete(v, margenes),
                    },
                    {
                        id: 'tableroEuca',
                        calc: (v) =>
                            calculateMaterialCosts.tableroEuca(v, margenes),
                    },
                    {
                        id: 'cantoMarco',
                        calc: (v) =>
                            calculateMaterialCosts.cantoMarco(v, margenes),
                    },
                ]
            }
            // Solo pushear si no existe ya ese material para ese producto
            mats.forEach(({ id, calc }, idx) => {
                const { value, formula } = calc(variablesPredefinidas)

                if (
                    value > 0 &&
                    !costs.some(
                        (c) =>
                            c.materialId === id &&
                            c.isVariable &&
                            c.label ===
                                (MATERIALS.find((m) => m.id === id)?.label ||
                                    id),
                    )
                ) {
                    costs.push({
                        label: MATERIALS.find((m) => m.id === id)?.label || id,
                        value,
                        formula,
                        materialId: id,
                        order: idx + 2,
                        isVariable: true,
                    })
                }
            })
            const laborCost = calculateLaborCosts(
                manoObra,
                costosFijos,
                parametros,
                margenes,
            )
        })

        // Group costs by product
        const grouped = PRODUCTS.map((product) => {
            // Solo los costos de los materiales relevantes para el producto
            const productMaterialIds = MATERIALS.filter((m) =>
                m.products.includes(product.id),
            ).map((m) => m.id)
            // Solo un costo por materialId y tipo (fijo/variable)
            const productCosts: CalculatedCost[] = []
            productMaterialIds.forEach((materialId) => {
                const fixed = costs.find(
                    (c) => c.materialId === materialId && c.isFixed,
                )
                if (fixed) productCosts.push(fixed)
                const variable = costs.find(
                    (c) => c.materialId === materialId && c.isVariable,
                )
                if (variable) productCosts.push(variable)
            })
            const total = productCosts.reduce(
                (sum, cost) => sum + cost.value,
                0,
            )

            return {
                product,
                costs: productCosts,
                total,
            }
        })

        return { calculatedCosts: costs, groupedCosts: grouped }
    }, [variablesPredefinidas, manoObra, costosFijos, parametros, puerta])

    return {
        calculateMaterialCosts,
        calculatedCosts,
        groupedCosts,
        products: PRODUCTS,
        materials: MATERIALS,
        loading,
        error,
        variablesPredefinidas,
        margenes,
    }
}

import { useState, useEffect, useCallback } from 'react'
import { useSelector } from 'react-redux'
import { RootState } from '@/store/rootReducer'
import { apiGetClients } from '@/services/ClientService'
import { Client } from '@/@types/clientInfo'

export const useClients = () => {
    const [clients, setClients] = useState<Client[]>([])
    const [loading, setLoading] = useState<boolean>(true)
    const [expanded, setExpanded] = useState<{ [key: string]: boolean }>({})

    const { currentBusinessUnit } = useSelector(
        (state: RootState) => state.businessUnit.data
    )

    const fetchClientData = useCallback(async () => {
        // Los clientes deben estar asociados a una unidad de negocio
        if (!currentBusinessUnit?._id) {
            setClients([])
            setLoading(false)
            return
        }

        try {
            setLoading(true)
            const resp = await apiGetClients<{ clientes: any[] }>({ 
                unidadNegocio: currentBusinessUnit._id 
            })
            
            if (resp.data && resp.data.clientes) {
                setClients(resp.data.clientes)
            }
        } catch (error) {
            console.error('Error fetching clients:', error)
        } finally {
            setLoading(false)
        }
    }, [currentBusinessUnit?._id])

    useEffect(() => {
        fetchClientData()
    }, [fetchClientData])

    const toggleExpand = useCallback((_id: string) => {
        setExpanded((prevState) => ({
            ...prevState,
            [_id]: !prevState[_id],
        }))
    }, [])

    return {
        clients,
        loading,
        expanded,
        toggleExpand,
        fetchClients: fetchClientData,
    }
}

import { useMemo } from 'react'
import {
    useCalculatedCosts,
    calculateLaborCosts,
    costoMarco,
    costoAplique,
    costoVidrio,
    costoInsumosColocacion,
} from './useCalculatedCosts'
import { Puerta } from '@/@types/presupuesto'
import { marcos } from '@/constants/presupuestos.constant'
import { useCostos } from './useCostos'

export const useDoorCost = (puerta: Puerta) => {
    const {
        variablesPredefinidas,
        margenes,
        parametros,
        costosFijos,
        manoObra,
        costoVidrios,
        loading: costosLoading,
        error: costosError,
    } = useCostos()

    const {
        groupedCosts,
        loading: calculatedLoading,
        error: calculatedError,
    } = useCalculatedCosts(puerta)

    const loading = costosLoading || calculatedLoading
    const error = costosError || calculatedError

    const laborCosts = useMemo(() => {
        return calculateLaborCosts(manoObra, costosFijos, parametros, margenes)
    }, [manoObra, costosFijos, parametros, margenes])

    const doorCost = useMemo(() => {
        if (loading || error || !puerta) return null

        //Margenes
        const PtaPpal = margenes?.PtaPpal ? margenes.PtaPpal : 0
        const BenMarco = margenes?.Marco ? margenes.Marco : 0
        const BenHoja = margenes?.Hoja ? margenes.Hoja : 0
        const BenLustre = margenes?.Lustre ? margenes.Lustre : 0
        const BenVidrio = margenes?.Vidrio ? margenes.Vidrio : 0
        const BenColocacion = margenes?.Colocacion ? margenes.Colocacion : 0

        //Parametros
        const frameLenght = puerta.Ancho / 1000 + 2 * (puerta.Alto / 1000)
        const frameLenghtCorrediza =
            2 * (puerta.Ancho / 1000) + 3 * (puerta.Alto / 1000)
        const esMayor = puerta.Alto >= 2300
        const esDoble = puerta.Hoja === 'Doble'
        const lustrada = puerta.Terminacion === 'Lustrado'
        const laqueada = puerta.Terminacion === 'Laqueado'
        const molduras = puerta.Apliques === 'Molduras'
        const alistonado = puerta.Apliques === 'Revestimiento alistonado euca'
        const esCorrediza = puerta.Corrediza === true
        const extraComplex = puerta.ComplejidadExtra
            ? puerta.ComplejidadExtra / 100
            : 0
        const sinColocacion = puerta.SinColocacion
        const SinTerminacion = puerta.SinTerminacion
        const puertaPpal = puerta.PuertaPrincipal
        const suplemento = marcos.find((m) => m.value === '2x2')
        if (!suplemento) return null
        const suplementoCost = costoMarco(
            variablesPredefinidas,
            margenes,
            suplemento.anchoCm / 100,
            0,
        ).value
        const suplementoArea =
            (puerta.Ancho / 1000) * (suplemento.anchoCm / 100)
        const doorArea =
            (puerta.Ancho / 1000) * (puerta.Alto / 1000) - suplementoArea
        const doorTotalArea = doorArea + suplementoArea

        const vidrioSeleccionado = puerta.Vidrio
        const vidrioCodigo = vidrioSeleccionado.Codigo || ''
        const vidrioCantidad = vidrioSeleccionado.Cantidad || 0
        const vidrioArea =
            (vidrioSeleccionado.Ancho / 1000) *
                (vidrioSeleccionado.Alto / 1000) || 0
        const vidrioML =
            (vidrioSeleccionado.Ancho / 1000) * 2 +
                (vidrioSeleccionado.Alto / 1000) * 2 || 0

        const insumosColocacion =
            costoInsumosColocacion(variablesPredefinidas).value * frameLenght

        let finishCosts
        if (lustrada) {
            finishCosts = groupedCosts.find(
                (group) => group.product.id === 'terminacion-lustre',
            )
        } else if (laqueada) {
            finishCosts = groupedCosts.find(
                (group) => group.product.id === 'terminacion-hidrolaqueado',
            )
        }
        if (!finishCosts) return null

        let productCosts
        if (lustrada) {
            productCosts = groupedCosts.find(
                (group) => group.product.id === 'puerta-lustrar',
            )
        } else if (laqueada) {
            productCosts = groupedCosts.find(
                (group) => group.product.id === 'puerta-pintar',
            )
        }
        if (!productCosts) return null

        //Calculo de costo del marco
        const marcoSeleccionado = marcos.find((m) => m.value === puerta.Marco)
        const areaMarco = marcoSeleccionado?.areaDeLustreCm || 0

        const marcoCost = marcoSeleccionado
            ? costoMarco(
                  variablesPredefinidas,
                  margenes,
                  marcoSeleccionado.anchoCm / 100,
                  0,
              ).value *
              (esCorrediza ? frameLenghtCorrediza : frameLenght) *
              (extraComplex ? 1 + extraComplex : 1) *
              (puertaPpal ? 1 + PtaPpal : 1) *
              (1 + BenMarco)
            : 0

        //Calcular costo de Paño Fijo
        const pañoFijoCost = puerta.PañoFijo.reduce((total, paño) => {
            const PFLenght = 2 * (paño.Ancho / 1000) + 2 * (puerta.Alto / 1000)
            const PFArea = (paño.Ancho / 1000) * (puerta.Alto / 1000)
            const ciego = paño.Vidrio === 'Sin Vidrio'

            const vidrioCodigo = paño.Vidrio

            let costoVidrioPF = 0
            if (ciego) {
                costoVidrioPF = productCosts.costs.reduce(
                    (sum: any, cost: any) => {
                        const costValue = cost.isFixed
                            ? cost.value
                            : cost.value * PFArea * (1 + BenHoja)

                        return sum + costValue
                    },
                    0,
                )
            } else {
                costoVidrioPF =
                    costoVidrio(
                        costoVidrios,
                        PFArea,
                        PFLenght,
                        vidrioCodigo,
                        vidrioCantidad,
                    ).value *
                    (1 + BenVidrio)
            }

            const costoMarcoPF = marcoSeleccionado
                ? costoMarco(
                      variablesPredefinidas,
                      margenes,
                      marcoSeleccionado.anchoCm / 100,
                      0,
                  ).value *
                      PFLenght *
                      (extraComplex ? 1 + extraComplex : 1) *
                      (puertaPpal ? 1 + PtaPpal : 1) *
                      (1 + BenMarco) +
                  laborCosts.costoFabricacionMarco * PFLenght
                : 0

            let costoTerminaciónPF = 0
            if (ciego) {
                costoTerminaciónPF =
                    (finishCosts.costs.reduce((sum: any, cost: any) => {
                        return sum + cost.value * doorTotalArea
                    }, 0) +
                        laborCosts.costoLustradoHoja * PFArea +
                        finishCosts.costs.reduce((sum: any, cost: any) => {
                            return (
                                sum + cost.value * (areaMarco / 100) * PFLenght
                            )
                        }, 0) +
                        laborCosts.costoLustradoMarco *
                            (areaMarco / 100) *
                            PFLenght) *
                    (1 + BenLustre)
            } else {
                costoTerminaciónPF =
                    (finishCosts.costs.reduce((sum: any, cost: any) => {
                        return sum + cost.value * (areaMarco / 100) * PFLenght
                    }, 0) +
                        laborCosts.costoLustradoMarco *
                            (areaMarco / 100) *
                            PFLenght) *
                    (1 + BenLustre)
            }

            const costoTJ = costoMarcoPF * 0.2

            const colocacionPF = ciego
                ? laborCosts.costoColocacionMarco +
                  laborCosts.costoColocacionHoja
                : laborCosts.costoColocacionMarco

            const costo =
                (costoMarcoPF +
                    costoVidrioPF +
                    costoTerminaciónPF +
                    costoTJ +
                    colocacionPF) *
                (extraComplex ? 1 + extraComplex : 1) *
                (sinColocacion ? 0 : 1) *
                (1 + BenColocacion)

            return total + costo
        }, 0)

        //Calcular costo de las tapajuntas
        const tapajuntas = marcoCost * 0.2 * (puertaPpal ? 1 + PtaPpal : 1)

        //Calculo de costo de la hoja
        const hojaCost =
            (productCosts.costs.reduce((sum, cost) => {
                const costValue = cost.value * doorArea

                return sum + costValue
            }, 0) +
                suplementoCost *
                    (puerta.Ancho / 1000) *
                    (extraComplex ? 1 + extraComplex : 1) *
                    (puertaPpal ? 1 + PtaPpal : 1)) *
            (1 + BenHoja)

        //Calculo de costo de los apliques
        let apliqueCost = 0
        if (molduras) {
            apliqueCost = hojaCost * 0.2
        } else if (alistonado) {
            apliqueCost =
                costoAplique(variablesPredefinidas, margenes).value *
                doorArea *
                (extraComplex ? 1 + extraComplex : 1) *
                (1 + BenHoja)
        }

        if (!productCosts) return null

        //Calculo de costo de terminación
        const terminacionHojaCost = finishCosts.costs.reduce((sum, cost) => {
            return sum + cost.value * doorTotalArea * 2
        }, 0)

        const terminacionMarcoCost = finishCosts.costs.reduce((sum, cost) => {
            return sum + cost.value * (areaMarco / 100) * frameLenght
        }, 0)

        let MOLustre = 0
        if (lustrada) {
            MOLustre =
                laborCosts.costoLustradoHoja * (apliqueCost !== 0 ? 2 : 1) +
                +laborCosts.costoLustradoMarco
        } else if (laqueada) {
            MOLustre =
                laborCosts.costoPintadoHoja * (apliqueCost !== 0 ? 2 : 1) +
                +laborCosts.costoPintadoMarco
        }

        const terminacionTotal =
            (terminacionHojaCost + terminacionMarcoCost + MOLustre) *
            (1 + BenLustre)

        // Calcular costos de fabricación
        let fabricacionTotal = 0
        fabricacionTotal +=
            ((laborCosts.costoFabricacionHoja +
                laborCosts.costoFabricacionMarco) *
                (extraComplex ? 1 + extraComplex : 1) +
                (esDoble ? laborCosts.costoFabricacionBoca : 0) +
                (molduras || alistonado
                    ? laborCosts.costoFabricacionHoja * 0.2
                    : 0)) *
            (1 + BenColocacion)

        // Calcular costos de colocación en obra
        let colocacion =
            (laborCosts.costoColocacionHoja +
                laborCosts.costoColocacionMarco +
                insumosColocacion) *
            (extraComplex ? 1 + extraComplex : 1) *
            (sinColocacion ? 0 : 1) *
            (1 + BenColocacion)

        //Calcular costo de vidrio
        const vidrioCost = vidrioSeleccionado
            ? costoVidrio(
                  costoVidrios,
                  vidrioArea,
                  vidrioML,
                  vidrioCodigo,
                  vidrioCantidad,
              ).value *
              (1 + BenVidrio)
            : 0

        const totalCost =
            hojaCost +
            apliqueCost +
            marcoCost +
            tapajuntas +
            terminacionTotal +
            fabricacionTotal +
            colocacion +
            vidrioCost +
            pañoFijoCost

        return {
            hojaCost,
            apliqueCost,
            marcoCost,
            tapajuntas,
            terminacionHojaCost,
            terminacionMarcoCost,
            terminacionTotal,
            fabricacionTotal,
            colocacion,
            vidrioCost,
            pañoFijoCost,
            totalCost,
            doorArea,
        }
    }, [
        puerta,
        groupedCosts,
        loading,
        error,
        variablesPredefinidas,
        margenes,
        laborCosts,
    ])

    return {
        doorCost,
        loading,
        error,
    }
}

import { useState, useEffect } from 'react'
import { fetchIncomes } from '@/api/api'

interface User {
    email: string
    invites: Invite[]
}

interface Invite {
    email: string
    _id: string
}

interface Income {
    _id: string
    categoria: string
    subCategoria: string
    divisa: string
    monto: number
    repetir: string
    fechaPago: Date
    comentarios: string
}

const useFetchUserIncomes = () => {
    const [incomes, setIncomes] = useState<Income[]>([])

    useEffect(() => {
        const fetchUserIncomes = async (
            userEmail: string,
        ): Promise<Income[]> => {
            try {
                const incomesData = await fetchIncomes(userEmail)
                return Array.isArray(incomesData)
                    ? incomesData
                    : incomesData.ingresos || []
            } catch (error) {
                console.error('Error fetching incomes:', error)
                return []
            }
        }

        const fetchDataForUser = async (email: string) => {
            const userIncomes = await fetchUserIncomes(email)
            return userIncomes
        }

        const fetchIncomesData = async () => {
            const user: User = JSON.parse(localStorage.getItem('user') || '{}')

            const allIncomes: Income[] = []

            const userIncomes = await fetchDataForUser(user.email)
            allIncomes.push(...userIncomes)

            setIncomes(allIncomes)
        }

        fetchIncomesData()
    }, [])

    return incomes
}

export default useFetchUserIncomes

import { useState, useEffect, useMemo } from 'react'
import { Project } from '@/@types/project'
import { Pedido } from '@/@types/pedidos'
import { fetchPedidos } from '@/api/api'
import { normalizeProgress } from '@/utils/projectUtils'

export const useProjectDashboard = (project: Project | null, isOpen: boolean) => {
    const [pedidos, setPedidos] = useState<Pedido[]>([])
    const [loadingPedidos, setLoadingPedidos] = useState(false)

    useEffect(() => {
        if (isOpen && project?._id) {
            const loadData = async () => {
                setLoadingPedidos(true)
                try {
                    const response = await fetchPedidos({ proyecto: project._id })
                    if (response.ok) {
                        setPedidos(response.pedidos)
                    }
                } catch (error) {
                    console.error('Error fetching dashboard data:', error)
                } finally {
                    setLoadingPedidos(false)
                }
            }
            loadData()
        }
    }, [isOpen, project?._id])

    const dashboardLogic = useMemo(() => {
        if (!project) return { chartData: [], projectStatus: null, nowTs: Date.now() }
        
        const now = new Date().getTime()
        const startDate = project.fechaInicio ? new Date(project.fechaInicio).getTime() : (project.fechaCreacion ? new Date(project.fechaCreacion).getTime() : now - (86400000 * 7))
        
        const idealMilestones = [{ timestamp: startDate, ideal: 0 }]
        let cumulativeWeight = 0
        const sortedStages = [...project.etapas].sort((a, b) => {
            const da = a.deadline ? new Date(a.deadline).getTime() : Infinity
            const db = b.deadline ? new Date(b.deadline).getTime() : Infinity
            return da - db
        })

        sortedStages.forEach(stage => {
            if (stage.subetapas && stage.subetapas.length > 0) {
                const subWeight = stage.peso / stage.subetapas.length
                const sortedSubs = [...stage.subetapas].sort((a, b) => {
                    const da = a.deadline ? new Date(a.deadline).getTime() : Infinity
                    const db = b.deadline ? new Date(b.deadline).getTime() : Infinity
                    return da - db
                })

                sortedSubs.forEach((sub) => {
                    cumulativeWeight += subWeight
                    if (sub.deadline) {
                        idealMilestones.push({
                            timestamp: new Date(sub.deadline).getTime(),
                            ideal: cumulativeWeight
                        })
                    }
                })
            } else {
                cumulativeWeight += stage.peso
                if (stage.deadline) {
                    idealMilestones.push({ 
                        timestamp: new Date(stage.deadline).getTime(), 
                        ideal: cumulativeWeight 
                    })
                }
            }
        })

        if (idealMilestones.length === 1 && project.deadline) {
            idealMilestones.push({ timestamp: new Date(project.deadline).getTime(), ideal: 100 })
        } else if (cumulativeWeight < 100 && project.deadline) {
            idealMilestones.push({ timestamp: new Date(project.deadline).getTime(), ideal: 100 })
        }

        const realEvents: { timestamp: number, contribution: number }[] = []
        project.etapas.forEach(stage => {
            if (stage.subetapas && stage.subetapas.length > 0) {
                stage.subetapas.forEach(sub => {
                    if (sub.avance > 0 && sub.fechaActualizacion) {
                        realEvents.push({
                            timestamp: new Date(sub.fechaActualizacion).getTime(),
                            contribution: (stage.peso * (sub.avance / 100)) / stage.subetapas.length
                        })
                    }
                })
            } else if (stage.avance > 0 && stage.fechaActualizacion) {
                realEvents.push({
                    timestamp: new Date(stage.fechaActualizacion).getTime(),
                    contribution: stage.peso * (stage.avance / 100)
                })
            }
        })

        realEvents.sort((a, b) => a.timestamp - b.timestamp)

        const allTimestamps = Array.from(new Set([
            startDate,
            now,
            ...idealMilestones.map(m => m.timestamp),
            ...realEvents.map(e => e.timestamp)
        ])).sort((a, b) => a - b)

        const finalData = allTimestamps.map(ts => {
            let ideal = 0
            for (let i = 0; i < idealMilestones.length - 1; i++) {
                const m1 = idealMilestones[i]; const m2 = idealMilestones[i+1]
                if (ts >= m1.timestamp && ts <= m2.timestamp) {
                    const ratio = (ts - m1.timestamp) / (m2.timestamp - m1.timestamp)
                    ideal = m1.ideal + (m2.ideal - m1.ideal) * ratio
                    break
                }
                if (ts > m2.timestamp) ideal = m2.ideal
            }
            if (ts > idealMilestones[idealMilestones.length-1].timestamp) ideal = 100

            let real = 0
            realEvents.forEach(e => {
                if (e.timestamp <= ts) real += e.contribution
            })

            return {
                timestamp: ts,
                ideal: Math.round(ideal * 10) / 10,
                real: Math.round(real * 10) / 10,
            }
        })

        const currentReal = normalizeProgress(project.avance)
        
        let currentIdeal = 0
        for (let i = 0; i < idealMilestones.length - 1; i++) {
            const m1 = idealMilestones[i]; const m2 = idealMilestones[i+1]
            if (now >= m1.timestamp && now <= m2.timestamp) {
                const ratio = (now - m1.timestamp) / (m2.timestamp - m1.timestamp)
                currentIdeal = m1.ideal + (m2.ideal - m1.ideal) * ratio
                break
            }
            if (now > m2.timestamp) currentIdeal = m2.ideal
        }
        if (now > idealMilestones[idealMilestones.length-1].timestamp) currentIdeal = 100

        const gap = currentReal - currentIdeal
        
        return { 
            chartData: finalData, 
            projectStatus: {
                gap: gap,
                isAhead: gap >= 0,
                idealToday: Math.round(currentIdeal),
                realToday: Math.round(currentReal)
            },
            nowTs: now
        }
    }, [project?.etapas, project?.avance, project?.fechaInicio, project?.deadline])

    return {
        ...dashboardLogic,
        pedidos,
        loadingPedidos
    }
}

import { useState, useEffect, useCallback } from 'react'
import { fetchUsers } from '@/api/api'

export const useUsers = () => {
    const [users, setUsers] = useState<any[]>([])
    const [loading, setLoading] = useState<boolean>(true)

    const fetchUsersData = useCallback(async () => {
        try {
            setLoading(true)
            const response = await fetchUsers()
            if (response) {
                // Backend might return { usuarios: [...] } or direct array
                setUsers(response.usuarios || (Array.isArray(response) ? response : []))
            }
        } catch (error) {
            console.error('Error fetching users:', error)
        } finally {
            setLoading(false)
        }
    }, [])

    useEffect(() => {
        fetchUsersData()
    }, [fetchUsersData])

    return {
        users,
        loading,
        fetchUsers: fetchUsersData,
    }
}

import { useState, useEffect } from 'react'
import { fetchIncomes } from '@/api/api'

interface User {
    email: string
    invites: Invite[]
}

interface Invite {
    email: string
    _id: string
}

interface Income {
    _id: string
    categoria: string
    subCategoria: string
    divisa: string
    monto: number
    repetir: string
    fechaPago: Date
    comentarios: string
}

const useFetchAllIncomes = () => {
    const [incomes, setIncomes] = useState<Income[]>([])

    useEffect(() => {
        const fetchUserIncomes = async (
            userEmail: string,
        ): Promise<Income[]> => {
            try {
                const incomesData = await fetchIncomes(userEmail)
                return Array.isArray(incomesData)
                    ? incomesData
                    : incomesData.ingresos || []
            } catch (error) {
                console.error('Error fetching incomes:', error)
                return []
            }
        }

        const fetchDataForUser = async (email: string) => {
            const userIncomes = await fetchUserIncomes(email)
            return userIncomes
        }

        const fetchIncomesData = async () => {
            const user: User = JSON.parse(localStorage.getItem('user') || '{}')
            const invData = user.invites || []

            const allIncomes: Income[] = []

            for (const invite of invData) {
                if (invite.email) {
                    const userIncomes = await fetchDataForUser(invite.email)
                    allIncomes.push(...userIncomes)
                }
            }

            const userIncomes = await fetchDataForUser(user.email)
            allIncomes.push(...userIncomes)

            setIncomes(allIncomes)
        }

        fetchIncomesData()
    }, [])

    return incomes
}

export default useFetchAllIncomes

export const normalizeProgress = (val: number) => {
    if (!val) return 0
    return (val > 0 && val <= 1) ? val * 100 : val
}

export const getProgressClasses = (percent: number) => {
    const p = normalizeProgress(percent)
    if (p >= 100) return { border: 'border-t-green-500', text: 'text-green-600', ring: 'focus:ring-green-500', bg: 'bg-green-500' }
    if (p >= 75) return { border: 'border-t-emerald-500', text: 'text-emerald-600', ring: 'focus:ring-emerald-500', bg: 'bg-emerald-500' }
    if (p >= 50) return { border: 'border-t-blue-500', text: 'text-blue-600', ring: 'focus:ring-blue-500', bg: 'bg-blue-500' }
    if (p >= 25) return { border: 'border-t-orange-500', text: 'text-orange-600', ring: 'focus:ring-orange-500', bg: 'bg-orange-500' }
    return { border: 'border-t-red-500', text: 'text-red-600', ring: 'focus:ring-red-500', bg: 'bg-red-500' }
}

export const getClientName = (client: any) => {
    if (!client) return 'Sin Cliente'
    if (typeof client === 'string') return client
    if (client.tipoCliente === 'Empresa') return client.razonSocial
    return `${client.nombre || ''} ${client.apellido || ''}`.trim()
}

export const getResponsableName = (resp: any) => {
    if (!resp) return 'Sin Asignar'
    if (typeof resp === 'string') return resp
    return `${resp.nombre || ''} ${resp.apellido || ''}`.trim()
}

export const getStatusColor = (status?: string) => {
    switch (status) {
        case 'Planificacion':
            return 'bg-gray-100 text-gray-700'
        case 'En_curso':
            return 'bg-blue-100 text-blue-700'
        case 'Pausado':
            return 'bg-amber-100 text-amber-700'
        case 'Completado':
            return 'bg-emerald-100 text-emerald-700'
        case 'Cancelado':
            return 'bg-red-100 text-red-700'
        default:
            return 'bg-blue-100 text-blue-700'
    }
}

import { useSelector } from 'react-redux'
import { RootState } from '@/store/rootReducer'
import DashboardHeader from '@/components/template/HomeView/DashboardHeader'
import StatisticCard from '@/components/template/HomeView/StatisticCard'
import MainChartCard from '@/components/template/HomeView/MainChartCard'
import SalesSideCard from '@/components/template/HomeView/SalesSideCard'
import { 
    HiOutlineCurrencyDollar, 
    HiOutlineUsers, 
    HiOutlineBriefcase, 
    HiOutlineChartBar 
} from 'react-icons/hi'
import { useClients } from '@/utils/hooks/useClients'
import formatCurrency from '@/utils/hooks/formatCurrency'
import { useMemo } from 'react'

const Home = () => {
    const { currentBusinessUnit } = useSelector(
        (state: RootState) => state.businessUnit.data
    )

    const { clients, loading } = useClients()

    // Cálculos de estadísticas
    const stats = useMemo(() => {
        if (!clients || clients.length === 0) return null

        const allPresupuestos = clients.flatMap(c => c.Presupuestos || [])
        const allPagos = allPresupuestos.flatMap(p => p.pagos || [])

        const totalPresupuestos = allPresupuestos.length
        const aprobados = allPresupuestos.filter(p => p.estado === 'Aprobado').length
        const pendientes = allPresupuestos.filter(p => p.estado === 'Pendiente').length
        
        const totalVentas = allPresupuestos.filter(p => p.estado === 'Aprobado').reduce((sum, p) => sum + (p.total || 0), 0)
        const totalCobrado = allPagos.reduce((sum, p) => sum + (p.monto || 0), 0)
        const deudaTotal = totalVentas - totalCobrado

        const conversionRate = totalPresupuestos > 0 ? (aprobados / totalPresupuestos) * 100 : 0
        
        const clientesActivos = clients.filter(c => c.estado === 'Activo').length
        const totalClientes = clients.length

        return {
            presupuestos: {
                label: `${aprobados}/${totalPresupuestos}`,
                pending: pendientes,
                total: totalPresupuestos,
                percent: totalPresupuestos > 0 ? Math.round((aprobados / totalPresupuestos) * 100) : 0
            },
            clientes: {
                label: `${clientesActivos}/${totalClientes}`,
                active: clientesActivos,
                total: totalClientes,
                percent: totalClientes > 0 ? Math.round((clientesActivos / totalClientes) * 100) : 0
            },
            financiero: {
                ventas: totalVentas,
                cobrado: totalCobrado,
                deuda: deudaTotal,
                debtPercent: totalVentas > 0 ? Math.round((deudaTotal / totalVentas) * 100) : 0
            },
            conversion: {
                rate: conversionRate.toFixed(2),
                percent: Math.round(conversionRate)
            }
        }
    }, [clients])

    return (
        <div className="flex flex-col gap-4 p-2 md:p-4 animate-fade-in">
            <DashboardHeader />
            
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-4">
                <StatisticCard 
                    title="Presupuestos"
                    value={stats?.presupuestos.label || '0/0'}
                    subtitle="Presupuestos Aprobados"
                    progressLabel="Pendientes de Aprobación"
                    progressValue={String(stats?.presupuestos.pending || 0)}
                    progressPercent={stats?.presupuestos.percent || 0}
                    icon={<HiOutlineBriefcase />}
                    progressColor="bg-blue-600"
                />
                <StatisticCard 
                    title="Clientes"
                    value={stats?.clientes.label || '0/0'}
                    subtitle="Clientes Activos"
                    progressLabel="Fidelización"
                    progressValue={`${stats?.clientes.active || 0} Activos`}
                    progressPercent={stats?.clientes.percent || 0}
                    icon={<HiOutlineUsers />}
                    progressColor="bg-amber-500"
                />
                <StatisticCard 
                    title="Cobranzas"
                    value={formatCurrency(stats?.financiero.cobrado || 0)}
                    subtitle="Total Cobrado"
                    progressLabel="Deuda Pendiente"
                    progressValue={formatCurrency(stats?.financiero.deuda || 0)}
                    progressPercent={stats?.financiero.debtPercent || 0}
                    icon={<HiOutlineCurrencyDollar />}
                    progressColor="bg-rose-500"
                />
                <StatisticCard 
                    title="Conversión"
                    value={`${stats?.conversion.rate || 0}%`}
                    subtitle="Tasa de Cierre"
                    progressLabel="Efectividad Ventas"
                    progressValue={formatCurrency(stats?.financiero.ventas || 0)}
                    progressPercent={stats?.conversion.percent || 0}
                    icon={<HiOutlineChartBar />}
                    progressColor="bg-emerald-500"
                />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-4">
                <div className="lg:col-span-8 flex">
                    <div className="w-full">
                        <MainChartCard clients={clients} />
                    </div>
                </div>
                <div className="lg:col-span-4 flex">
                    <div className="w-full">
                        <SalesSideCard clients={clients} />
                    </div>
                </div>
            </div>
            
            <div className="mt-8 py-4 border-t border-gray-100 dark:border-gray-800 flex items-center justify-between text-gray-400 text-xs">
                <span>Sesión activa en: <strong className="text-gray-600 dark:text-gray-300 uppercase">{currentBusinessUnit?.nombre || 'Sin Unidad Seleccionada'}</strong></span>
                <span>© {new Date().getFullYear()} EDGE RealState System</span>
            </div>
        </div>
    )
}

export default Home

import Input from '@/components/ui/Input'
import Button from '@/components/ui/Button'
import Checkbox from '@/components/ui/Checkbox'
import { FormItem, FormContainer } from '@/components/ui/Form'
import Alert from '@/components/ui/Alert'
import PasswordInput from '@/components/shared/PasswordInput'
import ActionLink from '@/components/shared/ActionLink'
import useTimeOutMessage from '@/utils/hooks/useTimeOutMessage'
import useAuth from '@/utils/hooks/useAuth'
import { Field, Form, Formik } from 'formik'
import * as Yup from 'yup'
import type { CommonProps } from '@/@types/common'

interface SignInFormProps extends CommonProps {
    disableSubmit?: boolean
    forgotPasswordUrl?: string
    signUpUrl?: string
}

type SignInFormSchema = {
    email: string
    password: string
    rememberMe: boolean
}

const validationSchema = Yup.object().shape({
    email: Yup.string().required('Por favor, ingrese su correo electrónico'),
    password: Yup.string().required('Por favor, ingrese su contraseña'),
    rememberMe: Yup.bool(),
})

interface User {
    email: string
    password: string
}

const SignInForm = (props: SignInFormProps) => {
    const {
        disableSubmit = false,
        className,
        forgotPasswordUrl = '/forgot-password',
        signUpUrl = '/sign-up',
    } = props

    const [message, setMessage] = useTimeOutMessage()

    const { signIn } = useAuth()

    const onSignIn = async (
        values: SignInFormSchema,
        setSubmitting: (isSubmitting: boolean) => void,
    ) => {
        const { email, password } = values
        setSubmitting(true)

        const result = await signIn({ email, password })

        if (result?.status === 'failed') {
            setMessage(result.message)
        }

        setSubmitting(false)
    }

    return (
        <div className={className}>
            {message && (
                <Alert showIcon className="mb-4" type="danger">
                    <>{message}</>
                </Alert>
            )}
            <Formik
                initialValues={{
                    email: '',
                    password: '',
                    rememberMe: true,
                }}
                validationSchema={validationSchema}
                onSubmit={(values, { setSubmitting }) => {
                    if (!disableSubmit) {
                        onSignIn(values, setSubmitting)
                    } else {
                        setSubmitting(false)
                    }
                }}
            >
                {({ touched, errors, isSubmitting }) => (
                    <Form>
                        <FormContainer>
                            <FormItem
                                label="Correo Electrónico"
                                invalid={
                                    (errors.email && touched.email) as boolean
                                }
                                errorMessage={errors.email}
                            >
                                <Field
                                    type="text"
                                    autoComplete="off"
                                    name="email"
                                    placeholder="Correo Electrónico"
                                    component={Input}
                                />
                            </FormItem>
                            <FormItem
                                label="Contraseña"
                                invalid={
                                    (errors.password &&
                                        touched.password) as boolean
                                }
                                errorMessage={errors.password}
                            >
                                <Field
                                    autoComplete="off"
                                    name="password"
                                    placeholder="Password"
                                    component={PasswordInput}
                                />
                            </FormItem>
                            <div className="flex justify-between mb-6">
                                <Field
                                    className="mb-0 mt-1"
                                    name="rememberMe"
                                    component={Checkbox}
                                >
                                    Recordarme
                                </Field>
                                <ActionLink className="mt-1" to={forgotPasswordUrl}>
                                    ¿Olvidaste tu contraseña?
                                </ActionLink>
                            </div>
                            <Button
                                block
                                loading={isSubmitting}
                                variant="solid"
                                type="submit"
                            >
                                {isSubmitting
                                    ? 'Iniciando sesión...'
                                    : 'Iniciar sesión'}
                            </Button>
                            {/* <div className="mt-4 text-center">
                                <span>{`¿Todavía no tienes una cuenta?`} </span>
                                <ActionLink to={signUpUrl}>
                                    Registrarse
                                </ActionLink>
                            </div> */}
                        </FormContainer>
                    </Form>
                )}
            </Formik>
        </div>
    )
}

export default SignInForm

