import React, { useState } from 'react'
import { Drawer, Switcher } from '@/components/ui'
import { HiOutlineDocumentPlus } from 'react-icons/hi2'
import { Project } from '@/@types/project'
import ProjectForm from '@/components/template/ProjectsView/Forms/ProjectForm'
import ProjectDashboardPanel from '@/components/template/ProjectsView/Dashboard/ProjectDashboardPanel'
import ProjectCardList from '@/components/template/ProjectsView/Lists/ProjectCardList'
import { useProjects } from '@/utils/hooks/useProjects'
import { useProjectActions } from '@/utils/hooks/useProjectActions'
import { useAppSelector } from '@/store'
import DividerMain from '@/components/template/DividerMain'
import { IconButton, Tooltip } from '@mui/material'
import { 
    normalizeProgress, 
    getProgressClasses, 
    getClientName, 
    getResponsableName,
    getStatusColor
} from '@/utils/projectUtils'

const ProjectsView = () => {
    const { projects, setProjects, loading, fetchProjects } = useProjects()
    const currentBusinessUnit = useAppSelector((state) => state.businessUnit.data.currentBusinessUnit)
    
    const [createDrawerOpen, setCreateDrawerOpen] = useState(false)
    const [dashboardOpen, setDashboardOpen] = useState(false)
    const [selectedProject, setSelectedProject] = useState<Project | null>(null)
    const [allProjects, setAllProjects] = useState(false)

    const { handleCreate, updateStageProgress, updateSubTaskProgress, updateProjectStatus } = useProjectActions(
        fetchProjects,
        setProjects,
        currentBusinessUnit?._id
    )

    const openDashboard = (project: Project) => {
        setSelectedProject(project)
        setDashboardOpen(true)
    }

    return (
        <div className="h-full">
            <div className="flex justify-between items-center">
                <div className="flex-col items-center">
                    <h3 className="section-title text-lg font-bold">Proyectos</h3>
                    <p className="text-gray-500 text-sm italic">Gestiona el avance de tus obras</p>
                </div>
            
                <div className="flex items-center">
                    <div className="flex mr-2 items-center">
                        <p className="mr-2 text-sm text-gray-500">Mostrar todos </p>
                        <Switcher 
                            checked={allProjects} 
                            onChange={(checked) => setAllProjects(checked)} 
                        />
                    </div>
                    <div className="">
                        <Tooltip title="Nuevo Proyecto" arrow>
                            <IconButton size="large" onClick={() => setCreateDrawerOpen(true)}>
                                <HiOutlineDocumentPlus className="theme-icon" />
                            </IconButton>
                        </Tooltip>
                    </div>
                </div>
            </div>
                    
            <DividerMain />
            
            
            <div className="mt-2">
            <ProjectCardList 
                projects={projects}
                onProjectClick={openDashboard}
                getProgressClasses={getProgressClasses}
                normalizeProgress={normalizeProgress}
                getClientName={getClientName}
                getResponsableName={getResponsableName}
                getStatusColor={getStatusColor}
                loading={loading}
                allProjects={allProjects}
                currentBusinessUnitId={currentBusinessUnit?._id}
            />
            </div>

            {/* Create Drawer */}
            <Drawer
                title="Nuevo Proyecto"
                isOpen={createDrawerOpen}
                onClose={() => setCreateDrawerOpen(false)}
                onRequestClose={() => setCreateDrawerOpen(false)}
                width={700}
            >
                <ProjectForm
                    initialValues={{}}
                    onSubmit={async (val, stages) => {
                        const success = await handleCreate(val, stages)
                        if (success) setCreateDrawerOpen(false)
                    }}
                    onCancel={() => setCreateDrawerOpen(false)}
                />
            </Drawer>

            {/* Dashboard Panel */}
            <ProjectDashboardPanel
                project={selectedProject}
                isOpen={dashboardOpen}
                onClose={() => setDashboardOpen(false)}
                onSubTaskUpdate={(stageId, subetapaId, completed) => 
                    updateSubTaskProgress(selectedProject!._id, stageId, subetapaId, completed, selectedProject, setSelectedProject)
                }
                onStageUpdate={(stageId, newAvance) => 
                    updateStageProgress(selectedProject!._id, stageId, newAvance, selectedProject, setSelectedProject)
                }
                onStatusUpdate={(newStatus: Project['estado']) => 
                    updateProjectStatus(selectedProject!._id, newStatus, selectedProject, setSelectedProject)
                }
                onProjectUpdate={() => fetchProjects(true)}
            />
        </div>
    )
}

export default ProjectsView

