import React, { useState, useEffect } from 'react'
import { Formik, Form, Field, FieldArray } from 'formik'
import * as Yup from 'yup'
import { Input, Button, Select, FormItem } from '@/components/ui'
import { HiPlus, HiTrash } from 'react-icons/hi'
import { Pedido, EstadoPedido } from '@/@types/pedidos'
import { fetchProjects } from '@/api/api'
import { Project } from '@/@types/project'

type FormProps = {
    initialValues: Partial<Pedido>
    onSubmit: (values: any) => void
    onCancel: () => void
}

const validationSchema = Yup.object().shape({
    numeroPedido: Yup.string().required('Requerido'),
    categoria: Yup.string().required('Requerido'),
    subcategoria: Yup.string().required('Requerido'),
    proyecto: Yup.string().required('Proyecto es requerido'),
    items: Yup.array().of(
        Yup.object().shape({
            descripcion: Yup.string().required('Requerido'),
            cantidad: Yup.number().min(0.01, 'Min 0.01').required('Requerido'),
            unidad: Yup.string().required('Requerido'),
        })
    )
})

const optionsEstado = Object.values(EstadoPedido).map((estado) => ({
    value: estado,
    label: estado,
}))

const categoryOptions = [
    { value: 'Obra Gruesa', label: 'Obra Gruesa' },
    { value: 'Instalaciones', label: 'Instalaciones' },
    { value: 'Aberturas', label: 'Aberturas' },
    { value: 'Terminaciones', label: 'Terminaciones' },
    { value: 'Herramientas', label: 'Herramientas' },
]

const subcategoryMapping: Record<string, { value: string, label: string }[]> = {
    'Obra Gruesa': [
        { value: 'Materiales de Corralón', label: 'Materiales de Corralón (Cemento, arena, ladrillos)' },
        { value: 'Hierro y Acero', label: 'Hierro y Acero Estructural' },
        { value: 'Hormigón Elaborado', label: 'Hormigón Elaborado' },
        { value: 'Aislaciones y Techados', label: 'Aislaciones y Techados' },
        { value: 'Madera para Encofrado', label: 'Madera para Encofrado' },
        { value: 'Otros', label: 'Otros' },
    ],
    'Instalaciones': [
        { value: 'Sanitaria', label: 'Sanitaria (Agua, Cloaca, Tanques)' },
        { value: 'Eléctrica', label: 'Eléctrica (Cables, Tableros, Cajas)' },
        { value: 'Gas', label: 'Gas (Cañerías, Llaves, Ventilación)' },
        { value: 'Climatización', label: 'Climatización (AA, Calefacción)' },
        { value: 'Seguridad', label: 'Seguridad e Incendio' },
        { value: 'Otros', label: 'Otros' },
    ],
    'Aberturas': [
        { value: 'Perfiles', label: 'Perfiles de Aluminio/PVC' },
        { value: 'Herrajes', label: 'Herrajes y Accesorios' },
        { value: 'Vidrios', label: 'Vidrios y DVH' },
        { value: 'Puertas de Interior', label: 'Puertas de Interior' },
        { value: 'Puertas Exteriores', label: 'Puertas Exteriores y Portones' },
        { value: 'Otros', label: 'Otros' },
    ],
    'Terminaciones': [
        { value: 'Pisos y Revestimientos', label: 'Pisos y Revestimientos' },
        { value: 'Pinturas', label: 'Pinturas y Enduídos' },
        { value: 'Cielorrasos', label: 'Cielorrasos (Durlock, Yeso)' },
        { value: 'Griferías y Sanitarios', label: 'Griferías y Sanitarios' },
        { value: 'Mesadas', label: 'Mesadas (Granito, Mármol)' },
        { value: 'Muebles y Carpintería', label: 'Muebles de Cocina y Placares' },
        { value: 'Otros', label: 'Otros' },
    ],
    'Herramientas': [
        { value: 'Eléctricas', label: 'Herramientas Eléctricas' },
        { value: 'Manuales', label: 'Herramientas Manuales' },
        { value: 'Medición', label: 'Equipos de Medición' },
        { value: 'Seguridad y EPP', label: 'Seguridad y EPP (Ropa, Guantes)' },
        { value: 'Andamios', label: 'Andamios y Escaleras' },
        { value: 'Consumibles', label: 'Consumibles (Discos, Mechas)' },
        { value: 'Otros', label: 'Otros' },
    ],
}

const PedidoForm = ({ initialValues, onSubmit, onCancel }: FormProps) => {
    const [projects, setProjects] = useState<Project[]>([])
    const [loadingProjects, setLoadingProjects] = useState(false)

    useEffect(() => {
        const loadProjects = async () => {
            setLoadingProjects(true)
            try {
                const response = await fetchProjects()
                if (response.ok) {
                    setProjects(response.proyectos)
                }
            } catch (error) {
                console.error('Error fetching projects:', error)
            } finally {
                setLoadingProjects(false)
            }
        }
        loadProjects()
    }, [])

    const projectOptions = projects.map(p => ({
        value: p._id,
        label: `${p.codigo} - ${p.nombre}`,
        unidadNegocio: p.unidadNegocio?._id || p.unidadNegocio
    }))

    return (
        <Formik
            initialValues={{
                numeroPedido: initialValues.numeroPedido || '',
                categoria: (initialValues as any).categoria || 'Obra Gruesa',
                subcategoria: (initialValues as any).subcategoria || '',
                estado: initialValues.estado || EstadoPedido.BORRADOR,
                items: initialValues.items || [{ descripcion: '', cantidad: 1, unidad: 'u', precioUnitario: 0, subtotal: 0 }],
                observaciones: initialValues.observaciones || '',
                unidadNegocio: initialValues.unidadNegocio || '',
                proyecto: initialValues.proyecto?._id || initialValues.proyecto || '',
            }}
            validationSchema={validationSchema}
            enableReinitialize={true}
            onSubmit={(values) => {
                onSubmit(values)
            }}
        >
            {({ values, touched, errors, setFieldValue, handleSubmit }) => (
                <Form>
                    <div className="grid grid-cols-1 gap-4">
                        <FormItem
                            label="Proyecto"
                            invalid={Boolean(errors.proyecto && touched.proyecto)}
                            errorMessage={errors.proyecto as string}
                        >
                            <Field name="proyecto">
                                {({ field, form }: any) => (
                                    <Select
                                        placeholder={loadingProjects ? "Cargando proyectos..." : "Selecciona un proyecto"}
                                        options={projectOptions}
                                        value={projectOptions.find(opt => opt.value === field.value)}
                                        isLoading={loadingProjects}
                                        onChange={(option) => {
                                            form.setFieldValue(field.name, option?.value)
                                            // Sincronizar unidadNegocio automáticamente desde el proyecto
                                            if (option) {
                                                form.setFieldValue('unidadNegocio', option.unidadNegocio)
                                            }
                                        }}
                                    />
                                )}
                            </Field>
                        </FormItem>

                        <div className="grid grid-cols-2 gap-4">
                            <FormItem
                                label="Número de Pedido"
                                invalid={Boolean(errors.numeroPedido && touched.numeroPedido)}
                                errorMessage={errors.numeroPedido as string}
                            >
                                <Field name="numeroPedido" as={Input} placeholder="Ej: PED-001" />
                            </FormItem>

                            <FormItem
                                label="Estado"
                                invalid={Boolean(errors.estado && touched.estado)}
                                errorMessage={errors.estado as string}
                            >
                                <Field name="estado">
                                    {({ field, form }: any) => (
                                        <Select
                                            options={optionsEstado}
                                            value={optionsEstado.find(opt => opt.value === field.value)}
                                            onChange={(option) => form.setFieldValue(field.name, option?.value)}
                                        />
                                    )}
                                </Field>
                            </FormItem>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <FormItem
                                label="Categoría"
                                invalid={Boolean(errors.categoria && touched.categoria)}
                                errorMessage={errors.categoria as string}
                            >
                                <Field name="categoria">
                                    {({ field, form }: any) => (
                                    <Select
                                        options={categoryOptions}
                                        value={categoryOptions.find((opt: any) => opt.value === field.value)}
                                        onChange={(option) => {
                                            form.setFieldValue(field.name, option?.value)
                                            // Reset subcategory when category changes
                                            form.setFieldValue('subcategoria', '')
                                        }}
                                    />
                                    )}
                                </Field>
                            </FormItem>

                            <FormItem
                                label="Subcategoría"
                                invalid={Boolean(errors.subcategoria && touched.subcategoria)}
                                errorMessage={errors.subcategoria as string}
                            >
                                <Field name="subcategoria">
                                    {({ field, form }: any) => {
                                        const currentSubOptions = subcategoryMapping[values.categoria] || []
                                        return (
                                            <Select
                                                options={currentSubOptions}
                                                value={currentSubOptions.find((opt: any) => opt.value === field.value)}
                                                onChange={(option) => form.setFieldValue(field.name, option?.value)}
                                                placeholder="Selecciona subcategoría"
                                                isDisabled={!values.categoria}
                                            />
                                        )
                                    }}
                                </Field>
                            </FormItem>
                        </div>

                        <div className="mt-4">
                            <h4 className="mb-2 font-bold">Ítems del Pedido</h4>
                            <FieldArray name="items">
                                {({ push, remove }) => (
                                    <div className="space-y-3">
                                        {values.items.map((_, index) => (
                                            <div key={index} className="p-4 border border-gray-100 rounded-lg bg-gray-50/50">
                                                <div className="flex gap-2 mb-2 items-start">
                                                    <div className="flex-grow">
                                                        <Field
                                                            name={`items.${index}.descripcion`}
                                                            as={Input}
                                                            placeholder="Descripción del material"
                                                        />
                                                    </div>
                                                    <div className="w-24">
                                                        <Field
                                                            name={`items.${index}.cantidad`}
                                                            as={Input}
                                                            type="number"
                                                            placeholder="Cant."
                                                        />
                                                    </div>
                                                    <div className="w-24">
                                                        <Field
                                                            name={`items.${index}.unidad`}
                                                            as={Input}
                                                            placeholder="Un."
                                                        />
                                                    </div>
                                                    <Button
                                                        size="sm"
                                                        icon={<HiTrash />}
                                                        className="text-red-500"
                                                        onClick={() => remove(index)}
                                                        variant="plain"
                                                    />
                                                </div>
                                            </div>
                                        ))}
                                        <Button
                                            type="button"
                                            size="sm"
                                            icon={<HiPlus />}
                                            onClick={() => push({ descripcion: '', cantidad: 1, unidad: 'u', precioUnitario: 0, subtotal: 0 })}
                                            className="mt-2"
                                        >
                                            Agregar Ítem
                                        </Button>
                                    </div>
                                )}
                            </FieldArray>
                        </div>

                        <FormItem label="Observaciones">
                            <Field name="observaciones">
                                {({ field, form }: any) => (
                                    <Input 
                                        textArea 
                                        {...field}
                                        placeholder="Notas adicionales..." 
                                    />
                                )}
                            </Field>
                        </FormItem>

                        <div className="flex justify-end gap-2 mt-6">
                            <Button type="button" onClick={onCancel}>
                                Cancelar
                            </Button>
                            <Button variant="solid" type="submit">
                                Guardar Pedido
                            </Button>
                        </div>
                    </div>
                </Form>
            )}
        </Formik>
    )
}

export default PedidoForm

