import React, { useState, useEffect } from 'react'
import { Card, Button, Table, Switcher, Tooltip, Notification, toast, Drawer } from '@/components/ui'
import { HiTrash, HiChevronDown, HiChevronUp, HiOutlineDownload, HiInformationCircle, HiPlus } from 'react-icons/hi'
import { Pedido, EstadoPedido } from '@/@types/pedidos'
import { fetchPedidos, deletePedido as apiDeletePedido, createPedido as apiCreatePedido } from '@/api/api'
import PedidoForm from './PedidoForm'

const { Tr, Th, Td, THead, TBody } = Table

const statusTextColors: Record<EstadoPedido, string> = {
    [EstadoPedido.BORRADOR]: 'text-gray-500',
    [EstadoPedido.ENVIADO]: 'text-blue-600',
    [EstadoPedido.CONFIRMADO]: 'text-indigo-600',
    [EstadoPedido.PARCIAL]: 'text-yellow-600',
    [EstadoPedido.RECIBIDO]: 'text-green-500',
    [EstadoPedido.CANCELADO]: 'text-red-500',
}

const PedidosListView = ({ category }: { category: Pedido['categoria'] }) => {
    const [pedidos, setPedidos] = useState<Pedido[]>([])
    const [loading, setLoading] = useState(false)
    const [expandedPedidoId, setExpandedPedidoId] = useState<string | null>(null)
    const [showAll, setShowAll] = useState(false)
    const [dialogIsOpen, setDialogIsOpen] = useState(false)

    useEffect(() => {
        loadPedidos()
    }, [category])

    const loadPedidos = async () => {
        setLoading(true)
        try {
            const response = await fetchPedidos({ categoria: category })
            if (response.ok) {
                setPedidos(response.pedidos)
            }
        } catch (error) {
            console.error('Error fetching pedidos:', error)
        } finally {
            setLoading(false)
        }
    }

    const handleCreate = async (values: any) => {
        try {
            const response = await apiCreatePedido(values)
            if (response.ok) {
                toast.push(<Notification title="Pedido creado" type="success" />, { placement: 'top-center' })
                loadPedidos()
                setDialogIsOpen(false)
            }
        } catch (error) {
            console.error('Error creating pedido:', error)
            toast.push(<Notification title="Error al crear" type="danger" />, { placement: 'top-center' })
        }
    }

    const handleDelete = async (id: string) => {
        if (window.confirm('¿Estás seguro de eliminar este pedido?')) {
            try {
                const response = await apiDeletePedido(id)
                if (response.ok) {
                    toast.push(<Notification title="Pedido eliminado" type="success" />, { placement: 'top-center' })
                    loadPedidos()
                }
            } catch (error: any) {
                const msg = error.response?.data?.msg || 'Error al eliminar'
                toast.push(<Notification title={msg} type="danger" />, { placement: 'top-center' })
            }
        }
    }

    const handleReceiveMaterial = (item: any, pedidoId: string) => {
        console.log("Receive item", item, "from pedido", pedidoId)
        toast.push(<Notification title="Función de Ingreso (Próximamente)" type="info" />, { placement: 'top-center' })
    }

    const handleInfoMaterial = (item: any) => {
        console.log("Info item", item)
        toast.push(<Notification title={`Info: ${item.descripcion}`} type="info" />, { placement: 'top-center' })
    }

    const openNew = () => {
        setDialogIsOpen(true)
    }

    return (
        <div>
            <div className="flex items-center justify-between mb-6">
                <h3 className="section-title text-lg font-bold">Pedidos de {category}</h3>
                <div className="flex items-center gap-4">
                    <div className="flex items-center gap-2 text-gray-600">
                        <span>Mostrar todos</span>
                        <Switcher checked={showAll} onChange={setShowAll} />
                    </div>
                    <Button size="sm" icon={<HiPlus />} onClick={openNew} />
                </div>
            </div>
            
            <div className="overflow-x-auto">
                <Table className="w-full">
                    <THead className="!bg-gray-200">
                        <Tr>
                            <Th className="!text-gray-700 font-bold uppercase text-xs w-1/4">Proyecto</Th>
                            <Th className="!text-gray-700 font-bold uppercase text-xs text-center">Fecha</Th>
                            <Th className="!text-gray-700 font-bold uppercase text-xs text-center">Categoría</Th>
                            <Th className="!text-gray-700 font-bold uppercase text-xs text-center">Subcategoría</Th>
                            <Th className="!text-gray-700 font-bold uppercase text-xs text-center">Estado</Th>
                            <Th className="w-10"></Th>
                        </Tr>
                    </THead>
                    <TBody>
                        {loading ? (
                            <Tr><Td colSpan={6} className="text-center py-8">Cargando...</Td></Tr>
                        ) : pedidos.length === 0 ? (
                            <Tr>
                                <Td colSpan={6} className="text-center py-8 text-gray-500">
                                    No hay pedidos registrados.
                                </Td>
                            </Tr>
                        ) : (
                            pedidos.map((pedido) => (
                                <React.Fragment key={pedido._id}>
                                    <Tr className="hover:bg-gray-50">
                                        <Td className="font-medium text-gray-800">{pedido.proyecto?.nombre || 'General'}</Td>
                                        <Td className="text-center text-gray-600">{new Date(pedido.fechaPedido).toLocaleDateString()}</Td>
                                        <Td className="text-center text-gray-600">{pedido.numeroPedido || '-'}</Td>
                                        <Td className="text-center text-gray-600 font-semibold">{pedido.categoria || '-'}</Td>
                                        <Td className="text-center text-gray-600 italic text-xs">{pedido.subcategoria || '-'}</Td>
                                        <Td className="text-center">
                                            <span className={`font-semibold ${statusTextColors[pedido.estado]}`}>
                                                {pedido.estado}
                                            </span>
                                        </Td>
                                        <Td className="text-right">
                                            <div className="flex items-center justify-end gap-2">
                                                <Button
                                                    size="xs"
                                                    variant="plain"
                                                    icon={expandedPedidoId === pedido._id ? <HiChevronUp size={20} /> : <HiChevronDown size={20} />}
                                                    onClick={() => setExpandedPedidoId(expandedPedidoId === pedido._id ? null : pedido._id)}
                                                    className="text-gray-500 hover:text-gray-800"
                                                />
                                                <Button 
                                                    size="xs" 
                                                    variant="plain" 
                                                    icon={<HiTrash />} 
                                                    onClick={(e) => { e.stopPropagation(); handleDelete(pedido._id); }} 
                                                    className="text-gray-400 hover:text-red-500" 
                                                />
                                            </div>
                                        </Td>
                                    </Tr>
                                    {expandedPedidoId === pedido._id && (
                                        <Tr>
                                            <Td colSpan={6} className="!p-0 !border-0">
                                                <div className="bg-gray-50 p-4 border-b border-gray-200 shadow-inner">
                                                    <Table compact className="w-full bg-white rounded-md border border-gray-200">
                                                        <THead className="bg-gray-100 border-b border-gray-200">
                                                            <Tr>
                                                                <Th className="text-xs font-bold text-gray-600 w-24 pl-4">Código</Th>
                                                                <Th className="text-xs font-bold text-gray-600">Descripción</Th>
                                                                <Th className="text-xs font-bold text-gray-600 text-center w-32">Cant. Pedida</Th>
                                                                <Th className="text-xs font-bold text-gray-600 text-center w-32">Cant. Recibida</Th>
                                                                <Th className="text-xs font-bold text-gray-600 text-center w-32">Estado</Th>
                                                                <Th className="w-32"></Th>
                                                            </Tr>
                                                        </THead>
                                                        <TBody>
                                                            {(pedido.items || []).map((item, idx) => {
                                                                const cantRecibida = 0 
                                                                const isComplete = cantRecibida >= item.cantidad
                                                                const isPartial = cantRecibida > 0 && cantRecibida < item.cantidad
                                                                
                                                                let statusLabel = 'Pendiente'
                                                                let statusColor = 'text-gray-500'
                                                                if (isComplete) { statusLabel = 'Completo'; statusColor = 'text-green-500' }
                                                                else if (isPartial) { statusLabel = 'En tránsito'; statusColor = 'text-gray-600' }
 
                                                                return (
                                                                    <Tr key={idx} className="border-b border-gray-100 last:border-0 hover:bg-gray-50 transition-colors">
                                                                        <Td className="text-gray-600 font-mono text-xs pl-4">{item.codigo || '-'}</Td>
                                                                        <Td className="text-gray-700 font-medium">{item.descripcion}</Td>
                                                                        <Td className="text-center text-gray-600 font-medium">{item.cantidad.toFixed(2)}</Td>
                                                                        <Td className="text-center text-gray-600 font-medium">{cantRecibida.toFixed(2)}</Td>
                                                                        <Td className={`text-center font-semibold text-xs uppercase ${statusColor}`}>{statusLabel}</Td>
                                                                        <Td className="text-right pr-4">
                                                                             <div className="flex justify-end gap-1">
                                                                                <Tooltip title="Dar Ingreso">
                                                                                    <Button 
                                                                                        size="xs" 
                                                                                        variant="twoTone" 
                                                                                        icon={<HiOutlineDownload />} 
                                                                                        className="text-gray-600 hover:text-blue-600 border-gray-200"
                                                                                        onClick={() => handleReceiveMaterial(item, pedido._id)}
                                                                                    />
                                                                                </Tooltip>
                                                                                <Tooltip title="Ver Información">
                                                                                    <Button 
                                                                                        size="xs" 
                                                                                        variant="plain" 
                                                                                        icon={<HiInformationCircle size={18} />} 
                                                                                        className="text-gray-400 hover:text-blue-500"
                                                                                        onClick={() => handleInfoMaterial(item)}
                                                                                    />
                                                                                </Tooltip>
                                                                             </div>
                                                                        </Td>
                                                                    </Tr>
                                                                )
                                                            })}
                                                        </TBody>
                                                    </Table>
                                                </div>
                                            </Td>
                                        </Tr>
                                    )}
                                </React.Fragment>
                            ))
                        )}
                    </TBody>
                </Table>
            </div>

            <Drawer
                title={`Nuevo Pedido (${category})`}
                isOpen={dialogIsOpen}
                onClose={() => setDialogIsOpen(false)}
                onRequestClose={() => setDialogIsOpen(false)}
                width={600}
            >
                <PedidoForm
                    initialValues={{ categoria: category as any }}
                    onSubmit={handleCreate}
                    onCancel={() => setDialogIsOpen(false)}
                />
            </Drawer>
        </div>
    )
}

export default PedidosListView
